def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    """Solve crew scheduling via greedy construction + local search."""
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # Try the default solver first with a portion of the budget
    try:
        default_budget = min(remaining() * 0.7, time_limit_s * 0.7)
        sol = tools['solve_default'](time_limit_s=default_budget)
        if sol is not None:
            feasible, _ = tools['is_feasible'](sol)
            if feasible:
                best_sol = sol
                best_cost = tools['objective'](best_sol)
                # Try local search with remaining time
                if remaining() > 2.0:
                    best_sol = local_search(
                        best_sol, N, K, tasks, arcs, time_limit, tools, 
                        start_time, time_limit_s
                    )
                return best_sol
    except Exception:
        pass

    # Fallback: greedy construction
    try:
        chains = tools['greedy_chain_pack']()
        if len(chains) <= K:
            sol = tools['make_solution'](chains)
            feasible, _ = tools['is_feasible'](sol)
            if feasible:
                if remaining() > 2.0:
                    sol = local_search(
                        sol, N, K, tasks, arcs, time_limit, tools,
                        start_time, time_limit_s
                    )
                return sol
    except Exception:
        pass

    # Manual greedy construction
    sol = greedy_construct(N, K, tasks, arcs, time_limit, tools)
    if sol is not None:
        feasible, _ = tools['is_feasible'](sol)
        if feasible:
            if remaining() > 2.0:
                sol = local_search(
                    sol, N, K, tasks, arcs, time_limit, tools,
                    start_time, time_limit_s
                )
            return sol

    # Last resort: trivial assignment (one task per crew if K >= N)
    return trivial_solution(N, K, tasks, arcs, time_limit, tools)


def greedy_construct(N, K, tasks, arcs, time_limit, tools):
    """Greedy construction: assign tasks to crews minimizing transition costs."""
    # Sort tasks by start time
    task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])

    crews = []  # list of lists of task ids
    crew_last = []  # last task in each crew
    crew_start = []  # start time of first task in each crew
    crew_finish = []  # finish time of last task in each crew

    for task in task_order:
        t_start, t_finish = tasks[task]

        best_crew = -1
        best_cost = float('inf')

        for i, crew in enumerate(crews):
            last = crew_last[i]
            last_finish = crew_finish[i]
            first_start = crew_start[i]

            # Check no overlap
            if last_finish > t_start:
                continue

            # Check arc exists
            if (last, task) not in arcs:
                continue

            # Check duty time
            duty = t_finish - first_start
            if duty > time_limit:
                continue

            cost = arcs[(last, task)]
            if cost < best_cost:
                best_cost = cost
                best_crew = i

        if best_crew >= 0:
            crews[best_crew].append(task)
            crew_last[best_crew] = task
            crew_finish[best_crew] = t_finish
        else:
            # Open new crew
            if len(crews) < K:
                crews.append([task])
                crew_last.append(task)
                crew_start.append(t_start)
                crew_finish.append(t_finish)
            else:
                # Try to force assign to some crew (may fail constraints)
                # Find best crew ignoring duty time, then check
                forced = False
                for i in range(len(crews)):
                    last = crew_last[i]
                    if crew_finish[i] <= t_start and (last, task) in arcs:
                        duty = t_finish - crew_start[i]
                        if duty <= time_limit:
                            crews[i].append(task)
                            crew_last[i] = task
                            crew_finish[i] = t_finish
                            forced = True
                            break
                if not forced:
                    return None

    sol = {'crews': crews}
    feasible, _ = tools['is_feasible'](sol)
    if feasible:
        return sol
    return None


def local_search(sol, N, K, tasks, arcs, time_limit, tools, start_time, time_limit_s):
    """Local search to improve solution quality."""
    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    best_sol = sol
    best_cost = tools['objective'](sol)

    crews = [list(c) for c in sol['crews']]

    improved = True
    iteration = 0

    while improved and remaining() > 0.5:
        improved = False
        iteration += 1

        # Try relocate: move a task from one crew to another position
        for ci in range(len(crews)):
            if remaining() < 0.3:
                break
            for ti in range(len(crews[ci])):
                if remaining() < 0.3:
                    break
                task = crews[ci][ti]

                # Try inserting task into other crews
                for cj in range(len(crews)):
                    if ci == cj:
                        continue
                    if remaining() < 0.3:
                        break

                    # Try each position in cj
                    for pos in range(len(crews[cj]) + 1):
                        new_ci = crews[ci][:ti] + crews[ci][ti+1:]
                        new_cj = crews[cj][:pos] + [task] + crews[cj][pos:]

                        # Validate both crews
                        if len(new_ci) == 0 and len(crews) > 1:
                            # Would create empty crew - skip if K allows
                            # Actually empty crews are not allowed, but we can just remove them
                            pass

                        valid_ci = len(new_ci) == 0 or check_crew(new_ci, tasks, arcs, time_limit)
                        valid_cj = check_crew(new_cj, tasks, arcs, time_limit)

                        if valid_ci and valid_cj:
                            new_crews = []
                            for k, c in enumerate(crews):
                                if k == ci:
                                    if len(new_ci) > 0:
                                        new_crews.append(new_ci)
                                elif k == cj:
                                    new_crews.append(new_cj)
                                else:
                                    new_crews.append(c)

                            if len(new_crews) > K:
                                continue
                            if len(new_crews) == 0:
                                continue

                            new_cost = sum(crew_cost_local(c, arcs) for c in new_crews)
                            if new_cost < best_cost - 1e-9:
                                best_cost = new_cost
                                crews = new_crews
                                best_sol = {'crews': [list(c) for c in crews]}
                                improved = True
                                break

                    if improved:
                        break
                if improved:
                    break
            if improved:
                break

        if improved:
            continue

        # Try 2-opt within a crew: reverse a subsequence
        for ci in range(len(crews)):
            if remaining() < 0.3:
                break
            crew = crews[ci]
            n = len(crew)
            for i in range(n - 1):
                if remaining() < 0.3:
                    break
                for j in range(i + 2, n):
                    # Reverse segment [i+1..j]
                    new_crew = crew[:i+1] + crew[i+1:j+1][::-1] + crew[j+1:]
                    if check_crew(new_crew, tasks, arcs, time_limit):
                        new_cost_crew = crew_cost_local(new_crew, arcs)
                        old_cost_crew = crew_cost_local(crew, arcs)
                        if new_cost_crew < old_cost_crew - 1e-9:
                            delta = new_cost_crew - old_cost_crew
                            best_cost += delta
                            crews[ci] = new_crew
                            best_sol = {'crews': [list(c) for c in crews]}
                            improved = True
                            break
                if improved:
                    break
            if improved:
                break

        if improved:
            continue

        # Try swap: exchange tasks between two crews
        for ci in range(len(crews)):
            if remaining() < 0.3:
                break
            for ti in range(len(crews[ci])):
                if remaining() < 0.3:
                    break
                for cj in range(ci + 1, len(crews)):
                    if remaining() < 0.3:
                        break
                    for tj in range(len(crews[cj])):
                        task_i = crews[ci][ti]
                        task_j = crews[cj][tj]

                        new_ci = crews[ci][:ti] + [task_j] + crews[ci][ti+1:]
                        new_cj = crews[cj][:tj] + [task_i] + crews[cj][tj+1:]

                        if check_crew(new_ci, tasks, arcs, time_limit) and \
                           check_crew(new_cj, tasks, arcs, time_limit):
                            old_cost = crew_cost_local(crews[ci], arcs) + crew_cost_local(crews[cj], arcs)
                            new_cost = crew_cost_local(new_ci, arcs) + crew_cost_local(new_cj, arcs)
                            if new_cost < old_cost - 1e-9:
                                best_cost += new_cost - old_cost
                                crews[ci] = new_ci
                                crews[cj] = new_cj
                                best_sol = {'crews': [list(c) for c in crews]}
                                improved = True
                                break
                    if improved:
                        break
                if improved:
                    break
            if improved:
                break

    # Verify final solution
    feasible, _ = tools['is_feasible'](best_sol)
    if feasible:
        return best_sol
    return sol


def check_crew(crew, tasks, arcs, time_limit):
    """Check if a crew sequence is valid."""
    if len(crew) == 0:
        return True

    first_start = tasks[crew[0]][0]
    last_finish = tasks[crew[-1]][1]

    if last_finish - first_start > time_limit:
        return False

    for i in range(len(crew) - 1):
        t1, t2 = crew[i], crew[i+1]
        if tasks[t1][1] > tasks[t2][0]:
            return False
        if (t1, t2) not in arcs:
            return False

    return True


def crew_cost_local(crew, arcs):
    """Compute cost of a crew."""
    cost = 0.0
    for i in range(len(crew) - 1):
        key = (crew[i], crew[i+1])
        if key in arcs:
            cost += arcs[key]
        else:
            return float('inf')
    return cost


def trivial_solution(N, K, tasks, arcs, time_limit, tools):
    """Last resort: try to build any feasible solution."""
    if K >= N:
        # Each task in its own crew
        crews = [[i] for i in range(1, N + 1)]
        sol = {'crews': crews}
        feasible, _ = tools['is_feasible'](sol)
        if feasible:
            return sol

    # Try min cost flow
    try:
        sol = tools['solve_min_cost_flow'](time_limit_s=10.0)
        if sol is not None:
            feasible, _ = tools['is_feasible'](sol)
            if feasible:
                return sol
    except Exception:
        pass

    # Return whatever we have
    crews = [[i] for i in range(1, min(N, K) + 1)]
    if N > K:
        # Assign remaining tasks greedily
        for task in range(K + 1, N + 1):
            crews[0].append(task)
    return {'crews': crews}

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    """
    Crew Scheduling via Large Neighborhood Search + Simulated Annealing.

    Core differences from portfolio:
    1. LNS destroy/repair instead of move-based local search
    2. Simulated annealing acceptance (not pure greedy descent)
    3. DP-based chain repair (shortest path on task DAG)
    4. Regret-based insertion for repair phase
    5. Destroy targets highest-cost crews preferentially
    """
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # ------------------------------------------------------------------ #
    # Precompute structures
    # ------------------------------------------------------------------ #
    # Sorted successors for each task
    succ = defaultdict(list)  # task -> [(start_j, j, cost)]
    pred = defaultdict(list)  # task -> [(finish_i, i, cost)]

    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ[i].append((tasks[j][0], j, cost))
            pred[j].append((tasks[i][1], i, cost))

    for t in range(1, N + 1):
        succ[t].sort()
        pred[t].sort()

    # Tasks sorted by start time
    tasks_by_start = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
    task_start_rank = {t: i for i, t in enumerate(tasks_by_start)}

    # ------------------------------------------------------------------ #
    # Fast feasibility helpers
    # ------------------------------------------------------------------ #
    def check_crew(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arcs:
                return False
        return True

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    # ------------------------------------------------------------------ #
    # Phase 1: Get initial solution
    # ------------------------------------------------------------------ #
    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # Use solve_default for initial solution (50% of budget)
    init_budget = min(remaining() * 0.50, time_limit_s * 0.50)
    if init_budget > 0.5:
        try:
            sol = tools['solve_default'](time_limit_s=init_budget)
            update_best(sol)
        except Exception:
            pass

    # Greedy fallback
    if best_sol is None and remaining() > 1:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 1:
        sol = _greedy_construct(N, K, tasks, arcs, time_limit)
        update_best(sol)

    if best_sol is None:
        if K >= N:
            best_sol = {'crews': [[i] for i in range(1, N + 1)]}
        else:
            task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
            crews_e = [[] for _ in range(K)]
            for idx, t in enumerate(task_order):
                crews_e[idx % K].append(t)
            best_sol = {'crews': [c for c in crews_e if c]}

    # ------------------------------------------------------------------ #
    # Phase 2: LNS + Simulated Annealing
    # ------------------------------------------------------------------ #
    if remaining() > 1.0:
        best_sol = _lns_sa(
            best_sol, N, K, tasks, arcs, time_limit,
            succ, pred, tasks_by_start, tools,
            start_time, time_limit_s
        )

    return best_sol


def _greedy_construct(N, K, tasks, arcs, time_limit):
    """Greedy construction by start time."""
    task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
    crews = []
    crew_last = []
    crew_start = []
    crew_finish = []

    for task in task_order:
        t_start, t_finish = tasks[task]
        best_crew = -1
        best_cost_val = float('inf')

        for i in range(len(crews)):
            last = crew_last[i]
            if crew_finish[i] > t_start:
                continue
            if (last, task) not in arcs:
                continue
            if t_finish - crew_start[i] > time_limit:
                continue
            c = arcs[(last, task)]
            if c < best_cost_val:
                best_cost_val = c
                best_crew = i

        if best_crew >= 0:
            crews[best_crew].append(task)
            crew_last[best_crew] = task
            crew_finish[best_crew] = t_finish
        elif len(crews) < K:
            crews.append([task])
            crew_last.append(task)
            crew_start.append(t_start)
            crew_finish.append(t_finish)
        else:
            forced = False
            for i in range(len(crews)):
                last = crew_last[i]
                if crew_finish[i] <= t_start and (last, task) in arcs:
                    if t_finish - crew_start[i] <= time_limit:
                        crews[i].append(task)
                        crew_last[i] = task
                        crew_finish[i] = t_finish
                        forced = True
                        break
            if not forced:
                return None

    return {'crews': crews}


def _lns_sa(initial_sol, N, K, tasks, arcs, time_limit,
            succ, pred, tasks_by_start, tools,
            start_time, time_limit_s):
    """
    Large Neighborhood Search with Simulated Annealing acceptance.

    Destroy: remove tasks from selected crews (segment or random removal)
    Repair: DP-based shortest path chain construction for unassigned tasks
    Accept: Simulated annealing (accept worse solutions with decreasing probability)
    """
    def remaining():
        return time_limit_s - (time.time() - start_time)

    def check_crew(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arcs:
                return False
        return True

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    # ------------------------------------------------------------------ #
    # DP-based chain builder: given a set of tasks to cover, build
    # minimum-cost chains using shortest path on the task DAG
    # ------------------------------------------------------------------ #
    def dp_build_chains(task_set, max_chains):
        """
        Build minimum-cost chains covering all tasks in task_set.
        Uses a greedy DP approach: for each task in start-time order,
        extend the cheapest valid chain or start a new one.

        Returns list of chains or None if infeasible.
        """
        if not task_set:
            return []

        ordered = sorted(task_set, key=lambda t: tasks[t][0])

        # dp[task] = (min_cost_to_reach, prev_task_or_None)
        # We use a priority queue to build optimal chains greedily
        # Strategy: build chains using Dijkstra-like approach on DAG

        # For each task, find best predecessor within task_set
        # dp_cost[t] = min cost of chain ending at t
        # dp_prev[t] = predecessor of t in optimal chain
        INF = float('inf')
        dp_cost = {t: 0.0 for t in task_set}  # cost to start new chain at t
        dp_prev = {t: None for t in task_set}

        # Process in topological order (by start time, then finish time)
        for t in ordered:
            ts_t, tf_t = tasks[t]
            # Try all predecessors in task_set
            for (_, finish_i, i, cost_i) in sorted(
                [(tasks[i][0], tasks[i][1], i, arcs.get((i, t), INF))
                 for i in task_set if i != t
                 and tasks[i][1] <= ts_t
                 and (i, t) in arcs],
                key=lambda x: x[0]
            ):
                new_cost = dp_cost[i] + cost_i
                # Check duty time
                # Find chain head of i
                head = i
                h = dp_prev[i]
                visited = set()
                while h is not None and h not in visited:
                    visited.add(head)
                    head = h
                    h = dp_prev[h]
                duty = tasks[t][1] - tasks[head][0]
                if duty > time_limit:
                    continue
                if new_cost < dp_cost[t]:
                    dp_cost[t] = new_cost
                    dp_prev[t] = i

        # Reconstruct chains
        in_chain = set()
        chain_ends = []  # tasks that are chain ends (no successor in dp)

        # Find which tasks are "pointed to" by others
        has_successor = set()
        for t in task_set:
            if dp_prev[t] is not None:
                has_successor.add(dp_prev[t])

        # Chain ends: tasks with no successor in dp
        for t in task_set:
            if t not in has_successor:
                chain_ends.append(t)

        chains = []
        for end in chain_ends:
            chain = []
            cur = end
            visited = set()
            while cur is not None and cur not in visited:
                visited.add(cur)
                chain.append(cur)
                cur = dp_prev[cur]
            chain.reverse()
            if check_crew(chain):
                chains.append(chain)
            else:
                # Fall back: each task in its own chain
                for t in chain:
                    chains.append([t])

        if len(chains) > max_chains:
            return None  # Can't fit in max_chains

        return chains

    # ------------------------------------------------------------------ #
    # Regret-based insertion repair
    # ------------------------------------------------------------------ #
    def regret_repair(unassigned, current_crews, max_total_crews):
        """
        Insert unassigned tasks using regret-2 heuristic.
        Regret = (2nd best insertion cost) - (best insertion cost)
        Tasks with high regret are inserted first.

        Returns updated crews or None if infeasible.
        """
        if not unassigned:
            return current_crews

        crews = [list(c) for c in current_crews]
        remaining_tasks = list(unassigned)

        while remaining_tasks:
            # Compute best and 2nd best insertion for each task
            regrets = []

            for task in remaining_tasks:
                ts_t, tf_t = tasks[task]
                insertions = []  # (cost_delta, crew_idx, pos)

                for ci, crew in enumerate(crews):
                    for pos in range(len(crew) + 1):
                        # Temporal check
                        if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                            continue
                        if pos < len(crew) and tf_t > tasks[crew[pos]][0]:
                            continue

                        # Arc check
                        cost_add = 0.0
                        ok = True
                        if pos > 0:
                            c = arcs.get((crew[pos - 1], task))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if ok and pos < len(crew):
                            c = arcs.get((task, crew[pos]))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if not ok:
                            continue

                        # Bridge removal
                        bridge = 0.0
                        if pos > 0 and pos < len(crew):
                            bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                        # Duty time check
                        new_crew = crew[:pos] + [task] + crew[pos:]
                        dt = tasks[new_crew[-1]][1] - tasks[new_crew[0]][0]
                        if dt > time_limit:
                            continue

                        delta = cost_add - bridge
                        insertions.append((delta, ci, pos))

                # Also consider opening a new crew
                if len(crews) < max_total_crews:
                    insertions.append((0.0, -1, 0))  # new crew, cost = 0

                if not insertions:
                    return None  # Can't insert this task

                insertions.sort(key=lambda x: x[0])
                best_cost_ins = insertions[0][0]
                second_cost_ins = insertions[1][0] if len(insertions) > 1 else best_cost_ins + 1e9

                regret_val = second_cost_ins - best_cost_ins
                regrets.append((regret_val, task, insertions[0]))

            # Insert task with highest regret
            regrets.sort(key=lambda x: -x[0])
            _, task_to_insert, (delta, ci, pos) = regrets[0]

            if ci == -1:
                # Open new crew
                crews.append([task_to_insert])
            else:
                crews[ci] = crews[ci][:pos] + [task_to_insert] + crews[ci][pos:]

            remaining_tasks.remove(task_to_insert)

        return crews

    # ------------------------------------------------------------------ #
    # Greedy repair: insert by cheapest position
    # ------------------------------------------------------------------ #
    def greedy_repair(unassigned, current_crews, max_total_crews):
        """Simple greedy repair: insert each task at cheapest valid position."""
        if not unassigned:
            return current_crews

        crews = [list(c) for c in current_crews]
        # Sort unassigned by start time
        task_order = sorted(unassigned, key=lambda t: tasks[t][0])

        for task in task_order:
            ts_t, tf_t = tasks[task]
            best_delta = float('inf')
            best_ci = -1
            best_pos = -1

            for ci, crew in enumerate(crews):
                for pos in range(len(crew) + 1):
                    if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                        continue
                    if pos < len(crew) and tf_t > tasks[crew[pos]][0]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < len(crew):
                        c = arcs.get((task, crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if pos > 0 and pos < len(crew):
                        bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                    new_crew = crew[:pos] + [task] + crew[pos:]
                    dt = tasks[new_crew[-1]][1] - tasks[new_crew[0]][0]
                    if dt > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_delta:
                        best_delta = delta
                        best_ci = ci
                        best_pos = pos

            if best_ci >= 0:
                crews[best_ci] = crews[best_ci][:best_pos] + [task] + crews[best_ci][best_pos:]
            elif len(crews) < max_total_crews:
                crews.append([task])
            else:
                return None  # Can't insert

        return crews

    # ------------------------------------------------------------------ #
    # Destroy operators
    # ------------------------------------------------------------------ #
    def destroy_random_tasks(crews, n_remove, rng):
        """Remove n_remove random tasks from crews."""
        all_tasks = [(ci, pos, t)
                     for ci, crew in enumerate(crews)
                     for pos, t in enumerate(crew)]
        if not all_tasks:
            return crews, []

        n_remove = min(n_remove, len(all_tasks))
        removed_entries = rng.sample(all_tasks, n_remove)
        removed_tasks = [t for _, _, t in removed_entries]
        removed_set = set(removed_tasks)

        new_crews = []
        for crew in crews:
            new_crew = [t for t in crew if t not in removed_set]
            if new_crew:
                new_crews.append(new_crew)

        return new_crews, removed_tasks

    def destroy_worst_crew(crews, n_crews_to_destroy, rng):
        """Remove tasks from the most expensive crews."""
        if not crews:
            return crews, []

        crew_costs = [(crew_cost_fn(crew), ci) for ci, crew in enumerate(crews)]
        crew_costs.sort(reverse=True)

        n_destroy = min(n_crews_to_destroy, len(crews))
        destroyed_indices = set(ci for _, ci in crew_costs[:n_destroy])

        removed_tasks = []
        new_crews = []
        for ci, crew in enumerate(crews):
            if ci in destroyed_indices:
                removed_tasks.extend(crew)
            else:
                new_crews.append(crew)

        return new_crews, removed_tasks

    def destroy_segment(crews, rng):
        """Remove a contiguous segment from a randomly chosen crew."""
        if not crews:
            return crews, []

        # Pick crew weighted by cost
        crew_costs = [max(crew_cost_fn(crew), 0.01) for crew in crews]
        total_w = sum(crew_costs)
        probs = [c / total_w for c in crew_costs]

        r = rng.random()
        cumulative = 0.0
        ci = 0
        for i, p in enumerate(probs):
            cumulative += p
            if r <= cumulative:
                ci = i
                break

        crew = crews[ci]
        if len(crew) <= 1:
            return crews, []

        # Remove a random contiguous segment
        seg_len = rng.randint(1, max(1, len(crew) // 2))
        start_pos = rng.randint(0, len(crew) - seg_len)
        removed = crew[start_pos:start_pos + seg_len]
        new_crew = crew[:start_pos] + crew[start_pos + seg_len:]

        new_crews = []
        for i, c in enumerate(crews):
            if i == ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)

        return new_crews, removed

    def destroy_related_tasks(crews, n_remove, rng):
        """
        Remove tasks that are 'related' (share arcs or close in time).
        Starts from a random task, then removes its neighbors.
        """
        all_tasks_flat = [t for crew in crews for t in crew]
        if not all_tasks_flat:
            return crews, []

        seed_task = rng.choice(all_tasks_flat)
        removed_set = {seed_task}

        # Expand by relatedness: tasks connected by arcs to removed tasks
        candidates = set()
        for t in removed_set:
            for _, j, _ in succ[t]:
                if j in all_tasks_flat:
                    candidates.add(j)
            for _, i, _ in pred[t]:
                if i in all_tasks_flat:
                    candidates.add(i)

        # Also add temporally close tasks
        seed_start = tasks[seed_task][0]
        for t in all_tasks_flat:
            if abs(tasks[t][0] - seed_start) < (time_limit * 0.1):
                candidates.add(t)

        candidates -= removed_set
        candidates = list(candidates)
        rng.shuffle(candidates)

        n_remove = min(n_remove, len(all_tasks_flat))
        for t in candidates:
            if len(removed_set) >= n_remove:
                break
            removed_set.add(t)

        removed_tasks = list(removed_set)
        new_crews = []
        for crew in crews:
            new_crew = [t for t in crew if t not in removed_set]
            if new_crew:
                new_crews.append(new_crew)

        return new_crews, removed_tasks

    # ------------------------------------------------------------------ #
    # Main LNS + SA loop
    # ------------------------------------------------------------------ #
    current_crews = [list(c) for c in initial_sol['crews']]
    current_cost = total_cost_fn(current_crews)
    best_crews = [list(c) for c in current_crews]
    best_cost = current_cost

    rng = random.Random(42)

    # SA parameters
    # Initial temperature: accept 5% worse solutions with ~50% probability
    # T = -delta / ln(0.5) => T = delta / ln(2)
    # Estimate initial delta as ~5% of current cost
    if current_cost > 0 and current_cost < float('inf'):
        T_init = max(0.05 * current_cost / math.log(2), 1.0)
    else:
        T_init = 100.0

    T_min = 1e-4
    T = T_init

    # Cooling: geometric cooling
    # We want T to reach T_min after ~80% of iterations
    # Estimate iterations based on remaining time
    ls_time = remaining() - 0.5
    if ls_time <= 0:
        return initial_sol

    # Estimate ~100 iterations per second for LNS
    estimated_iters = max(50, int(ls_time * 30))
    cooling_rate = (T_min / T_init) ** (1.0 / max(1, estimated_iters))

    # Adaptive destroy size
    n_destroy_base = max(1, N // 10)

    iteration = 0
    no_improve_streak = 0

    # Destroy operator selection (adaptive weights)
    destroy_ops = ['random', 'worst_crew', 'segment', 'related']
    op_weights = [1.0, 1.0, 1.0, 1.0]
    op_success = [0, 0, 0, 0]
    op_tries = [1, 1, 1, 1]

    def select_destroy_op():
        # UCB-style selection
        total_tries = sum(op_tries)
        scores = []
        for i in range(len(destroy_ops)):
            exploit = op_success[i] / op_tries[i]
            explore = math.sqrt(2 * math.log(total_tries) / op_tries[i])
            scores.append(exploit + 0.3 * explore)
        return scores.index(max(scores))

    while remaining() > 0.5:
        iteration += 1
        T = max(T * cooling_rate, T_min)

        # Adaptive destroy size: increase when stuck
        n_destroy = n_destroy_base + min(no_improve_streak // 5, N // 5)
        n_destroy = min(n_destroy, max(1, N // 2))

        # Select destroy operator
        op_idx = select_destroy_op()
        op_tries[op_idx] += 1
        destroy_op = destroy_ops[op_idx]

        # Destroy
        if destroy_op == 'random':
            partial_crews, removed = destroy_random_tasks(current_crews, n_destroy, rng)
        elif destroy_op == 'worst_crew':
            n_crews_destroy = max(1, min(3, len(current_crews) // 3))
            partial_crews, removed = destroy_worst_crew(current_crews, n_crews_destroy, rng)
        elif destroy_op == 'segment':
            partial_crews, removed = destroy_segment(current_crews, rng)
        else:  # related
            partial_crews, removed = destroy_related_tasks(current_crews, n_destroy, rng)

        if not removed:
            continue

        # Repair: alternate between regret and greedy repair
        max_crews = K
        if iteration % 3 == 0:
            # Use regret repair (slower but better)
            if len(removed) <= 20:  # Only for small sets (regret is O(n^2))
                new_crews = regret_repair(removed, partial_crews, max_crews)
            else:
                new_crews = greedy_repair(removed, partial_crews, max_crews)
        else:
            new_crews = greedy_repair(removed, partial_crews, max_crews)

        if new_crews is None:
            continue

        # Verify all tasks present
        all_covered = set(t for crew in new_crews for t in crew)
        if len(all_covered) != N:
            # Try to add missing tasks
            missing = set(range(1, N + 1)) - all_covered
            new_crews = greedy_repair(list(missing), new_crews, max_crews)
            if new_crews is None:
                continue
            all_covered2 = set(t for crew in new_crews for t in crew)
            if len(all_covered2) != N:
                continue

        if len(new_crews) > K:
            continue

        # Quick validity check
        all_valid = True
        for crew in new_crews:
            if not check_crew(crew):
                all_valid = False
                break
        if not all_valid:
            continue

        new_cost = total_cost_fn(new_crews)

        # SA acceptance
        delta = new_cost - current_cost
        accept = False
        if delta < 0:
            accept = True
        elif T > T_min * 10:
            prob = math.exp(-delta / T)
            accept = rng.random() < prob

        if accept:
            current_crews = new_crews
            current_cost = new_cost

            if new_cost < best_cost - 1e-9:
                # Verify with tools
                candidate = {'crews': [list(c) for c in new_crews]}
                try:
                    feasible, _ = tools['is_feasible'](candidate)
                    if feasible:
                        obj = tools['objective'](candidate)
                        if obj < best_cost:
                            best_cost = obj
                            best_crews = [list(c) for c in new_crews]
                            op_success[op_idx] += 1
                            no_improve_streak = 0
                except Exception:
                    pass
            else:
                no_improve_streak += 1
        else:
            no_improve_streak += 1

        # Periodically reset to best (diversification restart)
        if no_improve_streak > 50 and remaining() > 2.0:
            current_crews = [list(c) for c in best_crews]
            current_cost = best_cost
            no_improve_streak = 0
            # Reheat slightly
            T = max(T, T_init * 0.1)

    # Final solution
    result = {'crews': [list(c) for c in best_crews if c]}
    try:
        feasible, _ = tools['is_feasible'](result)
        if feasible:
            return result
    except Exception:
        pass

    return initial_sol

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # ------------------------------------------------------------------ #
    # Fast data structures
    # ------------------------------------------------------------------ #
    succ_list = defaultdict(list)
    pred_list = defaultdict(list)
    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ_list[i].append((tasks[j][0], j, cost))
            pred_list[j].append((tasks[i][1], i, cost))
    for t in range(1, N + 1):
        succ_list[t].sort()
        pred_list[t].sort()

    def check_crew_fast(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arcs:
                return False
        return True

    def crew_cost_fast(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def solution_cost_fast(crews):
        return sum(crew_cost_fast(c) for c in crews)

    # ------------------------------------------------------------------ #
    # Instance feature analysis for dispatch
    # ------------------------------------------------------------------ #
    # Arc density: number of valid arcs relative to N^2
    arc_density = len(arcs) / max(N * N, 1)

    # Average successors per task
    avg_successors = sum(len(succ_list[t]) for t in range(1, N + 1)) / max(N, 1)

    # N/K ratio: tasks per crew
    tasks_per_crew = N / max(K, 1)

    # Time span analysis
    all_starts = [tasks[t][0] for t in range(1, N + 1)]
    all_finishes = [tasks[t][1] for t in range(1, N + 1)]
    total_span = max(all_finishes) - min(all_starts) if N > 0 else 1.0
    time_limit_ratio = time_limit / max(total_span, 1.0)

    # Classify instance regime
    # ILP regime: small N, low arc density (hard to find feasible), tight time limits
    # MCF/ILS regime: larger N, higher density, more flexible
    is_tiny = N <= 40
    is_small = 40 < N <= 100
    is_medium = 100 < N <= 250
    is_large = N > 250

    # Dense arc graph -> greedy/MCF works well; sparse -> ILP more needed
    is_sparse = avg_successors < 2.0
    is_dense = avg_successors >= 5.0

    # Tight duty time -> harder to chain tasks -> ILP more useful for small instances
    is_tight_time = time_limit_ratio < 0.5

    # Dispatch decision:
    # "ILP-first" regime: tiny instances OR (small + sparse + tight time)
    # "MCF/ILS-first" regime: everything else
    use_ilp_first = is_tiny or (is_small and is_sparse and is_tight_time)
    use_mcf_first = is_large or (is_medium and not is_sparse) or (is_dense and not is_tiny)

    # ------------------------------------------------------------------ #
    # Solution tracking
    # ------------------------------------------------------------------ #
    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # ------------------------------------------------------------------ #
    # Custom greedy construction
    # ------------------------------------------------------------------ #
    def greedy_construct(shuffle_seed=None, prefer_low_cost=True):
        task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
        if shuffle_seed is not None:
            rng = random.Random(shuffle_seed)
            i = 0
            while i < len(task_order):
                j = i
                while j < len(task_order) and tasks[task_order[j]][0] == tasks[task_order[i]][0]:
                    j += 1
                seg = task_order[i:j]
                rng.shuffle(seg)
                task_order[i:j] = seg
                i = j

        crews_g = []
        crew_last = []
        crew_start = []
        crew_finish = []

        for task in task_order:
            t_start, t_finish = tasks[task]
            best_crew_idx = -1
            best_c = float('inf')

            for i in range(len(crews_g)):
                last = crew_last[i]
                if crew_finish[i] > t_start:
                    continue
                if (last, task) not in arcs:
                    continue
                if t_finish - crew_start[i] > time_limit:
                    continue
                c = arcs[(last, task)]
                if c < best_c:
                    best_c = c
                    best_crew_idx = i

            if best_crew_idx >= 0:
                crews_g[best_crew_idx].append(task)
                crew_last[best_crew_idx] = task
                crew_finish[best_crew_idx] = t_finish
            elif len(crews_g) < K:
                crews_g.append([task])
                crew_last.append(task)
                crew_start.append(t_start)
                crew_finish.append(t_finish)
            else:
                forced = False
                for i in range(len(crews_g)):
                    last = crew_last[i]
                    if crew_finish[i] <= t_start and (last, task) in arcs:
                        if t_finish - crew_start[i] <= time_limit:
                            crews_g[i].append(task)
                            crew_last[i] = task
                            crew_finish[i] = t_finish
                            forced = True
                            break
                if not forced:
                    return None

        if not crews_g:
            return None
        sol = {'crews': crews_g}
        try:
            feasible, _ = tools['is_feasible'](sol)
            return sol if feasible else None
        except Exception:
            return None

    # ------------------------------------------------------------------ #
    # Phase 1: Construction based on dispatch
    # ------------------------------------------------------------------ #

    if use_ilp_first:
        # ILP-first: exact solver with generous budget for tiny/hard instances
        ilp_budget = min(remaining() * 0.45, 40.0)
        if remaining() > 3:
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

        # MCF as complement
        if remaining() > 2:
            mcf_budget = min(remaining() * 0.35, 15.0)
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

    elif use_mcf_first:
        # MCF-first: polynomial solver for large/dense instances
        mcf_budget = min(remaining() * 0.30, 20.0)
        if remaining() > 2:
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

        # solve_default as backup for very large
        if is_large and remaining() > 3 and best_sol is None:
            sd_budget = min(remaining() * 0.25, 20.0)
            try:
                sol = tools['solve_default'](time_limit_s=sd_budget)
                update_best(sol)
            except Exception:
                pass

    else:
        # Balanced: medium instances - MCF then short ILP
        mcf_budget = min(remaining() * 0.28, 18.0)
        if remaining() > 2:
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

        if remaining() > 5:
            ilp_budget = min(remaining() * 0.25, 20.0)
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

    # Greedy chain pack as fallback
    if remaining() > 1:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    # Custom greedy constructions
    if remaining() > 0.5:
        sol = greedy_construct()
        update_best(sol)

    for seed in range(10):
        if remaining() < 0.3:
            break
        sol = greedy_construct(shuffle_seed=seed)
        update_best(sol)

    # Emergency fallback
    if best_sol is None:
        if K >= N:
            sol = {'crews': [[i] for i in range(1, N + 1)]}
            update_best(sol)
        if best_sol is None:
            task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
            crews_em = [[] for _ in range(min(K, N))]
            for idx, task in enumerate(task_order):
                crews_em[idx % len(crews_em)].append(task)
            sol = {'crews': [c for c in crews_em if c]}
            update_best(sol)

    if best_sol is None:
        return {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}

    # ------------------------------------------------------------------ #
    # Local Search Neighborhoods
    # ------------------------------------------------------------------ #

    def relocation_pass(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            crew_i = crews[ci]
            if len(crew_i) <= 1:
                continue
            for ti in range(len(crew_i)):
                task = crew_i[ti]
                t_start_task, t_finish_task = tasks[task]

                new_crew_i = crew_i[:ti] + crew_i[ti + 1:]
                if not check_crew_fast(new_crew_i):
                    continue

                old_cost_i = crew_cost_fast(crew_i)
                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                best_gain = 1e-9
                best_cj = -1
                best_pos = -1

                for cj in range(n_crews):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_cost_fast(crew_j)

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None:
                            if tasks[prev_j][1] > t_start_task:
                                continue
                            if (prev_j, task) not in arcs:
                                continue
                        if next_j is not None:
                            if t_finish_task > tasks[next_j][0]:
                                continue
                            if (task, next_j) not in arcs:
                                continue

                        insert_cost = 0.0
                        if prev_j is not None:
                            insert_cost += arcs[(prev_j, task)]
                        if next_j is not None:
                            insert_cost += arcs[(task, next_j)]

                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        new_crew_j = crew_j[:pos] + [task] + crew_j[pos:]
                        duty = tasks[new_crew_j[-1]][1] - tasks[new_crew_j[0]][0]
                        if duty > time_limit:
                            continue

                        gain = saving_i - (insert_cost - bridge_cost)
                        if gain > best_gain:
                            best_gain = gain
                            best_cj = cj
                            best_pos = pos

                if best_cj >= 0:
                    old_cost_j = crew_cost_fast(crews[best_cj])
                    new_crew_j = crews[best_cj][:best_pos] + [task] + crews[best_cj][best_pos:]
                    new_cost_j = crew_cost_fast(new_crew_j)
                    cost = cost - old_cost_i - old_cost_j + new_cost_i + new_cost_j
                    crews[ci] = new_crew_i
                    crews[best_cj] = new_crew_j
                    return crews, cost, True

        return crews, cost, False

    def swap_pass(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            for cj in range(ci + 1, n_crews):
                crew_i = crews[ci]
                crew_j = crews[cj]
                old_cost_ij = crew_cost_fast(crew_i) + crew_cost_fast(crew_j)
                best_gain = 1e-9
                best_pi = -1
                best_pj = -1

                for pi in range(len(crew_i)):
                    for pj in range(len(crew_j)):
                        task_i = crew_i[pi]
                        task_j = crew_j[pj]

                        ti_start, ti_finish = tasks[task_i]
                        tj_start, tj_finish = tasks[task_j]

                        if pi > 0 and tasks[crew_i[pi - 1]][1] > tj_start:
                            continue
                        if pi < len(crew_i) - 1 and tj_finish > tasks[crew_i[pi + 1]][0]:
                            continue
                        if pj > 0 and tasks[crew_j[pj - 1]][1] > ti_start:
                            continue
                        if pj < len(crew_j) - 1 and ti_finish > tasks[crew_j[pj + 1]][0]:
                            continue

                        new_ci = list(crew_i)
                        new_cj = list(crew_j)
                        new_ci[pi] = task_j
                        new_cj[pj] = task_i

                        if not check_crew_fast(new_ci):
                            continue
                        if not check_crew_fast(new_cj):
                            continue

                        new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                        gain = old_cost_ij - new_cost_ij
                        if gain > best_gain:
                            best_gain = gain
                            best_pi = pi
                            best_pj = pj

                if best_pi >= 0:
                    task_i = crew_i[best_pi]
                    task_j = crew_j[best_pj]
                    new_ci = list(crew_i)
                    new_cj = list(crew_j)
                    new_ci[best_pi] = task_j
                    new_cj[best_pj] = task_i
                    new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                    cost = cost - old_cost_ij + new_cost_ij
                    crews[ci] = new_ci
                    crews[cj] = new_cj
                    return crews, cost, True

        return crews, cost, False

    def oropt_pass(crews, cost, seg_len=2):
        n_crews = len(crews)
        for ci in range(n_crews):
            crew_i = crews[ci]
            if len(crew_i) <= seg_len:
                continue
            for ti in range(len(crew_i) - seg_len + 1):
                segment = crew_i[ti:ti + seg_len]
                new_crew_i = crew_i[:ti] + crew_i[ti + seg_len:]
                if not new_crew_i:
                    continue
                if not check_crew_fast(new_crew_i):
                    continue

                seg_valid = True
                for k in range(seg_len - 1):
                    if (segment[k], segment[k + 1]) not in arcs:
                        seg_valid = False
                        break
                if not seg_valid:
                    continue

                old_cost_i = crew_cost_fast(crew_i)
                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                seg_start = tasks[segment[0]][0]
                seg_finish = tasks[segment[-1]][1]

                best_gain = 1e-9
                best_cj = -1
                best_pos = -1

                for cj in range(n_crews):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_cost_fast(crew_j)

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None and tasks[prev_j][1] > seg_start:
                            continue
                        if next_j is not None and seg_finish > tasks[next_j][0]:
                            continue

                        ok = True
                        insert_cost = crew_cost_fast(segment)
                        if prev_j is not None:
                            c = arcs.get((prev_j, segment[0]))
                            if c is None:
                                ok = False
                            else:
                                insert_cost += c
                        if ok and next_j is not None:
                            c = arcs.get((segment[-1], next_j))
                            if c is None:
                                ok = False
                            else:
                                insert_cost += c
                        if not ok:
                            continue

                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        new_crew_j = crew_j[:pos] + segment + crew_j[pos:]
                        duty = tasks[new_crew_j[-1]][1] - tasks[new_crew_j[0]][0]
                        if duty > time_limit:
                            continue

                        new_cost_j = crew_cost_fast(new_crew_j)
                        gain = saving_i - (new_cost_j - old_cost_j)
                        if gain > best_gain:
                            best_gain = gain
                            best_cj = cj
                            best_pos = pos

                if best_cj >= 0:
                    old_cost_j = crew_cost_fast(crews[best_cj])
                    new_crew_j = crews[best_cj][:best_pos] + segment + crews[best_cj][best_pos:]
                    new_cost_j = crew_cost_fast(new_crew_j)
                    cost = cost - old_cost_i - old_cost_j + new_cost_i + new_cost_j
                    crews[ci] = new_crew_i
                    crews[best_cj] = new_crew_j
                    return crews, cost, True

        return crews, cost, False

    def intra_2opt_pass(crews, cost):
        improved = False
        for ci in range(len(crews)):
            crew = crews[ci]
            n = len(crew)
            if n < 3:
                continue
            old_cost_c = crew_cost_fast(crew)
            best_gain = 1e-9
            best_ij = (-1, -1)
            for i in range(n - 1):
                for j in range(i + 2, n):
                    new_crew = crew[:i + 1] + crew[i + 1:j + 1][::-1] + crew[j + 1:]
                    if not check_crew_fast(new_crew):
                        continue
                    new_cost_c = crew_cost_fast(new_crew)
                    gain = old_cost_c - new_cost_c
                    if gain > best_gain:
                        best_gain = gain
                        best_ij = (i, j)
            if best_ij[0] >= 0:
                i, j = best_ij
                new_crew = crew[:i + 1] + crew[i + 1:j + 1][::-1] + crew[j + 1:]
                new_cost_c = crew_cost_fast(new_crew)
                cost = cost - old_cost_c + new_cost_c
                crews[ci] = new_crew
                improved = True
        return crews, cost, improved

    def merge_pass(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            for cj in range(n_crews):
                if ci == cj:
                    continue
                tail_i = crews[ci][-1]
                head_j = crews[cj][0]
                if tasks[tail_i][1] > tasks[head_j][0]:
                    continue
                if (tail_i, head_j) not in arcs:
                    continue
                merged = crews[ci] + crews[cj]
                if not check_crew_fast(merged):
                    continue
                old_cost_ij = crew_cost_fast(crews[ci]) + crew_cost_fast(crews[cj])
                new_cost_m = crew_cost_fast(merged)
                if new_cost_m < old_cost_ij - 1e-9:
                    new_crews = []
                    for k in range(n_crews):
                        if k == ci:
                            new_crews.append(merged)
                        elif k == cj:
                            pass
                        else:
                            new_crews.append(list(crews[k]))
                    cost = cost - old_cost_ij + new_cost_m
                    return new_crews, cost, True
        return crews, cost, False

    def cross_crew_2opt(crews, cost):
        """Exchange tails between two crews: crew_i[:p+1] + crew_j[q+1:] and crew_j[:q+1] + crew_i[p+1:]"""
        n_crews = len(crews)
        for ci in range(n_crews):
            for cj in range(ci + 1, n_crews):
                crew_i = crews[ci]
                crew_j = crews[cj]
                old_cost_ij = crew_cost_fast(crew_i) + crew_cost_fast(crew_j)
                best_gain = 1e-9
                best_p = -1
                best_q = -1

                for p in range(len(crew_i)):
                    for q in range(len(crew_j)):
                        # new_ci = crew_i[:p+1] + crew_j[q+1:]
                        # new_cj = crew_j[:q+1] + crew_i[p+1:]
                        new_ci = crew_i[:p + 1] + crew_j[q + 1:]
                        new_cj = crew_j[:q + 1] + crew_i[p + 1:]

                        if not new_ci or not new_cj:
                            continue
                        if not check_crew_fast(new_ci):
                            continue
                        if not check_crew_fast(new_cj):
                            continue

                        new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                        gain = old_cost_ij - new_cost_ij
                        if gain > best_gain:
                            best_gain = gain
                            best_p = p
                            best_q = q

                if best_p >= 0:
                    new_ci = crew_i[:best_p + 1] + crew_j[best_q + 1:]
                    new_cj = crew_j[:best_q + 1] + crew_i[best_p + 1:]
                    new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                    cost = cost - old_cost_ij + new_cost_ij
                    crews[ci] = new_ci
                    crews[cj] = new_cj
                    return crews, cost, True

        return crews, cost, False

    def run_local_search(crews_in, time_budget):
        crews = [list(c) for c in crews_in]
        cost = solution_cost_fast(crews)
        ls_start = time.time()

        def ls_remaining():
            return time_budget - (time.time() - ls_start)

        avg_crew_sz = N / max(len(crews), 1)
        use_2opt = avg_crew_sz <= 30
        use_cross = avg_crew_sz <= 20

        improved_global = True
        while improved_global and ls_remaining() > 0.05:
            improved_global = False

            # Relocation (most powerful)
            while ls_remaining() > 0.05:
                crews, cost, imp = relocation_pass(crews, cost)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            # Swap
            while ls_remaining() > 0.05:
                crews, cost, imp = swap_pass(crews, cost)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            # Or-opt seg=2
            while ls_remaining() > 0.05:
                crews, cost, imp = oropt_pass(crews, cost, seg_len=2)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            # Or-opt seg=3
            while ls_remaining() > 0.05:
                crews, cost, imp = oropt_pass(crews, cost, seg_len=3)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            # Cross-crew 2-opt (tail exchange) - good for small instances
            if use_cross:
                while ls_remaining() > 0.05:
                    crews, cost, imp = cross_crew_2opt(crews, cost)
                    if not imp:
                        break
                    improved_global = True

            if ls_remaining() < 0.05:
                break

            # 2-opt within crews
            if use_2opt:
                while ls_remaining() > 0.05:
                    crews, cost, imp = intra_2opt_pass(crews, cost)
                    if not imp:
                        break
                    improved_global = True

            if ls_remaining() < 0.05:
                break

            # Merge
            while ls_remaining() > 0.05:
                crews, cost, imp = merge_pass(crews, cost)
                if not imp:
                    break
                improved_global = True

        return crews, cost

    def perturbation(crews_in, rng, n_moves=3):
        crews = [list(c) for c in crews_in]
        for _ in range(n_moves):
            if not crews:
                break
            eligible = [i for i in range(len(crews)) if len(crews[i]) > 1]
            if not eligible:
                break
            ci = rng.choice(eligible)
            crew_i = crews[ci]
            ti = rng.randint(0, len(crew_i) - 1)
            task = crew_i[ti]
            new_crew_i = crew_i[:ti] + crew_i[ti + 1:]
            if not check_crew_fast(new_crew_i):
                continue
            other_crews = [j for j in range(len(crews)) if j != ci]
            if not other_crews:
                continue
            rng.shuffle(other_crews)
            inserted = False
            for cj in other_crews:
                crew_j = crews[cj]
                positions = list(range(len(crew_j) + 1))
                rng.shuffle(positions)
                for pos in positions:
                    new_crew_j = crew_j[:pos] + [task] + crew_j[pos:]
                    if check_crew_fast(new_crew_j):
                        crews[ci] = new_crew_i
                        crews[cj] = new_crew_j
                        inserted = True
                        break
                if inserted:
                    break
            if not inserted and len(crews) < K:
                crews[ci] = new_crew_i
                crews.append([task])
        return [c for c in crews if c]

    def double_bridge_perturbation(crews_in, rng):
        """Double-bridge style perturbation: split two crews and recombine."""
        crews = [list(c) for c in crews_in]
        eligible = [i for i in range(len(crews)) if len(crews[i]) >= 2]
        if len(eligible) < 2:
            return crews
        ci, cj = rng.sample(eligible, 2)
        crew_i = crews[ci]
        crew_j = crews[cj]
        # Split points
        pi = rng.randint(1, len(crew_i) - 1) if len(crew_i) > 1 else 1
        pj = rng.randint(1, len(crew_j) - 1) if len(crew_j) > 1 else 1
        # Try recombining: crew_i[:pi] + crew_j[pj:] and crew_j[:pj] + crew_i[pi:]
        new_ci = crew_i[:pi] + crew_j[pj:]
        new_cj = crew_j[:pj] + crew_i[pi:]
        if new_ci and new_cj and check_crew_fast(new_ci) and check_crew_fast(new_cj):
            crews[ci] = new_ci
            crews[cj] = new_cj
        return crews

    # ------------------------------------------------------------------ #
    # ILS Main Loop
    # ------------------------------------------------------------------ #
    if best_sol is not None and remaining() > 1.0:
        rng = random.Random(42)

        # Tune initial LS budget based on regime
        if use_ilp_first:
            # For ILP regime, ILP may already be near-optimal; moderate LS
            initial_ls_frac = 0.45
            max_initial_ls = 25.0
        elif is_large:
            initial_ls_frac = 0.38
            max_initial_ls = 25.0
        else:
            initial_ls_frac = 0.42
            max_initial_ls = 30.0

        initial_ls_budget = min(remaining() * initial_ls_frac, max_initial_ls)
        current_crews, current_cost = run_local_search(best_sol['crews'], initial_ls_budget)

        sol = {'crews': current_crews}
        update_best(sol)

        # ILS loop
        ils_crews = [list(c) for c in best_sol['crews']]
        no_improve_count = 0
        iteration = 0

        # For ILP-first regime, also try a second ILP call with remaining time
        # if the ILS is stuck early
        ilp_retry_done = False

        while remaining() > 1.5:
            iteration += 1

            # Adaptive perturbation strength
            perturb_strength = 3 + no_improve_count // 3

            # Alternate between relocation perturbation and double-bridge
            if iteration % 4 == 0 and not is_large:
                perturbed = double_bridge_perturbation(ils_crews, rng)
                # Also do some relocations
                perturbed = perturbation(perturbed, rng, n_moves=2)
            else:
                perturbed = perturbation(ils_crews, rng, n_moves=perturb_strength)

            if not perturbed:
                break

            # Verify all tasks present after perturbation
            all_t = set()
            for c in perturbed:
                all_t.update(c)
            if len(all_t) != N:
                ils_crews = [list(c) for c in best_sol['crews']]
                no_improve_count = 0
                continue

            # LS budget per iteration - scale with instance size
            if is_tiny:
                ls_time = min(remaining() * 0.50, 15.0)
            elif is_small:
                ls_time = min(remaining() * 0.45, 12.0)
            elif is_medium:
                ls_time = min(remaining() * 0.38, 9.0)
            else:
                ls_time = min(remaining() * 0.30, 6.0)

            new_crews, new_cost = run_local_search(perturbed, ls_time)
            sol = {'crews': new_crews}

            if update_best(sol):
                ils_crews = [list(c) for c in new_crews]
                no_improve_count = 0
            else:
                no_improve_count += 1
                # Accept slightly worse for diversification
                if new_cost < best_cost * 1.02:
                    ils_crews = [list(c) for c in new_crews]
                else:
                    ils_crews = [list(c) for c in best_sol['crews']]

            # For ILP-first regime: retry ILP if stuck and time allows
            if use_ilp_first and not ilp_retry_done and no_improve_count >= 5 and remaining() > 8.0:
                ilp_retry_budget = min(remaining() * 0.35, 15.0)
                try:
                    sol2 = tools['ilp_crew_scheduling'](time_limit_s=ilp_retry_budget)
                    if update_best(sol2):
                        ils_crews = [list(c) for c in best_sol['crews']]
                        no_improve_count = 0
                except Exception:
                    pass
                ilp_retry_done = True

            # Restart from best if stuck
            if no_improve_count >= 8:
                ils_crews = [list(c) for c in best_sol['crews']]
                no_improve_count = 0

    return best_sol if best_sol is not None else {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    succ = defaultdict(list)
    pred = defaultdict(list)

    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ[i].append((tasks[j][0], j, cost))
            pred[j].append((tasks[i][1], i, cost))

    for t in range(1, N + 1):
        succ[t].sort()
        pred[t].sort()

    tasks_by_start = sorted(range(1, N + 1), key=lambda t: tasks[t][0])

    def check_crew(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arcs:
                return False
        return True

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # Use 35% of budget for initial solution (down from 50%)
    init_budget = min(remaining() * 0.35, time_limit_s * 0.35)
    if init_budget > 0.5:
        try:
            sol = tools['solve_default'](time_limit_s=init_budget)
            update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 1:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 1:
        sol = _greedy_construct(N, K, tasks, arcs, time_limit)
        update_best(sol)

    if best_sol is None:
        if K >= N:
            best_sol = {'crews': [[i] for i in range(1, N + 1)]}
        else:
            task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
            crews_e = [[] for _ in range(K)]
            for idx, t in enumerate(task_order):
                crews_e[idx % K].append(t)
            best_sol = {'crews': [c for c in crews_e if c]}

    if remaining() > 1.0:
        best_sol = _lns_sa(
            best_sol, N, K, tasks, arcs, time_limit,
            succ, pred, tasks_by_start, tools,
            start_time, time_limit_s
        )

    return best_sol


def _greedy_construct(N, K, tasks, arcs, time_limit):
    task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
    crews = []
    crew_last = []
    crew_start = []
    crew_finish = []

    for task in task_order:
        t_start, t_finish = tasks[task]
        best_crew = -1
        best_cost_val = float('inf')

        for i in range(len(crews)):
            last = crew_last[i]
            if crew_finish[i] > t_start:
                continue
            if (last, task) not in arcs:
                continue
            if t_finish - crew_start[i] > time_limit:
                continue
            c = arcs[(last, task)]
            if c < best_cost_val:
                best_cost_val = c
                best_crew = i

        if best_crew >= 0:
            crews[best_crew].append(task)
            crew_last[best_crew] = task
            crew_finish[best_crew] = t_finish
        elif len(crews) < K:
            crews.append([task])
            crew_last.append(task)
            crew_start.append(t_start)
            crew_finish.append(t_finish)
        else:
            forced = False
            for i in range(len(crews)):
                last = crew_last[i]
                if crew_finish[i] <= t_start and (last, task) in arcs:
                    if t_finish - crew_start[i] <= time_limit:
                        crews[i].append(task)
                        crew_last[i] = task
                        crew_finish[i] = t_finish
                        forced = True
                        break
            if not forced:
                return None

    return {'crews': crews}


def _lns_sa(initial_sol, N, K, tasks, arcs, time_limit,
            succ, pred, tasks_by_start, tools,
            start_time, time_limit_s):

    def remaining():
        return time_limit_s - (time.time() - start_time)

    def check_crew(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arcs:
                return False
        return True

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    def regret_repair(unassigned, current_crews, max_total_crews):
        if not unassigned:
            return current_crews

        crews = [list(c) for c in current_crews]
        remaining_tasks = list(unassigned)

        while remaining_tasks:
            regrets = []

            for task in remaining_tasks:
                ts_t, tf_t = tasks[task]
                insertions = []

                for ci, crew in enumerate(crews):
                    for pos in range(len(crew) + 1):
                        if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                            continue
                        if pos < len(crew) and tf_t > tasks[crew[pos]][0]:
                            continue

                        cost_add = 0.0
                        ok = True
                        if pos > 0:
                            c = arcs.get((crew[pos - 1], task))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if ok and pos < len(crew):
                            c = arcs.get((task, crew[pos]))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if not ok:
                            continue

                        bridge = 0.0
                        if pos > 0 and pos < len(crew):
                            bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                        new_crew = crew[:pos] + [task] + crew[pos:]
                        dt = tasks[new_crew[-1]][1] - tasks[new_crew[0]][0]
                        if dt > time_limit:
                            continue

                        delta = cost_add - bridge
                        insertions.append((delta, ci, pos))

                if len(crews) < max_total_crews:
                    insertions.append((0.0, -1, 0))

                if not insertions:
                    return None

                insertions.sort(key=lambda x: x[0])
                best_cost_ins = insertions[0][0]
                second_cost_ins = insertions[1][0] if len(insertions) > 1 else best_cost_ins + 1e9

                regret_val = second_cost_ins - best_cost_ins
                regrets.append((regret_val, task, insertions[0]))

            regrets.sort(key=lambda x: -x[0])
            _, task_to_insert, (delta, ci, pos) = regrets[0]

            if ci == -1:
                crews.append([task_to_insert])
            else:
                crews[ci] = crews[ci][:pos] + [task_to_insert] + crews[ci][pos:]

            remaining_tasks.remove(task_to_insert)

        return crews

    def greedy_repair(unassigned, current_crews, max_total_crews):
        if not unassigned:
            return current_crews

        crews = [list(c) for c in current_crews]
        task_order = sorted(unassigned, key=lambda t: tasks[t][0])

        for task in task_order:
            ts_t, tf_t = tasks[task]
            best_delta = float('inf')
            best_ci = -1
            best_pos = -1

            for ci, crew in enumerate(crews):
                for pos in range(len(crew) + 1):
                    if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                        continue
                    if pos < len(crew) and tf_t > tasks[crew[pos]][0]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < len(crew):
                        c = arcs.get((task, crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if pos > 0 and pos < len(crew):
                        bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                    new_crew = crew[:pos] + [task] + crew[pos:]
                    dt = tasks[new_crew[-1]][1] - tasks[new_crew[0]][0]
                    if dt > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_delta:
                        best_delta = delta
                        best_ci = ci
                        best_pos = pos

            if best_ci >= 0:
                crews[best_ci] = crews[best_ci][:best_pos] + [task] + crews[best_ci][best_pos:]
            elif len(crews) < max_total_crews:
                crews.append([task])
            else:
                return None

        return crews

    def destroy_random_tasks(crews, n_remove, rng):
        all_tasks = [(ci, pos, t)
                     for ci, crew in enumerate(crews)
                     for pos, t in enumerate(crew)]
        if not all_tasks:
            return crews, []

        n_remove = min(n_remove, len(all_tasks))
        removed_entries = rng.sample(all_tasks, n_remove)
        removed_tasks = [t for _, _, t in removed_entries]
        removed_set = set(removed_tasks)

        new_crews = []
        for crew in crews:
            new_crew = [t for t in crew if t not in removed_set]
            if new_crew:
                new_crews.append(new_crew)

        return new_crews, removed_tasks

    def destroy_worst_crew(crews, n_crews_to_destroy, rng):
        if not crews:
            return crews, []

        crew_costs = [(crew_cost_fn(crew), ci) for ci, crew in enumerate(crews)]
        crew_costs.sort(reverse=True)

        n_destroy = min(n_crews_to_destroy, len(crews))
        destroyed_indices = set(ci for _, ci in crew_costs[:n_destroy])

        removed_tasks = []
        new_crews = []
        for ci, crew in enumerate(crews):
            if ci in destroyed_indices:
                removed_tasks.extend(crew)
            else:
                new_crews.append(crew)

        return new_crews, removed_tasks

    def destroy_segment(crews, rng):
        if not crews:
            return crews, []

        crew_costs = [max(crew_cost_fn(crew), 0.01) for crew in crews]
        total_w = sum(crew_costs)
        probs = [c / total_w for c in crew_costs]

        r = rng.random()
        cumulative = 0.0
        ci = 0
        for i, p in enumerate(probs):
            cumulative += p
            if r <= cumulative:
                ci = i
                break

        crew = crews[ci]
        if len(crew) <= 1:
            return crews, []

        seg_len = rng.randint(1, max(1, len(crew) // 2))
        start_pos = rng.randint(0, len(crew) - seg_len)
        removed = crew[start_pos:start_pos + seg_len]
        new_crew = crew[:start_pos] + crew[start_pos + seg_len:]

        new_crews = []
        for i, c in enumerate(crews):
            if i == ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)

        return new_crews, removed

    def destroy_related_tasks(crews, n_remove, rng):
        all_tasks_flat = [t for crew in crews for t in crew]
        if not all_tasks_flat:
            return crews, []

        seed_task = rng.choice(all_tasks_flat)
        removed_set = {seed_task}

        candidates = set()
        for t in removed_set:
            for _, j, _ in succ[t]:
                if j in all_tasks_flat:
                    candidates.add(j)
            for _, i, _ in pred[t]:
                if i in all_tasks_flat:
                    candidates.add(i)

        seed_start = tasks[seed_task][0]
        for t in all_tasks_flat:
            if abs(tasks[t][0] - seed_start) < (time_limit * 0.1):
                candidates.add(t)

        candidates -= removed_set
        candidates = list(candidates)
        rng.shuffle(candidates)

        n_remove = min(n_remove, len(all_tasks_flat))
        for t in candidates:
            if len(removed_set) >= n_remove:
                break
            removed_set.add(t)

        removed_tasks = list(removed_set)
        new_crews = []
        for crew in crews:
            new_crew = [t for t in crew if t not in removed_set]
            if new_crew:
                new_crews.append(new_crew)

        return new_crews, removed_tasks

    # Main LNS + SA loop
    current_crews = [list(c) for c in initial_sol['crews']]
    current_cost = total_cost_fn(current_crews)
    best_crews = [list(c) for c in current_crews]
    best_cost = current_cost

    rng = random.Random(42)

    if current_cost > 0 and current_cost < float('inf'):
        T_init = max(0.05 * current_cost / math.log(2), 1.0)
    else:
        T_init = 100.0

    T_min = 1e-4
    T = T_init

    ls_time = remaining() - 0.5
    if ls_time <= 0:
        return initial_sol

    # Use a less aggressive cooling rate to allow more exploration
    estimated_iters = max(50, int(ls_time * 40))
    cooling_rate = (T_min / T_init) ** (1.0 / max(1, estimated_iters))

    n_destroy_base = max(1, N // 10)

    iteration = 0
    no_improve_streak = 0

    destroy_ops = ['random', 'worst_crew', 'segment', 'related']
    op_weights = [1.0, 1.0, 1.0, 1.0]
    op_success = [0, 0, 0, 0]
    op_tries = [1, 1, 1, 1]

    # --- MODIFICATION: Track acceptance rate for adaptive reheating ---
    # Use a sliding window to monitor recent acceptance rate
    accept_window_size = 20
    accept_history = []  # 1 = accepted, 0 = rejected
    reheat_count = 0
    max_reheats = 5  # limit total reheats to avoid infinite warming

    def select_destroy_op():
        total_tries = sum(op_tries)
        scores = []
        for i in range(len(destroy_ops)):
            exploit = op_success[i] / op_tries[i]
            explore = math.sqrt(2 * math.log(total_tries) / op_tries[i])
            scores.append(exploit + 0.3 * explore)
        return scores.index(max(scores))

    while remaining() > 0.5:
        iteration += 1
        T = max(T * cooling_rate, T_min)

        # --- MODIFICATION: Adaptive reheating based on acceptance rate ---
        # If acceptance rate in recent window is too low, reheat temperature
        if (len(accept_history) >= accept_window_size and
                reheat_count < max_reheats and
                remaining() > 1.5):
            recent_accept_rate = sum(accept_history[-accept_window_size:]) / accept_window_size
            if recent_accept_rate < 0.05:
                # Acceptance rate too low: reheat to 20% of initial temperature
                T = max(T, T_init * 0.20)
                reheat_count += 1
                # Reset accept history to avoid immediate re-trigger
                accept_history = []
                # Reset to best solution on reheat for fresh exploration
                current_crews = [list(c) for c in best_crews]
                current_cost = best_cost
                no_improve_streak = 0

        n_destroy = n_destroy_base + min(no_improve_streak // 5, N // 5)
        n_destroy = min(n_destroy, max(1, N // 2))

        op_idx = select_destroy_op()
        op_tries[op_idx] += 1
        destroy_op = destroy_ops[op_idx]

        if destroy_op == 'random':
            partial_crews, removed = destroy_random_tasks(current_crews, n_destroy, rng)
        elif destroy_op == 'worst_crew':
            n_crews_destroy = max(1, min(3, len(current_crews) // 3))
            partial_crews, removed = destroy_worst_crew(current_crews, n_crews_destroy, rng)
        elif destroy_op == 'segment':
            partial_crews, removed = destroy_segment(current_crews, rng)
        else:
            partial_crews, removed = destroy_related_tasks(current_crews, n_destroy, rng)

        if not removed:
            accept_history.append(0)
            continue

        max_crews = K
        if iteration % 3 == 0:
            if len(removed) <= 20:
                new_crews = regret_repair(removed, partial_crews, max_crews)
            else:
                new_crews = greedy_repair(removed, partial_crews, max_crews)
        else:
            new_crews = greedy_repair(removed, partial_crews, max_crews)

        if new_crews is None:
            accept_history.append(0)
            continue

        all_covered = set(t for crew in new_crews for t in crew)
        if len(all_covered) != N:
            missing = set(range(1, N + 1)) - all_covered
            new_crews = greedy_repair(list(missing), new_crews, max_crews)
            if new_crews is None:
                accept_history.append(0)
                continue
            all_covered2 = set(t for crew in new_crews for t in crew)
            if len(all_covered2) != N:
                accept_history.append(0)
                continue

        if len(new_crews) > K:
            accept_history.append(0)
            continue

        all_valid = True
        for crew in new_crews:
            if not check_crew(crew):
                all_valid = False
                break
        if not all_valid:
            accept_history.append(0)
            continue

        new_cost = total_cost_fn(new_crews)

        delta = new_cost - current_cost
        accept = False
        if delta < 0:
            accept = True
        elif T > T_min * 10:
            prob = math.exp(-delta / T)
            accept = rng.random() < prob

        accept_history.append(1 if accept else 0)

        if accept:
            current_crews = new_crews
            current_cost = new_cost

            if new_cost < best_cost - 1e-9:
                candidate = {'crews': [list(c) for c in new_crews]}
                try:
                    feasible, _ = tools['is_feasible'](candidate)
                    if feasible:
                        obj = tools['objective'](candidate)
                        if obj < best_cost:
                            best_cost = obj
                            best_crews = [list(c) for c in new_crews]
                            op_success[op_idx] += 1
                            no_improve_streak = 0
                except Exception:
                    pass
            else:
                no_improve_streak += 1
        else:
            no_improve_streak += 1

        if no_improve_streak > 50 and remaining() > 2.0:
            current_crews = [list(c) for c in best_crews]
            current_cost = best_cost
            no_improve_streak = 0
            # Only reheat here if we haven't hit the adaptive reheat recently
            T = max(T, T_init * 0.1)

    result = {'crews': [list(c) for c in best_crews if c]}
    try:
        feasible, _ = tools['is_feasible'](result)
        if feasible:
            return result
    except Exception:
        pass

    return initial_sol

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # ------------------------------------------------------------------ #
    # Instance feature analysis for dispatch
    # ------------------------------------------------------------------ #
    n_arcs = len(arcs)
    arc_density = n_arcs / max(1, N * (N - 1))
    k_ratio = K / max(1, N)

    # Average successors per task
    succ_counts = defaultdict(int)
    for (i, j) in arcs.keys():
        if tasks[i][1] <= tasks[j][0]:
            succ_counts[i] += 1
    avg_successors = sum(succ_counts.values()) / max(1, N)

    # Time span analysis
    all_starts = [tasks[t][0] for t in range(1, N + 1)]
    all_finishes = [tasks[t][1] for t in range(1, N + 1)]
    time_span = max(all_finishes) - min(all_starts)
    avg_task_duration = sum(tasks[t][1] - tasks[t][0] for t in range(1, N + 1)) / max(1, N)

    # Regime decision:
    # Use A-style (LNS+SA) when:
    #   - N is large (> 150): LNS scales better
    #   - K/N ratio is small (tight packing): needs global repair
    #   - arc density is high: many repair options available
    # Use B-style (move-based LS) when:
    #   - N is small (<= 150): exhaustive moves feasible
    #   - K/N ratio is generous: fine-tuning works well
    #   - arc density is low: moves must be careful

    use_lns_style = (
        N > 150 or
        k_ratio < 0.3 or
        (avg_successors > 3.0 and N > 80)
    )

    # ------------------------------------------------------------------ #
    # Shared data structures
    # ------------------------------------------------------------------ #
    arc_set = set(arcs.keys())

    succ_list = defaultdict(list)
    pred_list = defaultdict(list)
    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ_list[i].append(j)
            pred_list[j].append(i)
    for t in range(1, N + 1):
        succ_list[t].sort(key=lambda x: tasks[x][0])
        pred_list[t].sort(key=lambda x: tasks[x][1])

    task_start = {t: tasks[t][0] for t in range(1, N + 1)}
    task_finish = {t: tasks[t][1] for t in range(1, N + 1)}

    def crew_cost_fast(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            c = arcs.get((crew[idx], crew[idx + 1]))
            if c is None:
                return float('inf')
            cost += c
        return cost

    def check_crew_fast(crew):
        if not crew:
            return False
        if task_finish[crew[-1]] - task_start[crew[0]] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if task_finish[t1] > task_start[t2]:
                return False
            if (t1, t2) not in arc_set:
                return False
        return True

    def solution_cost_fast(crews):
        return sum(crew_cost_fast(c) for c in crews)

    # ------------------------------------------------------------------ #
    # Best solution tracking
    # ------------------------------------------------------------------ #
    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # ------------------------------------------------------------------ #
    # Phase 1: Initial solution construction
    # ------------------------------------------------------------------ #
    if use_lns_style:
        # A-style: use solve_default with generous budget
        init_budget = min(remaining() * 0.50, time_limit_s * 0.50)
        if init_budget > 0.5:
            try:
                sol = tools['solve_default'](time_limit_s=init_budget)
                update_best(sol)
            except Exception:
                pass
    else:
        # B-style: try MCF first, then ILP for small instances
        if remaining() > 3:
            mcf_budget = min(remaining() * 0.25, 15.0)
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

        if remaining() > 5 and N <= 200:
            ilp_budget = min(remaining() * 0.35, 40.0)
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

        if best_sol is None and remaining() > 3:
            sd_budget = min(remaining() * 0.25, 15.0)
            try:
                sol = tools['solve_default'](time_limit_s=sd_budget)
                update_best(sol)
            except Exception:
                pass

    # Greedy chain pack fallback
    if remaining() > 1:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    # Custom greedy construction
    def greedy_construct(shuffle_seed=None, alpha=0.0):
        task_order = sorted(range(1, N + 1), key=lambda t: task_start[t])
        rng_g = random.Random(shuffle_seed) if shuffle_seed is not None else None

        crews_g = []
        crew_last = []
        crew_start_t = []
        crew_finish_t = []

        for task in task_order:
            t_start = task_start[task]
            t_finish = task_finish[task]

            candidates = []
            for i in range(len(crews_g)):
                last = crew_last[i]
                if crew_finish_t[i] > t_start:
                    continue
                if (last, task) not in arc_set:
                    continue
                if t_finish - crew_start_t[i] > time_limit:
                    continue
                c = arcs[(last, task)]
                candidates.append((c, i))

            if candidates:
                if rng_g is not None and alpha > 0 and len(candidates) > 1:
                    candidates.sort()
                    min_c = candidates[0][0]
                    max_c = candidates[-1][0]
                    threshold = min_c + alpha * (max_c - min_c)
                    rcl = [i for c, i in candidates if c <= threshold]
                    chosen = rng_g.choice(rcl)
                else:
                    chosen = min(candidates, key=lambda x: x[0])[1]
                crews_g[chosen].append(task)
                crew_last[chosen] = task
                crew_finish_t[chosen] = t_finish
            elif len(crews_g) < K:
                crews_g.append([task])
                crew_last.append(task)
                crew_start_t.append(t_start)
                crew_finish_t.append(t_finish)
            else:
                forced = False
                for i in range(len(crews_g)):
                    last = crew_last[i]
                    if crew_finish_t[i] <= t_start and (last, task) in arc_set:
                        if t_finish - crew_start_t[i] <= time_limit:
                            crews_g[i].append(task)
                            crew_last[i] = task
                            crew_finish_t[i] = t_finish
                            forced = True
                            break
                if not forced:
                    return None

        if not crews_g:
            return None
        sol = {'crews': crews_g}
        try:
            feasible, _ = tools['is_feasible'](sol)
            return sol if feasible else None
        except Exception:
            return None

    if remaining() > 0.5:
        sol = greedy_construct()
        update_best(sol)

    for seed in range(3):
        if remaining() < 0.3:
            break
        for alpha in [0.1, 0.3]:
            if remaining() < 0.2:
                break
            sol = greedy_construct(shuffle_seed=seed, alpha=alpha)
            update_best(sol)

    # Emergency fallback
    if best_sol is None:
        if K >= N:
            sol = {'crews': [[i] for i in range(1, N + 1)]}
            update_best(sol)

    if best_sol is None:
        task_order = sorted(range(1, N + 1), key=lambda t: task_start[t])
        crews_em = [[] for _ in range(min(K, N))]
        for idx, task in enumerate(task_order):
            crews_em[idx % len(crews_em)].append(task)
        sol = {'crews': [c for c in crews_em if c]}
        update_best(sol)

    if best_sol is None:
        return {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}

    # ================================================================== #
    # Phase 2: Optimization - dispatch to A-style or B-style
    # ================================================================== #

    if use_lns_style:
        # ---------------------------------------------------------------- #
        # A-style: LNS + Simulated Annealing
        # ---------------------------------------------------------------- #
        result = _run_lns_sa(
            best_sol, N, K, tasks, arcs, time_limit,
            succ_list, pred_list, arc_set,
            task_start, task_finish,
            tools, start_time, time_limit_s
        )
        if result is not None:
            update_best(result)
    else:
        # ---------------------------------------------------------------- #
        # B-style: Move-based Local Search + SA
        # ---------------------------------------------------------------- #
        result = _run_move_ls_sa(
            best_sol, N, K, tasks, arcs, time_limit,
            arc_set, task_start, task_finish,
            tools, start_time, time_limit_s
        )
        if result is not None:
            update_best(result)

    return best_sol if best_sol is not None else {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}


# ====================================================================== #
# A-style: LNS + SA helpers
# ====================================================================== #

def _run_lns_sa(initial_sol, N, K, tasks, arcs, time_limit,
                succ_list, pred_list, arc_set,
                task_start, task_finish,
                tools, start_time, time_limit_s):

    def remaining():
        return time_limit_s - (time.time() - start_time)

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            c = arcs.get((crew[idx], crew[idx + 1]))
            if c is None:
                return float('inf')
            cost += c
        return cost

    def check_crew(crew):
        if not crew:
            return False
        if task_finish[crew[-1]] - task_start[crew[0]] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if task_finish[t1] > task_start[t2]:
                return False
            if (t1, t2) not in arc_set:
                return False
        return True

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    def greedy_repair(unassigned, current_crews, max_total_crews):
        if not unassigned:
            return current_crews
        crews = [list(c) for c in current_crews]
        task_order = sorted(unassigned, key=lambda t: task_start[t])

        for task in task_order:
            ts_t = task_start[task]
            tf_t = task_finish[task]
            best_delta = float('inf')
            best_ci = -1
            best_pos = -1

            for ci, crew in enumerate(crews):
                for pos in range(len(crew) + 1):
                    if pos > 0 and task_finish[crew[pos - 1]] > ts_t:
                        continue
                    if pos < len(crew) and tf_t > task_start[crew[pos]]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < len(crew):
                        c = arcs.get((task, crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if pos > 0 and pos < len(crew):
                        bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                    new_crew = crew[:pos] + [task] + crew[pos:]
                    dt = task_finish[new_crew[-1]] - task_start[new_crew[0]]
                    if dt > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_delta:
                        best_delta = delta
                        best_ci = ci
                        best_pos = pos

            if best_ci >= 0:
                crews[best_ci] = crews[best_ci][:best_pos] + [task] + crews[best_ci][best_pos:]
            elif len(crews) < max_total_crews:
                crews.append([task])
            else:
                return None

        return crews

    def regret_repair(unassigned, current_crews, max_total_crews):
        if not unassigned:
            return current_crews
        if len(unassigned) > 25:
            return greedy_repair(unassigned, current_crews, max_total_crews)

        crews = [list(c) for c in current_crews]
        remaining_tasks = list(unassigned)

        while remaining_tasks:
            regrets = []
            for task in remaining_tasks:
                ts_t = task_start[task]
                tf_t = task_finish[task]
                insertions = []

                for ci, crew in enumerate(crews):
                    for pos in range(len(crew) + 1):
                        if pos > 0 and task_finish[crew[pos - 1]] > ts_t:
                            continue
                        if pos < len(crew) and tf_t > task_start[crew[pos]]:
                            continue

                        cost_add = 0.0
                        ok = True
                        if pos > 0:
                            c = arcs.get((crew[pos - 1], task))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if ok and pos < len(crew):
                            c = arcs.get((task, crew[pos]))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if not ok:
                            continue

                        bridge = 0.0
                        if pos > 0 and pos < len(crew):
                            bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                        new_crew = crew[:pos] + [task] + crew[pos:]
                        dt = task_finish[new_crew[-1]] - task_start[new_crew[0]]
                        if dt > time_limit:
                            continue

                        delta = cost_add - bridge
                        insertions.append((delta, ci, pos))

                if len(crews) < max_total_crews:
                    insertions.append((0.0, -1, 0))

                if not insertions:
                    return None

                insertions.sort(key=lambda x: x[0])
                best_c = insertions[0][0]
                second_c = insertions[1][0] if len(insertions) > 1 else best_c + 1e9
                regret_val = second_c - best_c
                regrets.append((regret_val, task, insertions[0]))

            regrets.sort(key=lambda x: -x[0])
            _, task_to_insert, (delta, ci, pos) = regrets[0]

            if ci == -1:
                crews.append([task_to_insert])
            else:
                crews[ci] = crews[ci][:pos] + [task_to_insert] + crews[ci][pos:]

            remaining_tasks.remove(task_to_insert)

        return crews

    def destroy_random_tasks(crews, n_remove, rng):
        all_tasks = [(ci, pos, t) for ci, crew in enumerate(crews) for pos, t in enumerate(crew)]
        if not all_tasks:
            return crews, []
        n_remove = min(n_remove, len(all_tasks))
        removed_entries = rng.sample(all_tasks, n_remove)
        removed_tasks = [t for _, _, t in removed_entries]
        removed_set = set(removed_tasks)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, removed_tasks

    def destroy_worst_crew(crews, n_crews_to_destroy, rng):
        if not crews:
            return crews, []
        crew_costs = [(crew_cost_fn(crew), ci) for ci, crew in enumerate(crews)]
        crew_costs.sort(reverse=True)
        n_destroy = min(n_crews_to_destroy, len(crews))
        destroyed_indices = set(ci for _, ci in crew_costs[:n_destroy])
        removed_tasks = []
        new_crews = []
        for ci, crew in enumerate(crews):
            if ci in destroyed_indices:
                removed_tasks.extend(crew)
            else:
                new_crews.append(crew)
        return new_crews, removed_tasks

    def destroy_segment(crews, rng):
        if not crews:
            return crews, []
        crew_costs_w = [max(crew_cost_fn(crew), 0.01) for crew in crews]
        total_w = sum(crew_costs_w)
        probs = [c / total_w for c in crew_costs_w]
        r = rng.random()
        cumulative = 0.0
        ci = 0
        for i, p in enumerate(probs):
            cumulative += p
            if r <= cumulative:
                ci = i
                break
        crew = crews[ci]
        if len(crew) <= 1:
            return crews, []
        seg_len = rng.randint(1, max(1, len(crew) // 2))
        start_pos = rng.randint(0, len(crew) - seg_len)
        removed = crew[start_pos:start_pos + seg_len]
        new_crew = crew[:start_pos] + crew[start_pos + seg_len:]
        new_crews = []
        for i, c in enumerate(crews):
            if i == ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)
        return new_crews, removed

    def destroy_related_tasks(crews, n_remove, rng):
        all_tasks_flat = [t for crew in crews for t in crew]
        if not all_tasks_flat:
            return crews, []
        seed_task = rng.choice(all_tasks_flat)
        removed_set = {seed_task}
        candidates = set()
        for j in succ_list[seed_task]:
            candidates.add(j)
        for i in pred_list[seed_task]:
            candidates.add(i)
        seed_s = task_start[seed_task]
        for t in all_tasks_flat:
            if abs(task_start[t] - seed_s) < (time_limit * 0.1):
                candidates.add(t)
        candidates -= removed_set
        candidates = list(candidates)
        rng.shuffle(candidates)
        n_remove = min(n_remove, len(all_tasks_flat))
        for t in candidates:
            if len(removed_set) >= n_remove:
                break
            removed_set.add(t)
        removed_tasks = list(removed_set)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, removed_tasks

    # Main LNS+SA loop
    current_crews = [list(c) for c in initial_sol['crews']]
    current_cost = total_cost_fn(current_crews)
    best_crews = [list(c) for c in current_crews]
    best_cost = current_cost

    rng = random.Random(42)

    if current_cost > 0 and current_cost < float('inf'):
        T_init = max(0.05 * current_cost / math.log(2), 1.0)
    else:
        T_init = 100.0

    T_min = 1e-4
    T = T_init

    ls_time = remaining() - 0.5
    if ls_time <= 0:
        return initial_sol

    estimated_iters = max(50, int(ls_time * 30))
    cooling_rate = (T_min / T_init) ** (1.0 / max(1, estimated_iters))

    n_destroy_base = max(1, N // 10)

    destroy_ops = ['random', 'worst_crew', 'segment', 'related']
    op_success = [0, 0, 0, 0]
    op_tries = [1, 1, 1, 1]

    def select_destroy_op():
        total_tries = sum(op_tries)
        scores = []
        for i in range(len(destroy_ops)):
            exploit = op_success[i] / op_tries[i]
            explore = math.sqrt(2 * math.log(total_tries) / op_tries[i])
            scores.append(exploit + 0.3 * explore)
        return scores.index(max(scores))

    iteration = 0
    no_improve_streak = 0

    while remaining() > 0.5:
        iteration += 1
        T = max(T * cooling_rate, T_min)

        n_destroy = n_destroy_base + min(no_improve_streak // 5, N // 5)
        n_destroy = min(n_destroy, max(1, N // 2))

        op_idx = select_destroy_op()
        op_tries[op_idx] += 1
        destroy_op = destroy_ops[op_idx]

        if destroy_op == 'random':
            partial_crews, removed = destroy_random_tasks(current_crews, n_destroy, rng)
        elif destroy_op == 'worst_crew':
            n_crews_destroy = max(1, min(3, len(current_crews) // 3))
            partial_crews, removed = destroy_worst_crew(current_crews, n_crews_destroy, rng)
        elif destroy_op == 'segment':
            partial_crews, removed = destroy_segment(current_crews, rng)
        else:
            partial_crews, removed = destroy_related_tasks(current_crews, n_destroy, rng)

        if not removed:
            continue

        if iteration % 3 == 0 and len(removed) <= 20:
            new_crews = regret_repair(removed, partial_crews, K)
        else:
            new_crews = greedy_repair(removed, partial_crews, K)

        if new_crews is None:
            continue

        all_covered = set(t for crew in new_crews for t in crew)
        if len(all_covered) != N:
            missing = set(range(1, N + 1)) - all_covered
            new_crews = greedy_repair(list(missing), new_crews, K)
            if new_crews is None:
                continue
            if len(set(t for crew in new_crews for t in crew)) != N:
                continue

        if len(new_crews) > K:
            continue

        all_valid = all(check_crew(crew) for crew in new_crews)
        if not all_valid:
            continue

        new_cost = total_cost_fn(new_crews)
        delta = new_cost - current_cost
        accept = False
        if delta < 0:
            accept = True
        elif T > T_min * 10:
            prob = math.exp(-delta / T)
            accept = rng.random() < prob

        if accept:
            current_crews = new_crews
            current_cost = new_cost

            if new_cost < best_cost - 1e-9:
                candidate = {'crews': [list(c) for c in new_crews]}
                try:
                    feasible, _ = tools['is_feasible'](candidate)
                    if feasible:
                        obj = tools['objective'](candidate)
                        if obj < best_cost:
                            best_cost = obj
                            best_crews = [list(c) for c in new_crews]
                            op_success[op_idx] += 1
                            no_improve_streak = 0
                except Exception:
                    pass
            else:
                no_improve_streak += 1
        else:
            no_improve_streak += 1

        if no_improve_streak > 50 and remaining() > 2.0:
            current_crews = [list(c) for c in best_crews]
            current_cost = best_cost
            no_improve_streak = 0
            T = max(T, T_init * 0.1)

    result = {'crews': [list(c) for c in best_crews if c]}
    try:
        feasible, _ = tools['is_feasible'](result)
        if feasible:
            return result
    except Exception:
        pass
    return initial_sol


# ====================================================================== #
# B-style: Move-based LS + SA helpers
# ====================================================================== #

def _run_move_ls_sa(initial_sol, N, K, tasks, arcs, time_limit,
                    arc_set, task_start, task_finish,
                    tools, start_time, time_limit_s):

    def remaining():
        return time_limit_s - (time.time() - start_time)

    def crew_cost_fast(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            c = arcs.get((crew[idx], crew[idx + 1]))
            if c is None:
                return float('inf')
            cost += c
        return cost

    def check_crew_fast(crew):
        if not crew:
            return False
        if task_finish[crew[-1]] - task_start[crew[0]] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if task_finish[t1] > task_start[t2]:
                return False
            if (t1, t2) not in arc_set:
                return False
        return True

    def compute_crew_costs(crews):
        return [crew_cost_fast(c) for c in crews]

    def relocation_best_improvement(crews, crew_costs):
        best_gain = 1e-9
        best_move = None

        for ci in range(len(crews)):
            crew_i = crews[ci]
            if len(crew_i) <= 1:
                continue
            old_cost_i = crew_costs[ci]

            for ti in range(len(crew_i)):
                task = crew_i[ti]
                t_s = task_start[task]
                t_f = task_finish[task]

                new_crew_i = crew_i[:ti] + crew_i[ti + 1:]
                if not new_crew_i:
                    continue

                valid_removal = True
                if ti > 0 and ti < len(crew_i) - 1:
                    prev_t = crew_i[ti - 1]
                    next_t = crew_i[ti + 1]
                    if task_finish[prev_t] > task_start[next_t]:
                        valid_removal = False
                    elif (prev_t, next_t) not in arc_set:
                        valid_removal = False
                if valid_removal:
                    dt = task_finish[new_crew_i[-1]] - task_start[new_crew_i[0]]
                    if dt > time_limit:
                        valid_removal = False
                if not valid_removal:
                    continue

                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                for cj in range(len(crews)):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_costs[cj]

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None:
                            if task_finish[prev_j] > t_s:
                                continue
                            if (prev_j, task) not in arc_set:
                                continue
                        if next_j is not None:
                            if t_f > task_start[next_j]:
                                continue
                            if (task, next_j) not in arc_set:
                                continue

                        new_first = task_start[crew_j[0]] if pos > 0 else t_s
                        new_last = task_finish[crew_j[-1]] if pos < len(crew_j) else t_f
                        if new_last - new_first > time_limit:
                            continue

                        insert_cost = 0.0
                        if prev_j is not None:
                            insert_cost += arcs[(prev_j, task)]
                        if next_j is not None:
                            insert_cost += arcs[(task, next_j)]
                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        gain = saving_i - (insert_cost - bridge_cost)
                        if gain > best_gain:
                            best_gain = gain
                            best_move = (ci, ti, cj, pos)

        if best_move is None:
            return False, crews, crew_costs

        ci, ti, cj, pos = best_move
        task = crews[ci][ti]
        new_crew_i = crews[ci][:ti] + crews[ci][ti + 1:]
        new_crew_j = crews[cj][:pos] + [task] + crews[cj][pos:]
        crews[ci] = new_crew_i
        crews[cj] = new_crew_j
        crew_costs[ci] = crew_cost_fast(new_crew_i)
        crew_costs[cj] = crew_cost_fast(new_crew_j)
        return True, crews, crew_costs

    def swap_tasks(crews, crew_costs):
        best_gain = 1e-9
        best_move = None

        for ci in range(len(crews)):
            for cj in range(ci + 1, len(crews)):
                crew_i = crews[ci]
                crew_j = crews[cj]
                old_cost_ij = crew_costs[ci] + crew_costs[cj]

                for pi in range(len(crew_i)):
                    for pj in range(len(crew_j)):
                        task_i = crew_i[pi]
                        task_j = crew_j[pj]

                        ti_s = task_start[task_i]
                        ti_f = task_finish[task_i]
                        tj_s = task_start[task_j]
                        tj_f = task_finish[task_j]

                        ok_i = True
                        if pi > 0:
                            prev = crew_i[pi - 1]
                            if task_finish[prev] > tj_s or (prev, task_j) not in arc_set:
                                ok_i = False
                        if ok_i and pi < len(crew_i) - 1:
                            nxt = crew_i[pi + 1]
                            if tj_f > task_start[nxt] or (task_j, nxt) not in arc_set:
                                ok_i = False
                        if ok_i:
                            nf_i = crew_i[0] if pi > 0 else task_j
                            nl_i = crew_i[-1] if pi < len(crew_i) - 1 else task_j
                            if task_finish[nl_i] - task_start[nf_i] > time_limit:
                                ok_i = False
                        if not ok_i:
                            continue

                        ok_j = True
                        if pj > 0:
                            prev = crew_j[pj - 1]
                            if task_finish[prev] > ti_s or (prev, task_i) not in arc_set:
                                ok_j = False
                        if ok_j and pj < len(crew_j) - 1:
                            nxt = crew_j[pj + 1]
                            if ti_f > task_start[nxt] or (task_i, nxt) not in arc_set:
                                ok_j = False
                        if ok_j:
                            nf_j = crew_j[0] if pj > 0 else task_i
                            nl_j = crew_j[-1] if pj < len(crew_j) - 1 else task_i
                            if task_finish[nl_j] - task_start[nf_j] > time_limit:
                                ok_j = False
                        if not ok_j:
                            continue

                        new_ci = list(crew_i)
                        new_cj = list(crew_j)
                        new_ci[pi] = task_j
                        new_cj[pj] = task_i
                        new_cost = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                        gain = old_cost_ij - new_cost
                        if gain > best_gain:
                            best_gain = gain
                            best_move = (ci, pi, cj, pj)

        if best_move is None:
            return False, crews, crew_costs

        ci, pi, cj, pj = best_move
        task_i = crews[ci][pi]
        task_j = crews[cj][pj]
        new_ci = list(crews[ci])
        new_cj = list(crews[cj])
        new_ci[pi] = task_j
        new_cj[pj] = task_i
        crews[ci] = new_ci
        crews[cj] = new_cj
        crew_costs[ci] = crew_cost_fast(new_ci)
        crew_costs[cj] = crew_cost_fast(new_cj)
        return True, crews, crew_costs

    def oropt_move(crews, crew_costs, seg_len=2):
        best_gain = 1e-9
        best_move = None

        for ci in range(len(crews)):
            crew_i = crews[ci]
            if len(crew_i) <= seg_len:
                continue
            old_cost_i = crew_costs[ci]

            for ti in range(len(crew_i) - seg_len + 1):
                segment = crew_i[ti:ti + seg_len]
                seg_valid = all((segment[k], segment[k + 1]) in arc_set for k in range(seg_len - 1))
                if not seg_valid:
                    continue

                new_crew_i = crew_i[:ti] + crew_i[ti + seg_len:]
                if not new_crew_i:
                    continue

                if ti > 0 and ti + seg_len <= len(crew_i) - 1:
                    prev_t = crew_i[ti - 1]
                    next_t = crew_i[ti + seg_len]
                    if task_finish[prev_t] > task_start[next_t]:
                        continue
                    if (prev_t, next_t) not in arc_set:
                        continue

                dt_i = task_finish[new_crew_i[-1]] - task_start[new_crew_i[0]]
                if dt_i > time_limit:
                    continue

                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i
                seg_s = task_start[segment[0]]
                seg_f = task_finish[segment[-1]]
                seg_internal = crew_cost_fast(segment)

                for cj in range(len(crews)):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_costs[cj]

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None and task_finish[prev_j] > seg_s:
                            continue
                        if next_j is not None and seg_f > task_start[next_j]:
                            continue

                        ok = True
                        extra_cost = seg_internal
                        if prev_j is not None:
                            c = arcs.get((prev_j, segment[0]))
                            if c is None:
                                ok = False
                            else:
                                extra_cost += c
                        if ok and next_j is not None:
                            c = arcs.get((segment[-1], next_j))
                            if c is None:
                                ok = False
                            else:
                                extra_cost += c
                        if not ok:
                            continue

                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        new_first_t = task_start[crew_j[0]] if pos > 0 else seg_s
                        new_last_t = task_finish[crew_j[-1]] if pos < len(crew_j) else seg_f
                        if new_last_t - new_first_t > time_limit:
                            continue

                        gain = saving_i - (extra_cost - bridge_cost)
                        if gain > best_gain:
                            best_gain = gain
                            best_move = (ci, ti, cj, pos, seg_len)

        if best_move is None:
            return False, crews, crew_costs

        ci, ti, cj, pos, sl = best_move
        segment = crews[ci][ti:ti + sl]
        new_crew_i = crews[ci][:ti] + crews[ci][ti + sl:]
        new_crew_j = crews[cj][:pos] + segment + crews[cj][pos:]
        crews[ci] = new_crew_i
        crews[cj] = new_crew_j
        crew_costs[ci] = crew_cost_fast(new_crew_i)
        crew_costs[cj] = crew_cost_fast(new_crew_j)
        return True, crews, crew_costs

    def intra_relocate(crews, crew_costs):
        improved = False
        for ci in range(len(crews)):
            crew = crews[ci]
            n = len(crew)
            if n < 3:
                continue
            old_cost = crew_costs[ci]
            best_gain = 1e-9
            best_move = None

            for ti in range(n):
                task = crew[ti]
                new_crew_base = crew[:ti] + crew[ti + 1:]

                if ti > 0 and ti < n - 1:
                    prev_t = crew[ti - 1]
                    next_t = crew[ti + 1]
                    if task_finish[prev_t] > task_start[next_t] or (prev_t, next_t) not in arc_set:
                        continue

                for pos in range(len(new_crew_base) + 1):
                    if pos == ti:
                        continue
                    prev_j = new_crew_base[pos - 1] if pos > 0 else None
                    next_j = new_crew_base[pos] if pos < len(new_crew_base) else None

                    if prev_j is not None:
                        if task_finish[prev_j] > task_start[task] or (prev_j, task) not in arc_set:
                            continue
                    if next_j is not None:
                        if task_finish[task] > task_start[next_j] or (task, next_j) not in arc_set:
                            continue

                    new_crew = new_crew_base[:pos] + [task] + new_crew_base[pos:]
                    dt = task_finish[new_crew[-1]] - task_start[new_crew[0]]
                    if dt > time_limit:
                        continue

                    new_cost = crew_cost_fast(new_crew)
                    gain = old_cost - new_cost
                    if gain > best_gain:
                        best_gain = gain
                        best_move = (ti, pos, new_crew, new_cost)

            if best_move is not None:
                _, _, new_crew, new_cost = best_move
                crews[ci] = new_crew
                crew_costs[ci] = new_cost
                improved = True

        return improved, crews, crew_costs

    def run_local_search(crews_in, time_budget):
        crews = [list(c) for c in crews_in]
        crew_costs = compute_crew_costs(crews)
        ls_start = time.time()

        def ls_rem():
            return time_budget - (time.time() - ls_start)

        improved_global = True
        while improved_global and ls_rem() > 0.05:
            improved_global = False

            if ls_rem() > 0.02:
                imp, crews, crew_costs = intra_relocate(crews, crew_costs)
                if imp:
                    improved_global = True

            while ls_rem() > 0.05:
                imp, crews, crew_costs = relocation_best_improvement(crews, crew_costs)
                if not imp:
                    break
                improved_global = True

            if ls_rem() < 0.05:
                break

            while ls_rem() > 0.05:
                imp, crews, crew_costs = swap_tasks(crews, crew_costs)
                if not imp:
                    break
                improved_global = True

            if ls_rem() < 0.05:
                break

            while ls_rem() > 0.05:
                imp, crews, crew_costs = oropt_move(crews, crew_costs, seg_len=2)
                if not imp:
                    break
                improved_global = True

            if ls_rem() < 0.05:
                break

            if N <= 300 and ls_rem() > 0.1:
                while ls_rem() > 0.05:
                    imp, crews, crew_costs = oropt_move(crews, crew_costs, seg_len=3)
                    if not imp:
                        break
                    improved_global = True

        return crews, sum(crew_costs)

    def simulated_annealing(crews_in, time_budget, initial_temp=None, cooling=0.997):
        crews = [list(c) for c in crews_in]
        crew_costs = compute_crew_costs(crews)
        current_cost = sum(crew_costs)
        sa_best_cost = current_cost
        sa_best_crews = [list(c) for c in crews]

        sa_start = time.time()
        rng = random.Random(123)

        def sa_rem():
            return time_budget - (time.time() - sa_start)

        if initial_temp is None:
            initial_temp = max(current_cost * 0.05, 1.0)

        temp = initial_temp
        n_iter = 0

        while sa_rem() > 0.05:
            n_iter += 1
            if n_iter % 1000 == 0:
                temp *= cooling

            move_type = rng.randint(0, 2)

            if move_type == 0:
                eligible = [i for i in range(len(crews)) if len(crews[i]) > 1]
                if not eligible:
                    continue
                ci = rng.choice(eligible)
                ti = rng.randint(0, len(crews[ci]) - 1)
                task = crews[ci][ti]
                t_s = task_start[task]
                t_f = task_finish[task]

                new_crew_i = crews[ci][:ti] + crews[ci][ti + 1:]
                if not new_crew_i:
                    continue

                bridge_ok = True
                if ti > 0 and ti < len(crews[ci]) - 1:
                    prev_t = crews[ci][ti - 1]
                    next_t = crews[ci][ti + 1]
                    if task_finish[prev_t] > task_start[next_t] or (prev_t, next_t) not in arc_set:
                        bridge_ok = False
                if not bridge_ok:
                    continue

                dt_i = task_finish[new_crew_i[-1]] - task_start[new_crew_i[0]]
                if dt_i > time_limit:
                    continue

                other_crews = [j for j in range(len(crews)) if j != ci]
                if not other_crews:
                    continue
                cj = rng.choice(other_crews)
                crew_j = crews[cj]
                pos = rng.randint(0, len(crew_j))

                prev_j = crew_j[pos - 1] if pos > 0 else None
                next_j = crew_j[pos] if pos < len(crew_j) else None

                if prev_j is not None:
                    if task_finish[prev_j] > t_s or (prev_j, task) not in arc_set:
                        continue
                if next_j is not None:
                    if t_f > task_start[next_j] or (task, next_j) not in arc_set:
                        continue

                new_first = task_start[crew_j[0]] if pos > 0 else t_s
                new_last = task_finish[crew_j[-1]] if pos < len(crew_j) else t_f
                if new_last - new_first > time_limit:
                    continue

                new_crew_j = crew_j[:pos] + [task] + crew_j[pos:]
                new_cost_i = crew_cost_fast(new_crew_i)
                new_cost_j = crew_cost_fast(new_crew_j)
                delta = (new_cost_i + new_cost_j) - (crew_costs[ci] + crew_costs[cj])

                if delta < 0 or rng.random() < math.exp(-delta / max(temp, 1e-10)):
                    crews[ci] = new_crew_i
                    crews[cj] = new_crew_j
                    crew_costs[ci] = new_cost_i
                    crew_costs[cj] = new_cost_j
                    current_cost += delta
                    if current_cost < sa_best_cost:
                        sa_best_cost = current_cost
                        sa_best_crews = [list(c) for c in crews]

            elif move_type == 1:
                if len(crews) < 2:
                    continue
                ci = rng.randint(0, len(crews) - 1)
                cj = rng.randint(0, len(crews) - 1)
                if ci == cj or not crews[ci] or not crews[cj]:
                    continue
                pi = rng.randint(0, len(crews[ci]) - 1)
                pj = rng.randint(0, len(crews[cj]) - 1)

                new_ci = list(crews[ci])
                new_cj = list(crews[cj])
                new_ci[pi] = crews[cj][pj]
                new_cj[pj] = crews[ci][pi]

                if not check_crew_fast(new_ci) or not check_crew_fast(new_cj):
                    continue

                new_cost_ci = crew_cost_fast(new_ci)
                new_cost_cj = crew_cost_fast(new_cj)
                delta = (new_cost_ci + new_cost_cj) - (crew_costs[ci] + crew_costs[cj])

                if delta < 0 or rng.random() < math.exp(-delta / max(temp, 1e-10)):
                    crews[ci] = new_ci
                    crews[cj] = new_cj
                    crew_costs[ci] = new_cost_ci
                    crew_costs[cj] = new_cost_cj
                    current_cost += delta
                    if current_cost < sa_best_cost:
                        sa_best_cost = current_cost
                        sa_best_crews = [list(c) for c in crews]

            else:
                eligible = [i for i in range(len(crews)) if len(crews[i]) >= 3]
                if not eligible:
                    continue
                ci = rng.choice(eligible)
                crew = crews[ci]
                n = len(crew)
                ti = rng.randint(0, n - 1)
                task = crew[ti]
                new_crew_base = crew[:ti] + crew[ti + 1:]

                if ti > 0 and ti < n - 1:
                    prev_t = crew[ti - 1]
                    next_t = crew[ti + 1]
                    if task_finish[prev_t] > task_start[next_t] or (prev_t, next_t) not in arc_set:
                        continue

                pos = rng.randint(0, len(new_crew_base))
                if pos == ti:
                    continue

                prev_j = new_crew_base[pos - 1] if pos > 0 else None
                next_j = new_crew_base[pos] if pos < len(new_crew_base) else None

                if prev_j is not None:
                    if task_finish[prev_j] > task_start[task] or (prev_j, task) not in arc_set:
                        continue
                if next_j is not None:
                    if task_finish[task] > task_start[next_j] or (task, next_j) not in arc_set:
                        continue

                new_crew = new_crew_base[:pos] + [task] + new_crew_base[pos:]
                dt = task_finish[new_crew[-1]] - task_start[new_crew[0]]
                if dt > time_limit:
                    continue

                new_cost = crew_cost_fast(new_crew)
                delta = new_cost - crew_costs[ci]

                if delta < 0 or rng.random() < math.exp(-delta / max(temp, 1e-10)):
                    crews[ci] = new_crew
                    crew_costs[ci] = new_cost
                    current_cost += delta
                    if current_cost < sa_best_cost:
                        sa_best_cost = current_cost
                        sa_best_crews = [list(c) for c in crews]

        return sa_best_crews, sa_best_cost

    # Main B-style optimization
    best_local_sol = initial_sol
    best_local_cost = float('inf')

    def update_local(sol):
        nonlocal best_local_sol, best_local_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_local_cost:
                best_local_cost = cost
                best_local_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    update_local(initial_sol)

    # Initial LS pass
    ls_budget = min(remaining() * 0.40, 30.0)
    if remaining() > 1.0:
        ls_crews, ls_cost = run_local_search(best_local_sol['crews'], ls_budget)
        update_local({'crews': ls_crews})

    # SA phase
    if remaining() > 2.0:
        sa_budget = min(remaining() * 0.50, 25.0)
        init_temp = max(best_local_cost * 0.03, 0.5)
        sa_crews, sa_cost = simulated_annealing(
            best_local_sol['crews'], sa_budget,
            initial_temp=init_temp, cooling=0.998
        )
        update_local({'crews': sa_crews})

        # Post-SA LS
        if remaining() > 1.5:
            ls_budget2 = min(remaining() * 0.55, 18.0)
            ls_crews2, _ = run_local_search(best_local_sol['crews'], ls_budget2)
            update_local({'crews': ls_crews2})

    # Final polish
    if remaining() > 1.0:
        polish_budget = remaining() * 0.85
        polished, _ = run_local_search(best_local_sol['crews'], polish_budget)
        update_local({'crews': polished})

    return best_local_sol

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # ------------------------------------------------------------------ #
    # Fast data structures
    # ------------------------------------------------------------------ #
    succ_list = defaultdict(list)
    pred_list = defaultdict(list)
    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ_list[i].append((tasks[j][0], j, cost))
            pred_list[j].append((tasks[i][1], i, cost))
    for t in range(1, N + 1):
        succ_list[t].sort()
        pred_list[t].sort()

    def check_crew_fast(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arcs:
                return False
        return True

    def crew_cost_fast(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def solution_cost_fast(crews):
        return sum(crew_cost_fast(c) for c in crews)

    # ------------------------------------------------------------------ #
    # Instance feature analysis for dispatch
    # ------------------------------------------------------------------ #
    arc_density = len(arcs) / max(N * N, 1)
    avg_successors = sum(len(succ_list[t]) for t in range(1, N + 1)) / max(N, 1)
    tasks_per_crew = N / max(K, 1)

    all_starts = [tasks[t][0] for t in range(1, N + 1)]
    all_finishes = [tasks[t][1] for t in range(1, N + 1)]
    total_span = max(all_finishes) - min(all_starts) if N > 0 else 1.0
    time_limit_ratio = time_limit / max(total_span, 1.0)

    is_tiny = N <= 40
    is_small = 40 < N <= 100
    is_medium = 100 < N <= 250
    is_large = N > 250

    is_sparse = avg_successors < 2.0
    is_dense = avg_successors >= 5.0
    is_tight_time = time_limit_ratio < 0.5

    use_ilp_first = is_tiny or (is_small and is_sparse and is_tight_time)
    use_mcf_first = is_large or (is_medium and not is_sparse) or (is_dense and not is_tiny)

    # ------------------------------------------------------------------ #
    # Solution tracking
    # ------------------------------------------------------------------ #
    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # ------------------------------------------------------------------ #
    # Custom greedy construction
    # ------------------------------------------------------------------ #
    def greedy_construct(shuffle_seed=None, prefer_low_cost=True):
        task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
        if shuffle_seed is not None:
            rng = random.Random(shuffle_seed)
            i = 0
            while i < len(task_order):
                j = i
                while j < len(task_order) and tasks[task_order[j]][0] == tasks[task_order[i]][0]:
                    j += 1
                seg = task_order[i:j]
                rng.shuffle(seg)
                task_order[i:j] = seg
                i = j

        crews_g = []
        crew_last = []
        crew_start = []
        crew_finish = []

        for task in task_order:
            t_start, t_finish = tasks[task]
            best_crew_idx = -1
            best_c = float('inf')

            for i in range(len(crews_g)):
                last = crew_last[i]
                if crew_finish[i] > t_start:
                    continue
                if (last, task) not in arcs:
                    continue
                if t_finish - crew_start[i] > time_limit:
                    continue
                c = arcs[(last, task)]
                if c < best_c:
                    best_c = c
                    best_crew_idx = i

            if best_crew_idx >= 0:
                crews_g[best_crew_idx].append(task)
                crew_last[best_crew_idx] = task
                crew_finish[best_crew_idx] = t_finish
            elif len(crews_g) < K:
                crews_g.append([task])
                crew_last.append(task)
                crew_start.append(t_start)
                crew_finish.append(t_finish)
            else:
                forced = False
                for i in range(len(crews_g)):
                    last = crew_last[i]
                    if crew_finish[i] <= t_start and (last, task) in arcs:
                        if t_finish - crew_start[i] <= time_limit:
                            crews_g[i].append(task)
                            crew_last[i] = task
                            crew_finish[i] = t_finish
                            forced = True
                            break
                if not forced:
                    return None

        if not crews_g:
            return None
        sol = {'crews': crews_g}
        try:
            feasible, _ = tools['is_feasible'](sol)
            return sol if feasible else None
        except Exception:
            return None

    # ------------------------------------------------------------------ #
    # Phase 1: Construction based on dispatch
    # ------------------------------------------------------------------ #

    if use_ilp_first:
        ilp_budget = min(remaining() * 0.45, 40.0)
        if remaining() > 3:
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

        if remaining() > 2:
            mcf_budget = min(remaining() * 0.35, 15.0)
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

    elif use_mcf_first:
        mcf_budget = min(remaining() * 0.30, 20.0)
        if remaining() > 2:
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

        if is_large and remaining() > 3 and best_sol is None:
            sd_budget = min(remaining() * 0.25, 20.0)
            try:
                sol = tools['solve_default'](time_limit_s=sd_budget)
                update_best(sol)
            except Exception:
                pass

    else:
        mcf_budget = min(remaining() * 0.28, 18.0)
        if remaining() > 2:
            try:
                sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
                update_best(sol)
            except Exception:
                pass

        if remaining() > 5:
            ilp_budget = min(remaining() * 0.25, 20.0)
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

    if remaining() > 1:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    if remaining() > 0.5:
        sol = greedy_construct()
        update_best(sol)

    for seed in range(10):
        if remaining() < 0.3:
            break
        sol = greedy_construct(shuffle_seed=seed)
        update_best(sol)

    if best_sol is None:
        if K >= N:
            sol = {'crews': [[i] for i in range(1, N + 1)]}
            update_best(sol)
        if best_sol is None:
            task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
            crews_em = [[] for _ in range(min(K, N))]
            for idx, task in enumerate(task_order):
                crews_em[idx % len(crews_em)].append(task)
            sol = {'crews': [c for c in crews_em if c]}
            update_best(sol)

    if best_sol is None:
        return {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}

    # ------------------------------------------------------------------ #
    # Local Search Neighborhoods
    # ------------------------------------------------------------------ #

    def relocation_pass(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            crew_i = crews[ci]
            if len(crew_i) <= 1:
                continue
            for ti in range(len(crew_i)):
                task = crew_i[ti]
                t_start_task, t_finish_task = tasks[task]

                new_crew_i = crew_i[:ti] + crew_i[ti + 1:]
                if not check_crew_fast(new_crew_i):
                    continue

                old_cost_i = crew_cost_fast(crew_i)
                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                best_gain = 1e-9
                best_cj = -1
                best_pos = -1

                for cj in range(n_crews):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_cost_fast(crew_j)

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None:
                            if tasks[prev_j][1] > t_start_task:
                                continue
                            if (prev_j, task) not in arcs:
                                continue
                        if next_j is not None:
                            if t_finish_task > tasks[next_j][0]:
                                continue
                            if (task, next_j) not in arcs:
                                continue

                        insert_cost = 0.0
                        if prev_j is not None:
                            insert_cost += arcs[(prev_j, task)]
                        if next_j is not None:
                            insert_cost += arcs[(task, next_j)]

                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        new_crew_j = crew_j[:pos] + [task] + crew_j[pos:]
                        duty = tasks[new_crew_j[-1]][1] - tasks[new_crew_j[0]][0]
                        if duty > time_limit:
                            continue

                        gain = saving_i - (insert_cost - bridge_cost)
                        if gain > best_gain:
                            best_gain = gain
                            best_cj = cj
                            best_pos = pos

                if best_cj >= 0:
                    old_cost_j = crew_cost_fast(crews[best_cj])
                    new_crew_j = crews[best_cj][:best_pos] + [task] + crews[best_cj][best_pos:]
                    new_cost_j = crew_cost_fast(new_crew_j)
                    cost = cost - old_cost_i - old_cost_j + new_cost_i + new_cost_j
                    crews[ci] = new_crew_i
                    crews[best_cj] = new_crew_j
                    return crews, cost, True

        return crews, cost, False

    def swap_pass(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            for cj in range(ci + 1, n_crews):
                crew_i = crews[ci]
                crew_j = crews[cj]
                old_cost_ij = crew_cost_fast(crew_i) + crew_cost_fast(crew_j)
                best_gain = 1e-9
                best_pi = -1
                best_pj = -1

                for pi in range(len(crew_i)):
                    for pj in range(len(crew_j)):
                        task_i = crew_i[pi]
                        task_j = crew_j[pj]

                        ti_start, ti_finish = tasks[task_i]
                        tj_start, tj_finish = tasks[task_j]

                        if pi > 0 and tasks[crew_i[pi - 1]][1] > tj_start:
                            continue
                        if pi < len(crew_i) - 1 and tj_finish > tasks[crew_i[pi + 1]][0]:
                            continue
                        if pj > 0 and tasks[crew_j[pj - 1]][1] > ti_start:
                            continue
                        if pj < len(crew_j) - 1 and ti_finish > tasks[crew_j[pj + 1]][0]:
                            continue

                        new_ci = list(crew_i)
                        new_cj = list(crew_j)
                        new_ci[pi] = task_j
                        new_cj[pj] = task_i

                        if not check_crew_fast(new_ci):
                            continue
                        if not check_crew_fast(new_cj):
                            continue

                        new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                        gain = old_cost_ij - new_cost_ij
                        if gain > best_gain:
                            best_gain = gain
                            best_pi = pi
                            best_pj = pj

                if best_pi >= 0:
                    task_i = crew_i[best_pi]
                    task_j = crew_j[best_pj]
                    new_ci = list(crew_i)
                    new_cj = list(crew_j)
                    new_ci[best_pi] = task_j
                    new_cj[best_pj] = task_i
                    new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                    cost = cost - old_cost_ij + new_cost_ij
                    crews[ci] = new_ci
                    crews[cj] = new_cj
                    return crews, cost, True

        return crews, cost, False

    def oropt_pass(crews, cost, seg_len=2):
        n_crews = len(crews)
        for ci in range(n_crews):
            crew_i = crews[ci]
            if len(crew_i) <= seg_len:
                continue
            for ti in range(len(crew_i) - seg_len + 1):
                segment = crew_i[ti:ti + seg_len]
                new_crew_i = crew_i[:ti] + crew_i[ti + seg_len:]
                if not new_crew_i:
                    continue
                if not check_crew_fast(new_crew_i):
                    continue

                seg_valid = True
                for k in range(seg_len - 1):
                    if (segment[k], segment[k + 1]) not in arcs:
                        seg_valid = False
                        break
                if not seg_valid:
                    continue

                old_cost_i = crew_cost_fast(crew_i)
                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                seg_start = tasks[segment[0]][0]
                seg_finish = tasks[segment[-1]][1]

                best_gain = 1e-9
                best_cj = -1
                best_pos = -1

                for cj in range(n_crews):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_cost_fast(crew_j)

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None and tasks[prev_j][1] > seg_start:
                            continue
                        if next_j is not None and seg_finish > tasks[next_j][0]:
                            continue

                        ok = True
                        insert_cost = crew_cost_fast(segment)
                        if prev_j is not None:
                            c = arcs.get((prev_j, segment[0]))
                            if c is None:
                                ok = False
                            else:
                                insert_cost += c
                        if ok and next_j is not None:
                            c = arcs.get((segment[-1], next_j))
                            if c is None:
                                ok = False
                            else:
                                insert_cost += c
                        if not ok:
                            continue

                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        new_crew_j = crew_j[:pos] + segment + crew_j[pos:]
                        duty = tasks[new_crew_j[-1]][1] - tasks[new_crew_j[0]][0]
                        if duty > time_limit:
                            continue

                        new_cost_j = crew_cost_fast(new_crew_j)
                        gain = saving_i - (new_cost_j - old_cost_j)
                        if gain > best_gain:
                            best_gain = gain
                            best_cj = cj
                            best_pos = pos

                if best_cj >= 0:
                    old_cost_j = crew_cost_fast(crews[best_cj])
                    new_crew_j = crews[best_cj][:best_pos] + segment + crews[best_cj][best_pos:]
                    new_cost_j = crew_cost_fast(new_crew_j)
                    cost = cost - old_cost_i - old_cost_j + new_cost_i + new_cost_j
                    crews[ci] = new_crew_i
                    crews[best_cj] = new_crew_j
                    return crews, cost, True

        return crews, cost, False

    def intra_2opt_pass(crews, cost):
        improved = False
        for ci in range(len(crews)):
            crew = crews[ci]
            n = len(crew)
            if n < 3:
                continue
            old_cost_c = crew_cost_fast(crew)
            best_gain = 1e-9
            best_ij = (-1, -1)
            for i in range(n - 1):
                for j in range(i + 2, n):
                    new_crew = crew[:i + 1] + crew[i + 1:j + 1][::-1] + crew[j + 1:]
                    if not check_crew_fast(new_crew):
                        continue
                    new_cost_c = crew_cost_fast(new_crew)
                    gain = old_cost_c - new_cost_c
                    if gain > best_gain:
                        best_gain = gain
                        best_ij = (i, j)
            if best_ij[0] >= 0:
                i, j = best_ij
                new_crew = crew[:i + 1] + crew[i + 1:j + 1][::-1] + crew[j + 1:]
                new_cost_c = crew_cost_fast(new_crew)
                cost = cost - old_cost_c + new_cost_c
                crews[ci] = new_crew
                improved = True
        return crews, cost, improved

    def merge_pass(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            for cj in range(n_crews):
                if ci == cj:
                    continue
                tail_i = crews[ci][-1]
                head_j = crews[cj][0]
                if tasks[tail_i][1] > tasks[head_j][0]:
                    continue
                if (tail_i, head_j) not in arcs:
                    continue
                merged = crews[ci] + crews[cj]
                if not check_crew_fast(merged):
                    continue
                old_cost_ij = crew_cost_fast(crews[ci]) + crew_cost_fast(crews[cj])
                new_cost_m = crew_cost_fast(merged)
                if new_cost_m < old_cost_ij - 1e-9:
                    new_crews = []
                    for k in range(n_crews):
                        if k == ci:
                            new_crews.append(merged)
                        elif k == cj:
                            pass
                        else:
                            new_crews.append(list(crews[k]))
                    cost = cost - old_cost_ij + new_cost_m
                    return new_crews, cost, True
        return crews, cost, False

    def cross_crew_2opt(crews, cost):
        n_crews = len(crews)
        for ci in range(n_crews):
            for cj in range(ci + 1, n_crews):
                crew_i = crews[ci]
                crew_j = crews[cj]
                old_cost_ij = crew_cost_fast(crew_i) + crew_cost_fast(crew_j)
                best_gain = 1e-9
                best_p = -1
                best_q = -1

                for p in range(len(crew_i)):
                    for q in range(len(crew_j)):
                        new_ci = crew_i[:p + 1] + crew_j[q + 1:]
                        new_cj = crew_j[:q + 1] + crew_i[p + 1:]

                        if not new_ci or not new_cj:
                            continue
                        if not check_crew_fast(new_ci):
                            continue
                        if not check_crew_fast(new_cj):
                            continue

                        new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                        gain = old_cost_ij - new_cost_ij
                        if gain > best_gain:
                            best_gain = gain
                            best_p = p
                            best_q = q

                if best_p >= 0:
                    new_ci = crew_i[:best_p + 1] + crew_j[best_q + 1:]
                    new_cj = crew_j[:best_q + 1] + crew_i[best_p + 1:]
                    new_cost_ij = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                    cost = cost - old_cost_ij + new_cost_ij
                    crews[ci] = new_ci
                    crews[cj] = new_cj
                    return crews, cost, True

        return crews, cost, False

    def run_local_search(crews_in, time_budget):
        crews = [list(c) for c in crews_in]
        cost = solution_cost_fast(crews)
        ls_start = time.time()

        def ls_remaining():
            return time_budget - (time.time() - ls_start)

        avg_crew_sz = N / max(len(crews), 1)
        use_2opt = avg_crew_sz <= 30
        use_cross = avg_crew_sz <= 20

        improved_global = True
        while improved_global and ls_remaining() > 0.05:
            improved_global = False

            while ls_remaining() > 0.05:
                crews, cost, imp = relocation_pass(crews, cost)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            while ls_remaining() > 0.05:
                crews, cost, imp = swap_pass(crews, cost)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            while ls_remaining() > 0.05:
                crews, cost, imp = oropt_pass(crews, cost, seg_len=2)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            while ls_remaining() > 0.05:
                crews, cost, imp = oropt_pass(crews, cost, seg_len=3)
                if not imp:
                    break
                improved_global = True

            if ls_remaining() < 0.05:
                break

            if use_cross:
                while ls_remaining() > 0.05:
                    crews, cost, imp = cross_crew_2opt(crews, cost)
                    if not imp:
                        break
                    improved_global = True

            if ls_remaining() < 0.05:
                break

            if use_2opt:
                while ls_remaining() > 0.05:
                    crews, cost, imp = intra_2opt_pass(crews, cost)
                    if not imp:
                        break
                    improved_global = True

            if ls_remaining() < 0.05:
                break

            while ls_remaining() > 0.05:
                crews, cost, imp = merge_pass(crews, cost)
                if not imp:
                    break
                improved_global = True

        return crews, cost

    def perturbation(crews_in, rng, n_moves=3):
        crews = [list(c) for c in crews_in]
        for _ in range(n_moves):
            if not crews:
                break
            eligible = [i for i in range(len(crews)) if len(crews[i]) > 1]
            if not eligible:
                break
            ci = rng.choice(eligible)
            crew_i = crews[ci]
            ti = rng.randint(0, len(crew_i) - 1)
            task = crew_i[ti]
            new_crew_i = crew_i[:ti] + crew_i[ti + 1:]
            if not check_crew_fast(new_crew_i):
                continue
            other_crews = [j for j in range(len(crews)) if j != ci]
            if not other_crews:
                continue
            rng.shuffle(other_crews)
            inserted = False
            for cj in other_crews:
                crew_j = crews[cj]
                positions = list(range(len(crew_j) + 1))
                rng.shuffle(positions)
                for pos in positions:
                    new_crew_j = crew_j[:pos] + [task] + crew_j[pos:]
                    if check_crew_fast(new_crew_j):
                        crews[ci] = new_crew_i
                        crews[cj] = new_crew_j
                        inserted = True
                        break
                if inserted:
                    break
            if not inserted and len(crews) < K:
                crews[ci] = new_crew_i
                crews.append([task])
        return [c for c in crews if c]

    def double_bridge_perturbation(crews_in, rng):
        crews = [list(c) for c in crews_in]
        eligible = [i for i in range(len(crews)) if len(crews[i]) >= 2]
        if len(eligible) < 2:
            return crews
        ci, cj = rng.sample(eligible, 2)
        crew_i = crews[ci]
        crew_j = crews[cj]
        pi = rng.randint(1, len(crew_i) - 1) if len(crew_i) > 1 else 1
        pj = rng.randint(1, len(crew_j) - 1) if len(crew_j) > 1 else 1
        new_ci = crew_i[:pi] + crew_j[pj:]
        new_cj = crew_j[:pj] + crew_i[pi:]
        if new_ci and new_cj and check_crew_fast(new_ci) and check_crew_fast(new_cj):
            crews[ci] = new_ci
            crews[cj] = new_cj
        return crews

    # ------------------------------------------------------------------ #
    # ILS Main Loop with SA-style acceptance
    # ------------------------------------------------------------------ #
    if best_sol is not None and remaining() > 1.0:
        rng = random.Random(42)

        if use_ilp_first:
            initial_ls_frac = 0.45
            max_initial_ls = 25.0
        elif is_large:
            initial_ls_frac = 0.38
            max_initial_ls = 25.0
        else:
            initial_ls_frac = 0.42
            max_initial_ls = 30.0

        initial_ls_budget = min(remaining() * initial_ls_frac, max_initial_ls)
        current_crews, current_cost = run_local_search(best_sol['crews'], initial_ls_budget)

        sol = {'crews': current_crews}
        update_best(sol)

        ils_crews = [list(c) for c in best_sol['crews']]
        ils_cost = best_cost

        no_improve_count = 0
        iteration = 0
        ilp_retry_done = False

        # ------------------------------------------------------------------ #
        # SA-style acceptance parameters
        # Compute initial temperature based on best_cost magnitude.
        # We want to accept solutions ~2% worse with ~50% probability initially,
        # cooling to near-zero acceptance of worse solutions by end of budget.
        # T0 such that exp(-delta/T0) = 0.5 where delta = 0.02 * best_cost
        # => T0 = 0.02 * best_cost / ln(2)
        # ------------------------------------------------------------------ #
        if best_cost > 0 and best_cost < float('inf'):
            T0 = max(0.02 * best_cost / math.log(2.0), 1e-6)
        else:
            T0 = 1.0

        # We'll cool T exponentially over the remaining ILS time
        # T(t) = T0 * alpha^iteration, targeting T_final ~ 1e-6 * T0
        # alpha chosen dynamically each iteration based on remaining time

        T = T0
        T_min = T0 * 1e-5

        while remaining() > 1.5:
            iteration += 1

            perturb_strength = 3 + no_improve_count // 3

            if iteration % 4 == 0 and not is_large:
                perturbed = double_bridge_perturbation(ils_crews, rng)
                perturbed = perturbation(perturbed, rng, n_moves=2)
            else:
                perturbed = perturbation(ils_crews, rng, n_moves=perturb_strength)

            if not perturbed:
                break

            all_t = set()
            for c in perturbed:
                all_t.update(c)
            if len(all_t) != N:
                ils_crews = [list(c) for c in best_sol['crews']]
                ils_cost = best_cost
                no_improve_count = 0
                continue

            if is_tiny:
                ls_time = min(remaining() * 0.50, 15.0)
            elif is_small:
                ls_time = min(remaining() * 0.45, 12.0)
            elif is_medium:
                ls_time = min(remaining() * 0.38, 9.0)
            else:
                ls_time = min(remaining() * 0.30, 6.0)

            new_crews, new_cost = run_local_search(perturbed, ls_time)
            sol = {'crews': new_crews}

            if update_best(sol):
                ils_crews = [list(c) for c in new_crews]
                ils_cost = new_cost
                no_improve_count = 0
                # Reheat slightly on improvement to escape local optima region
                T = min(T * 1.5, T0 * 0.5)
            else:
                no_improve_count += 1

                # SA-style acceptance: accept worse solutions probabilistically
                delta = new_cost - ils_cost
                if delta <= 0:
                    # Better than current (but not global best) - always accept
                    ils_crews = [list(c) for c in new_crews]
                    ils_cost = new_cost
                elif T > T_min:
                    # Accept worse solution with SA probability
                    accept_prob = math.exp(-delta / T)
                    if rng.random() < accept_prob:
                        ils_crews = [list(c) for c in new_crews]
                        ils_cost = new_cost
                    # else: reject, keep current ils_crews
                else:
                    # Temperature too low - only accept improvements
                    pass

                # Cool temperature
                # Use geometric cooling: target reaching T_min in ~20 more iterations
                cooling_rate = max(0.85, (T_min / max(T, T_min)) ** (1.0 / max(20, 1)))
                T = max(T * 0.90, T_min)

            # ILP retry if stuck and time allows
            if use_ilp_first and not ilp_retry_done and no_improve_count >= 5 and remaining() > 8.0:
                ilp_retry_budget = min(remaining() * 0.35, 15.0)
                try:
                    sol2 = tools['ilp_crew_scheduling'](time_limit_s=ilp_retry_budget)
                    if update_best(sol2):
                        ils_crews = [list(c) for c in best_sol['crews']]
                        ils_cost = best_cost
                        no_improve_count = 0
                        T = T0 * 0.3  # Partial reheat after ILP improvement
                except Exception:
                    pass
                ilp_retry_done = True

            # Restart from best if deeply stuck (temperature has cooled too much)
            if no_improve_count >= 8:
                ils_crews = [list(c) for c in best_sol['crews']]
                ils_cost = best_cost
                no_improve_count = 0
                # Reheat temperature for fresh exploration
                T = T0 * (0.3 + 0.7 * remaining() / time_limit_s)
                T = max(T, T_min * 10)

    return best_sol if best_sol is not None else {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    succ = defaultdict(list)
    pred = defaultdict(list)

    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ[i].append((tasks[j][0], j, cost))
            pred[j].append((tasks[i][1], i, cost))

    for t in range(1, N + 1):
        succ[t].sort()
        pred[t].sort()

    arc_set = set(arcs.keys())
    tasks_by_start = sorted(range(1, N + 1), key=lambda t: (tasks[t][0], tasks[t][1]))

    def check_crew(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arc_set:
                return False
        return True

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    if N <= 80:
        ilp_budget = min(remaining() * 0.45, time_limit_s * 0.45)
        if ilp_budget > 0.5:
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

    if best_sol is None and remaining() > 1.0:
        mcf_budget = min(remaining() * 0.40, 20.0)
        try:
            sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
            update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 1.0:
        init_budget = min(remaining() * 0.45, 30.0)
        try:
            sol = tools['solve_default'](time_limit_s=init_budget)
            update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 0.5:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 0.5:
        sol = _greedy_construct(N, K, tasks, arcs, time_limit, arc_set)
        update_best(sol)

    if best_sol is None:
        if K >= N:
            best_sol = {'crews': [[i] for i in range(1, N + 1)]}
        else:
            task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
            crews_e = [[] for _ in range(K)]
            for idx, t in enumerate(task_order):
                crews_e[idx % K].append(t)
            best_sol = {'crews': [c for c in crews_e if c]}
        best_cost = total_cost_fn(best_sol['crews'])

    if remaining() > 1.0:
        improved_sol = _lns_sa_improve(
            best_sol, N, K, tasks, arcs, time_limit,
            succ, pred, arc_set, tasks_by_start, tools,
            start_time, time_limit_s,
            check_crew, crew_cost_fn, total_cost_fn,
            best_cost
        )
        if improved_sol is not None:
            try:
                feasible, _ = tools['is_feasible'](improved_sol)
                if feasible:
                    cost = tools['objective'](improved_sol)
                    if cost < best_cost:
                        best_cost = cost
                        best_sol = improved_sol
            except Exception:
                pass

    return best_sol


def _greedy_construct(N, K, tasks, arcs, time_limit, arc_set):
    task_order = sorted(range(1, N + 1), key=lambda t: (tasks[t][0], tasks[t][1]))
    crews = []
    crew_last = []
    crew_start = []
    crew_finish = []

    for task in task_order:
        t_start, t_finish = tasks[task]
        best_crew = -1
        best_cost_val = float('inf')

        for i in range(len(crews)):
            last = crew_last[i]
            if crew_finish[i] > t_start:
                continue
            if (last, task) not in arc_set:
                continue
            if t_finish - crew_start[i] > time_limit:
                continue
            c = arcs[(last, task)]
            if c < best_cost_val:
                best_cost_val = c
                best_crew = i

        if best_crew >= 0:
            crews[best_crew].append(task)
            crew_last[best_crew] = task
            crew_finish[best_crew] = t_finish
        elif len(crews) < K:
            crews.append([task])
            crew_last.append(task)
            crew_start.append(t_start)
            crew_finish.append(t_finish)
        else:
            forced = False
            for i in range(len(crews)):
                last = crew_last[i]
                if crew_finish[i] <= t_start and (last, task) in arc_set:
                    if t_finish - crew_start[i] <= time_limit:
                        crews[i].append(task)
                        crew_last[i] = task
                        crew_finish[i] = t_finish
                        forced = True
                        break
            if not forced:
                return None

    return {'crews': crews}


def _greedy_construct_randomized(N, K, tasks, arcs, time_limit, arc_set, rng, alpha=0.3):
    """Randomized greedy construction using RCL (restricted candidate list)."""
    task_order = sorted(range(1, N + 1), key=lambda t: (tasks[t][0], tasks[t][1]))
    crews = []
    crew_last = []
    crew_start = []
    crew_finish = []

    for task in task_order:
        t_start, t_finish = tasks[task]
        candidates = []

        for i in range(len(crews)):
            last = crew_last[i]
            if crew_finish[i] > t_start:
                continue
            if (last, task) not in arc_set:
                continue
            if t_finish - crew_start[i] > time_limit:
                continue
            c = arcs[(last, task)]
            candidates.append((c, i))

        if candidates:
            candidates.sort()
            c_min = candidates[0][0]
            c_max = candidates[-1][0]
            threshold = c_min + alpha * (c_max - c_min)
            rcl = [i for c, i in candidates if c <= threshold + 1e-9]
            best_crew = rng.choice(rcl)
            crews[best_crew].append(task)
            crew_last[best_crew] = task
            crew_finish[best_crew] = t_finish
        elif len(crews) < K:
            crews.append([task])
            crew_last.append(task)
            crew_start.append(t_start)
            crew_finish.append(t_finish)
        else:
            forced = False
            for i in range(len(crews)):
                last = crew_last[i]
                if crew_finish[i] <= t_start and (last, task) in arc_set:
                    if t_finish - crew_start[i] <= time_limit:
                        crews[i].append(task)
                        crew_last[i] = task
                        crew_finish[i] = t_finish
                        forced = True
                        break
            if not forced:
                return None

    return {'crews': crews}


def _lns_sa_improve(initial_sol, N, K, tasks, arcs, time_limit,
                    succ, pred, arc_set, tasks_by_start, tools,
                    start_time, time_limit_s,
                    check_crew, crew_cost_fn, total_cost_fn,
                    initial_best_cost):

    def remaining():
        return time_limit_s - (time.time() - start_time)

    def greedy_repair(unassigned, current_crews, max_crews):
        if not unassigned:
            return current_crews
        crews = [list(c) for c in current_crews]
        task_order = sorted(unassigned, key=lambda t: tasks[t][0])

        for task in task_order:
            ts_t, tf_t = tasks[task]
            best_delta = float('inf')
            best_ci = -1
            best_pos = -1

            for ci, crew in enumerate(crews):
                n = len(crew)
                for pos in range(n + 1):
                    if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                        continue
                    if pos < n and tf_t > tasks[crew[pos]][0]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < n:
                        c = arcs.get((task, crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if 0 < pos < n:
                        bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                    head_start = tasks[crew[0]][0] if pos > 0 else ts_t
                    tail_finish = tasks[crew[-1]][1] if pos < n else tf_t
                    if tail_finish - head_start > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_delta:
                        best_delta = delta
                        best_ci = ci
                        best_pos = pos

            if best_ci >= 0:
                crews[best_ci] = crews[best_ci][:best_pos] + [task] + crews[best_ci][best_pos:]
            elif len(crews) < max_crews:
                crews.append([task])
            else:
                return None

        return crews

    def regret_repair(unassigned, current_crews, max_crews):
        if not unassigned:
            return current_crews
        crews = [list(c) for c in current_crews]
        remaining_tasks = list(unassigned)

        while remaining_tasks:
            regrets = []
            for task in remaining_tasks:
                ts_t, tf_t = tasks[task]
                insertions = []

                for ci, crew in enumerate(crews):
                    n = len(crew)
                    for pos in range(n + 1):
                        if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                            continue
                        if pos < n and tf_t > tasks[crew[pos]][0]:
                            continue

                        cost_add = 0.0
                        ok = True
                        if pos > 0:
                            c = arcs.get((crew[pos - 1], task))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if ok and pos < n:
                            c = arcs.get((task, crew[pos]))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if not ok:
                            continue

                        bridge = 0.0
                        if 0 < pos < n:
                            bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                        head_start = tasks[crew[0]][0] if pos > 0 else ts_t
                        tail_finish = tasks[crew[-1]][1] if pos < n else tf_t
                        if tail_finish - head_start > time_limit:
                            continue

                        delta = cost_add - bridge
                        insertions.append((delta, ci, pos))

                if len(crews) < max_crews:
                    insertions.append((0.0, -1, 0))

                if not insertions:
                    return None

                insertions.sort(key=lambda x: x[0])
                best_c = insertions[0][0]
                second_c = insertions[1][0] if len(insertions) > 1 else best_c + 1e9
                regret_val = second_c - best_c
                regrets.append((regret_val, task, insertions[0]))

            regrets.sort(key=lambda x: -x[0])
            _, task_to_insert, (delta, ci, pos) = regrets[0]

            if ci == -1:
                crews.append([task_to_insert])
            else:
                crews[ci] = crews[ci][:pos] + [task_to_insert] + crews[ci][pos:]
            remaining_tasks.remove(task_to_insert)

        return crews

    def destroy_random_tasks(crews, n_remove, rng):
        all_tasks = [(ci, t) for ci, crew in enumerate(crews) for t in crew]
        if not all_tasks:
            return crews, []
        n_remove = min(n_remove, len(all_tasks))
        removed_entries = rng.sample(all_tasks, n_remove)
        removed_set = set(t for _, t in removed_entries)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, list(removed_set)

    def destroy_worst_crew(crews, n_destroy, rng):
        if not crews:
            return crews, []
        sorted_crews = sorted(range(len(crews)), key=lambda i: crew_cost_fn(crews[i]), reverse=True)
        n_destroy = min(n_destroy, len(crews))
        destroyed = set(sorted_crews[:n_destroy])
        removed = []
        new_crews = []
        for ci, crew in enumerate(crews):
            if ci in destroyed:
                removed.extend(crew)
            else:
                new_crews.append(crew)
        return new_crews, removed

    def destroy_segment(crews, rng):
        if not crews:
            return crews, []
        crew_costs = [max(crew_cost_fn(crew), 0.01) for crew in crews]
        total_w = sum(crew_costs)
        r = rng.random() * total_w
        cumulative = 0.0
        ci = 0
        for i, c in enumerate(crew_costs):
            cumulative += c
            if r <= cumulative:
                ci = i
                break
        crew = crews[ci]
        if len(crew) <= 1:
            return crews, []
        seg_len = rng.randint(1, max(1, len(crew) // 2))
        start_pos = rng.randint(0, len(crew) - seg_len)
        removed = crew[start_pos:start_pos + seg_len]
        new_crew = crew[:start_pos] + crew[start_pos + seg_len:]
        new_crews = []
        for i, c in enumerate(crews):
            if i == ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)
        return new_crews, removed

    def destroy_related_tasks(crews, n_remove, rng):
        all_tasks_flat = [t for crew in crews for t in crew]
        if not all_tasks_flat:
            return crews, []
        seed_task = rng.choice(all_tasks_flat)
        removed_set = {seed_task}
        candidates = set()
        for _, j, _ in succ[seed_task]:
            candidates.add(j)
        for _, i, _ in pred[seed_task]:
            candidates.add(i)
        seed_start = tasks[seed_task][0]
        time_window = time_limit * 0.15
        for t in all_tasks_flat:
            if abs(tasks[t][0] - seed_start) < time_window:
                candidates.add(t)
        candidates -= removed_set
        candidates = sorted(candidates, key=lambda t: abs(tasks[t][0] - seed_start))
        n_remove = min(n_remove, len(all_tasks_flat))
        for t in candidates:
            if len(removed_set) >= n_remove:
                break
            removed_set.add(t)
        removed_tasks = list(removed_set)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, removed_tasks

    def destroy_chain_break(crews, rng):
        if not crews:
            return crews, []
        best_cost_arc = -1
        best_ci = -1
        best_pos = -1
        for ci, crew in enumerate(crews):
            for pos in range(len(crew) - 1):
                c = arcs.get((crew[pos], crew[pos + 1]), 0)
                if c > best_cost_arc:
                    best_cost_arc = c
                    best_ci = ci
                    best_pos = pos
        if best_ci < 0:
            return crews, []
        crew = crews[best_ci]
        window = rng.randint(1, max(1, len(crew) // 4))
        lo = max(0, best_pos - window + 1)
        hi = min(len(crew), best_pos + window + 1)
        removed = crew[lo:hi]
        new_crew = crew[:lo] + crew[hi:]
        new_crews = []
        for i, c in enumerate(crews):
            if i == best_ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)
        return new_crews, removed

    def or_opt_move(crews, seg_len, rng):
        best_delta = -1e-9
        best_move = None

        crew_indices = list(range(len(crews)))
        rng.shuffle(crew_indices)

        for src_ci in crew_indices[:min(len(crew_indices), 8)]:
            src_crew = crews[src_ci]
            if len(src_crew) <= seg_len:
                continue

            for src_pos in range(len(src_crew) - seg_len + 1):
                segment = src_crew[src_pos:src_pos + seg_len]
                seg_start = tasks[segment[0]][0]
                seg_finish = tasks[segment[-1]][1]

                removal_gain = 0.0
                if src_pos > 0:
                    removal_gain += arcs.get((src_crew[src_pos - 1], segment[0]), 0.0)
                if src_pos + seg_len < len(src_crew):
                    removal_gain += arcs.get((segment[-1], src_crew[src_pos + seg_len]), 0.0)
                bridge_cost = 0.0
                if src_pos > 0 and src_pos + seg_len < len(src_crew):
                    prev_t = src_crew[src_pos - 1]
                    next_t = src_crew[src_pos + seg_len]
                    if (prev_t, next_t) in arc_set:
                        bridge_cost = arcs[(prev_t, next_t)]
                    else:
                        continue

                new_src = src_crew[:src_pos] + src_crew[src_pos + seg_len:]
                if new_src and tasks[new_src[-1]][1] - tasks[new_src[0]][0] > time_limit:
                    continue

                for dst_ci in crew_indices:
                    if dst_ci == src_ci:
                        continue
                    dst_crew = crews[dst_ci]

                    for ins_pos in range(len(dst_crew) + 1):
                        if ins_pos > 0 and tasks[dst_crew[ins_pos - 1]][1] > seg_start:
                            continue
                        if ins_pos < len(dst_crew) and seg_finish > tasks[dst_crew[ins_pos]][0]:
                            continue

                        ins_cost = 0.0
                        ok = True
                        if ins_pos > 0:
                            c = arcs.get((dst_crew[ins_pos - 1], segment[0]))
                            if c is None:
                                ok = False
                            else:
                                ins_cost += c
                        if ok and ins_pos < len(dst_crew):
                            c = arcs.get((segment[-1], dst_crew[ins_pos]))
                            if c is None:
                                ok = False
                            else:
                                ins_cost += c
                        if not ok:
                            continue

                        dst_bridge = 0.0
                        if 0 < ins_pos < len(dst_crew):
                            dst_bridge = arcs.get((dst_crew[ins_pos - 1], dst_crew[ins_pos]), 0.0)

                        new_dst = dst_crew[:ins_pos] + segment + dst_crew[ins_pos:]
                        if tasks[new_dst[-1]][1] - tasks[new_dst[0]][0] > time_limit:
                            continue

                        delta = (bridge_cost + ins_cost - dst_bridge) - removal_gain
                        if delta < best_delta:
                            best_delta = delta
                            best_move = (src_ci, src_pos, seg_len, dst_ci, ins_pos,
                                         new_src, new_dst)

        if best_move is None:
            return crews, False

        src_ci, src_pos, seg_len_m, dst_ci, ins_pos, new_src, new_dst = best_move
        new_crews = []
        for i, c in enumerate(crews):
            if i == src_ci:
                if new_src:
                    new_crews.append(new_src)
            elif i == dst_ci:
                new_crews.append(new_dst)
            else:
                new_crews.append(c)
        return new_crews, True

    def relocate_pass(crews):
        """One pass of single-task relocation, best improvement."""
        improved = False

        task_to_crew = {}
        task_to_pos = {}
        for ci, crew in enumerate(crews):
            for pos, t in enumerate(crew):
                task_to_crew[t] = ci
                task_to_pos[t] = pos

        all_task_ids = list(range(1, N + 1))
        random.shuffle(all_task_ids)

        for task in all_task_ids:
            if remaining() < 0.3:
                break
            src_ci = task_to_crew[task]
            src_pos = task_to_pos[task]
            src_crew = crews[src_ci]

            if src_pos > 0 and src_pos < len(src_crew) - 1:
                prev_t = src_crew[src_pos - 1]
                next_t = src_crew[src_pos + 1]
                if (prev_t, next_t) not in arc_set:
                    continue
                if tasks[prev_t][1] > tasks[next_t][0]:
                    continue

            new_src = src_crew[:src_pos] + src_crew[src_pos + 1:]
            if new_src and tasks[new_src[-1]][1] - tasks[new_src[0]][0] > time_limit:
                continue

            removal_gain = 0.0
            if src_pos > 0:
                removal_gain += arcs.get((src_crew[src_pos - 1], task), 0.0)
            if src_pos < len(src_crew) - 1:
                removal_gain += arcs.get((task, src_crew[src_pos + 1]), 0.0)
            if src_pos > 0 and src_pos < len(src_crew) - 1:
                removal_gain -= arcs.get((src_crew[src_pos - 1], src_crew[src_pos + 1]), 0.0)

            ts_t, tf_t = tasks[task]
            best_ins_delta = float('inf')
            best_dst_ci = -1
            best_ins_pos = -1

            for dst_ci, dst_crew in enumerate(crews):
                if dst_ci == src_ci:
                    continue
                n = len(dst_crew)
                for pos in range(n + 1):
                    if pos > 0 and tasks[dst_crew[pos - 1]][1] > ts_t:
                        continue
                    if pos < n and tf_t > tasks[dst_crew[pos]][0]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((dst_crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < n:
                        c = arcs.get((task, dst_crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if 0 < pos < n:
                        bridge = arcs.get((dst_crew[pos - 1], dst_crew[pos]), 0.0)

                    head_start = tasks[dst_crew[0]][0] if pos > 0 else ts_t
                    tail_finish = tasks[dst_crew[-1]][1] if pos < n else tf_t
                    if tail_finish - head_start > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_ins_delta:
                        best_ins_delta = delta
                        best_dst_ci = dst_ci
                        best_ins_pos = pos

            if best_dst_ci < 0:
                continue

            total_delta = best_ins_delta - removal_gain
            if total_delta < -1e-9:
                dst_crew = crews[best_dst_ci]
                new_dst = dst_crew[:best_ins_pos] + [task] + dst_crew[best_ins_pos:]

                crews[src_ci] = new_src
                crews[best_dst_ci] = new_dst

                if new_src:
                    for p, t in enumerate(new_src):
                        task_to_crew[t] = src_ci
                        task_to_pos[t] = p
                task_to_crew[task] = best_dst_ci
                task_to_pos[task] = best_ins_pos
                for p, t in enumerate(new_dst):
                    task_to_crew[t] = best_dst_ci
                    task_to_pos[t] = p

                improved = True

        return crews, improved

    # Main LNS + SA loop
    current_crews = [list(c) for c in initial_sol['crews']]
    current_cost = total_cost_fn(current_crews)
    best_crews = [list(c) for c in current_crews]
    best_cost_lns = current_cost
    best_sol_lns = {'crews': [list(c) for c in current_crews]}

    rng = random.Random(42)

    if current_cost > 0 and current_cost < float('inf'):
        T_init = max(0.05 * current_cost / math.log(2), 1.0)
    else:
        T_init = 100.0
    T_min = 1e-4
    T = T_init

    ls_time = remaining() - 0.3
    if ls_time <= 0:
        return initial_sol

    estimated_iters = max(50, int(ls_time * 25))
    cooling_rate = (T_min / T_init) ** (1.0 / max(1, estimated_iters))

    n_destroy_base = max(1, N // 8)

    destroy_ops = ['random', 'worst_crew', 'segment', 'related', 'chain_break']
    op_success = [0] * len(destroy_ops)
    op_tries = [1] * len(destroy_ops)

    def select_op():
        total_tries = sum(op_tries)
        scores = []
        for i in range(len(destroy_ops)):
            exploit = op_success[i] / op_tries[i]
            explore = math.sqrt(2 * math.log(total_tries) / op_tries[i])
            scores.append(exploit + 0.3 * explore)
        return scores.index(max(scores))

    no_improve_streak = 0
    iteration = 0
    last_ls_iter = 0
    restart_count = 0

    while remaining() > 0.3:
        iteration += 1
        T = max(T * cooling_rate, T_min)

        n_destroy = n_destroy_base + min(no_improve_streak // 8, N // 4)
        n_destroy = max(1, min(n_destroy, N // 2))

        op_idx = select_op()
        op_tries[op_idx] += 1
        destroy_op = destroy_ops[op_idx]

        if destroy_op == 'random':
            partial_crews, removed = destroy_random_tasks(current_crews, n_destroy, rng)
        elif destroy_op == 'worst_crew':
            n_cd = max(1, min(3, len(current_crews) // 3))
            partial_crews, removed = destroy_worst_crew(current_crews, n_cd, rng)
        elif destroy_op == 'segment':
            partial_crews, removed = destroy_segment(current_crews, rng)
        elif destroy_op == 'related':
            partial_crews, removed = destroy_related_tasks(current_crews, n_destroy, rng)
        else:
            partial_crews, removed = destroy_chain_break(current_crews, rng)

        if not removed:
            continue

        use_regret = (iteration % 4 == 0) and (len(removed) <= 25)
        if use_regret:
            new_crews = regret_repair(removed, partial_crews, K)
        else:
            new_crews = greedy_repair(removed, partial_crews, K)

        if new_crews is None:
            continue

        all_covered = set(t for crew in new_crews for t in crew)
        if len(all_covered) != N:
            missing = set(range(1, N + 1)) - all_covered
            new_crews = greedy_repair(list(missing), new_crews, K)
            if new_crews is None:
                continue
            if len(set(t for crew in new_crews for t in crew)) != N:
                continue

        if len(new_crews) > K:
            continue

        if not all(check_crew(crew) for crew in new_crews):
            continue

        new_cost = total_cost_fn(new_crews)

        delta = new_cost - current_cost
        accept = False
        if delta < 0:
            accept = True
        elif T > T_min * 10 and delta < float('inf'):
            prob = math.exp(-delta / T)
            accept = rng.random() < prob

        if accept:
            current_crews = new_crews
            current_cost = new_cost

            if new_cost < best_cost_lns - 1e-9:
                candidate = {'crews': [list(c) for c in new_crews]}
                try:
                    feasible, _ = tools['is_feasible'](candidate)
                    if feasible:
                        obj = tools['objective'](candidate)
                        if obj < best_cost_lns:
                            best_cost_lns = obj
                            best_crews = [list(c) for c in new_crews]
                            best_sol_lns = candidate
                            op_success[op_idx] += 1
                            no_improve_streak = 0
                except Exception:
                    pass
            else:
                no_improve_streak += 1
        else:
            no_improve_streak += 1

        if iteration % 20 == 0 and remaining() > 1.0:
            seg_len = rng.choice([1, 2, 3])
            new_crews_opt, improved_opt = or_opt_move(current_crews, seg_len, rng)
            if improved_opt and len(new_crews_opt) <= K:
                if all(check_crew(c) for c in new_crews_opt):
                    new_cost_opt = total_cost_fn(new_crews_opt)
                    if new_cost_opt < current_cost:
                        current_crews = new_crews_opt
                        current_cost = new_cost_opt
                        if new_cost_opt < best_cost_lns - 1e-9:
                            candidate = {'crews': [list(c) for c in new_crews_opt]}
                            try:
                                feasible, _ = tools['is_feasible'](candidate)
                                if feasible:
                                    obj = tools['objective'](candidate)
                                    if obj < best_cost_lns:
                                        best_cost_lns = obj
                                        best_crews = [list(c) for c in new_crews_opt]
                                        best_sol_lns = candidate
                                        no_improve_streak = 0
                            except Exception:
                                pass

        if iteration - last_ls_iter >= 30 and remaining() > 1.5 and no_improve_streak > 15:
            ls_crews, ls_improved = relocate_pass([list(c) for c in current_crews])
            if ls_improved:
                current_crews = ls_crews
                current_cost = total_cost_fn(current_crews)
                if current_cost < best_cost_lns - 1e-9:
                    candidate = {'crews': [list(c) for c in current_crews if c]}
                    try:
                        feasible, _ = tools['is_feasible'](candidate)
                        if feasible:
                            obj = tools['objective'](candidate)
                            if obj < best_cost_lns:
                                best_cost_lns = obj
                                best_crews = [list(c) for c in current_crews if c]
                                best_sol_lns = candidate
                                no_improve_streak = 0
                    except Exception:
                        pass
            last_ls_iter = iteration

        # MODIFIED RESTART STRATEGY: diversify with randomized construction
        # instead of always returning to best known solution
        if no_improve_streak > 60 and remaining() > 2.0:
            restart_count += 1
            # Every 3rd restart, try a randomized greedy construction for diversification
            # Other restarts return to best known (exploitation)
            if restart_count % 3 == 0 and remaining() > 3.0:
                # Try randomized greedy construction with varying alpha for diversification
                alpha = rng.uniform(0.1, 0.5)
                try:
                    rand_sol = _greedy_construct_randomized(
                        N, K, tasks, arcs, time_limit, arc_set, rng, alpha=alpha
                    )
                    if rand_sol is not None:
                        rand_crews = rand_sol['crews']
                        if (len(rand_crews) <= K and
                                all(check_crew(c) for c in rand_crews) and
                                len(set(t for c in rand_crews for t in c)) == N):
                            rand_cost = total_cost_fn(rand_crews)
                            # Accept the random solution as new current if it's not
                            # catastrophically worse than best (within 50% overhead)
                            if rand_cost < best_cost_lns * 1.5:
                                current_crews = rand_crews
                                current_cost = rand_cost
                                # Also update best if better
                                if rand_cost < best_cost_lns - 1e-9:
                                    candidate = {'crews': [list(c) for c in rand_crews]}
                                    try:
                                        feasible, _ = tools['is_feasible'](candidate)
                                        if feasible:
                                            obj = tools['objective'](candidate)
                                            if obj < best_cost_lns:
                                                best_cost_lns = obj
                                                best_crews = [list(c) for c in rand_crews]
                                                best_sol_lns = candidate
                                    except Exception:
                                        pass
                            else:
                                # Fall back to best known
                                current_crews = [list(c) for c in best_crews]
                                current_cost = best_cost_lns
                        else:
                            current_crews = [list(c) for c in best_crews]
                            current_cost = best_cost_lns
                    else:
                        current_crews = [list(c) for c in best_crews]
                        current_cost = best_cost_lns
                except Exception:
                    current_crews = [list(c) for c in best_crews]
                    current_cost = best_cost_lns
            else:
                # Standard restart: return to best known solution
                current_crews = [list(c) for c in best_crews]
                current_cost = best_cost_lns

            no_improve_streak = 0
            # Reheat temperature more aggressively on diversification restarts
            if restart_count % 3 == 0:
                T = max(T, T_init * 0.25)
            else:
                T = max(T, T_init * 0.15)

    result = {'crews': [list(c) for c in best_crews if c]}
    try:
        feasible, _ = tools['is_feasible'](result)
        if feasible:
            return result
    except Exception:
        pass

    return best_sol_lns

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # Precompute adjacency
    succ = defaultdict(list)
    pred = defaultdict(list)
    for (i, j), cost in arcs.items():
        if tasks[i][1] <= tasks[j][0]:
            succ[i].append(j)
            pred[j].append(i)

    arc_set = set(arcs.keys())

    # ------------------------------------------------------------------ #
    # Helper functions
    # ------------------------------------------------------------------ #
    def crew_valid(crew):
        if not crew:
            return False
        if tasks[crew[-1]][1] - tasks[crew[0]][0] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if tasks[t1][1] > tasks[t2][0]:
                return False
            if (t1, t2) not in arc_set:
                return False
        return True

    def crew_cost_fn(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            key = (crew[idx], crew[idx + 1])
            if key not in arcs:
                return float('inf')
            cost += arcs[key]
        return cost

    def total_cost_fn(crews_list):
        return sum(crew_cost_fn(c) for c in crews_list)

    def make_sol_dict(crews):
        return {'crews': [list(c) for c in crews if c]}

    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # ------------------------------------------------------------------ #
    # Dispatch: ILP for small N, flow/greedy+LNS for larger
    # ------------------------------------------------------------------ #
    arc_count = len(arcs)
    max_arcs = N * (N - 1)
    arc_density = arc_count / max_arcs if max_arcs > 0 else 0.0
    crew_slack = K / N if N > 0 else 1.0

    use_ilp = (N <= 70) or (arc_density < 0.04) or (crew_slack >= 0.8)

    # ------------------------------------------------------------------ #
    # Phase 1: Initial solution
    # ------------------------------------------------------------------ #
    if use_ilp:
        ilp_budget = min(remaining() * 0.50, time_limit_s * 0.50)
        if ilp_budget > 0.5:
            try:
                sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
                update_best(sol)
            except Exception:
                pass

    # Try min cost flow
    if (best_sol is None or not use_ilp) and remaining() > 1.0:
        mcf_budget = min(remaining() * 0.35, 20.0)
        try:
            sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
            update_best(sol)
        except Exception:
            pass

    # Try solve_default
    if best_sol is None and remaining() > 1.0:
        init_budget = min(remaining() * 0.40, 30.0)
        try:
            sol = tools['solve_default'](time_limit_s=init_budget)
            update_best(sol)
        except Exception:
            pass

    # Greedy chain pack
    if best_sol is None and remaining() > 0.5:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    # Custom greedy construction
    if best_sol is None and remaining() > 0.5:
        sol = _greedy_construct(N, K, tasks, arcs, arc_set, time_limit)
        update_best(sol)

    # Emergency fallback
    if best_sol is None:
        if K >= N:
            best_sol = {'crews': [[i] for i in range(1, N + 1)]}
            best_cost = 0.0
        else:
            task_order = sorted(range(1, N + 1), key=lambda t: tasks[t][0])
            crews_e = [[] for _ in range(K)]
            for idx, t in enumerate(task_order):
                crews_e[idx % K].append(t)
            best_sol = {'crews': [c for c in crews_e if c]}
            best_cost = float('inf')

    # ------------------------------------------------------------------ #
    # Phase 2: Local search improvement
    # ------------------------------------------------------------------ #
    if remaining() > 1.0:
        best_sol = _improve(
            best_sol, N, K, tasks, arcs, arc_set, time_limit,
            succ, pred, tools, start_time, time_limit_s,
            crew_valid, crew_cost_fn, total_cost_fn, make_sol_dict
        )

    return best_sol


def _greedy_construct(N, K, tasks, arcs, arc_set, time_limit):
    """Greedy construction: process tasks by start time, assign to best crew."""
    task_order = sorted(range(1, N + 1), key=lambda t: (tasks[t][0], tasks[t][1]))
    crews = []
    crew_last = []
    crew_start = []
    crew_finish = []

    for task in task_order:
        t_start, t_finish = tasks[task]
        best_crew_idx = -1
        best_cost_val = float('inf')

        for i in range(len(crews)):
            last = crew_last[i]
            if crew_finish[i] > t_start:
                continue
            if (last, task) not in arc_set:
                continue
            if t_finish - crew_start[i] > time_limit:
                continue
            c = arcs[(last, task)]
            if c < best_cost_val:
                best_cost_val = c
                best_crew_idx = i

        if best_crew_idx >= 0:
            crews[best_crew_idx].append(task)
            crew_last[best_crew_idx] = task
            crew_finish[best_crew_idx] = t_finish
        elif len(crews) < K:
            crews.append([task])
            crew_last.append(task)
            crew_start.append(t_start)
            crew_finish.append(t_finish)
        else:
            # Force assign: find any valid crew
            forced = False
            for i in range(len(crews)):
                last = crew_last[i]
                if crew_finish[i] <= t_start and (last, task) in arc_set:
                    if t_finish - crew_start[i] <= time_limit:
                        crews[i].append(task)
                        crew_last[i] = task
                        crew_finish[i] = t_finish
                        forced = True
                        break
            if not forced:
                return None

    return {'crews': crews}


def _improve(initial_sol, N, K, tasks, arcs, arc_set, time_limit,
             succ, pred, tools, start_time, time_limit_s,
             crew_valid, crew_cost_fn, total_cost_fn, make_sol_dict):
    """Combined LNS + SA + local search improvement."""

    def remaining():
        return time_limit_s - (time.time() - start_time)

    # ------------------------------------------------------------------ #
    # Repair operators
    # ------------------------------------------------------------------ #
    def greedy_repair(unassigned, current_crews, max_crews):
        if not unassigned:
            return current_crews
        crews = [list(c) for c in current_crews]
        task_order = sorted(unassigned, key=lambda t: tasks[t][0])

        for task in task_order:
            ts_t, tf_t = tasks[task]
            best_delta = float('inf')
            best_ci = -1
            best_pos = -1

            for ci, crew in enumerate(crews):
                n = len(crew)
                # Try appending at end first (most common case)
                positions = list(range(n + 1))
                for pos in positions:
                    if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                        continue
                    if pos < n and tf_t > tasks[crew[pos]][0]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < n:
                        c = arcs.get((task, crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if 0 < pos < n:
                        bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                    # Duty time check
                    head_start = tasks[crew[0]][0] if pos > 0 else ts_t
                    tail_finish = tasks[crew[-1]][1] if pos < n else tf_t
                    if tail_finish - head_start > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_delta:
                        best_delta = delta
                        best_ci = ci
                        best_pos = pos

            if best_ci >= 0:
                crews[best_ci] = crews[best_ci][:best_pos] + [task] + crews[best_ci][best_pos:]
            elif len(crews) < max_crews:
                crews.append([task])
            else:
                return None

        return crews

    def regret2_repair(unassigned, current_crews, max_crews):
        """Regret-2 repair: insert task with highest regret first."""
        if not unassigned:
            return current_crews
        crews = [list(c) for c in current_crews]
        remaining_tasks = list(unassigned)

        while remaining_tasks:
            regrets = []
            for task in remaining_tasks:
                ts_t, tf_t = tasks[task]
                insertions = []

                for ci, crew in enumerate(crews):
                    n = len(crew)
                    for pos in range(n + 1):
                        if pos > 0 and tasks[crew[pos - 1]][1] > ts_t:
                            continue
                        if pos < n and tf_t > tasks[crew[pos]][0]:
                            continue

                        cost_add = 0.0
                        ok = True
                        if pos > 0:
                            c = arcs.get((crew[pos - 1], task))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if ok and pos < n:
                            c = arcs.get((task, crew[pos]))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if not ok:
                            continue

                        bridge = 0.0
                        if 0 < pos < n:
                            bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                        head_start = tasks[crew[0]][0] if pos > 0 else ts_t
                        tail_finish = tasks[crew[-1]][1] if pos < n else tf_t
                        if tail_finish - head_start > time_limit:
                            continue

                        delta = cost_add - bridge
                        insertions.append((delta, ci, pos))

                if len(crews) < max_crews:
                    insertions.append((0.0, -1, 0))

                if not insertions:
                    return None

                insertions.sort(key=lambda x: x[0])
                best_c = insertions[0][0]
                second_c = insertions[1][0] if len(insertions) > 1 else best_c + 1e9
                regret_val = second_c - best_c
                regrets.append((regret_val, task, insertions[0]))

            regrets.sort(key=lambda x: -x[0])
            _, task_to_insert, (delta, ci, pos) = regrets[0]

            if ci == -1:
                crews.append([task_to_insert])
            else:
                crews[ci] = crews[ci][:pos] + [task_to_insert] + crews[ci][pos:]
            remaining_tasks.remove(task_to_insert)

        return crews

    # ------------------------------------------------------------------ #
    # Destroy operators
    # ------------------------------------------------------------------ #
    def destroy_random(crews, n_remove, rng):
        all_tasks = [(ci, t) for ci, crew in enumerate(crews) for t in crew]
        if not all_tasks:
            return crews, []
        n_remove = min(n_remove, len(all_tasks))
        removed_entries = rng.sample(all_tasks, n_remove)
        removed_set = set(t for _, t in removed_entries)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, list(removed_set)

    def destroy_worst_crew(crews, n_destroy, rng):
        if not crews:
            return crews, []
        sorted_crews = sorted(range(len(crews)), key=lambda i: crew_cost_fn(crews[i]), reverse=True)
        n_destroy = min(n_destroy, len(crews))
        destroyed = set(sorted_crews[:n_destroy])
        removed = []
        new_crews = []
        for ci, crew in enumerate(crews):
            if ci in destroyed:
                removed.extend(crew)
            else:
                new_crews.append(crew)
        return new_crews, removed

    def destroy_segment(crews, rng):
        if not crews:
            return crews, []
        # Weighted by cost
        crew_costs = [max(crew_cost_fn(crew), 0.01) for crew in crews]
        total_w = sum(crew_costs)
        r = rng.random() * total_w
        cumulative = 0.0
        ci = 0
        for i, c in enumerate(crew_costs):
            cumulative += c
            if r <= cumulative:
                ci = i
                break
        crew = crews[ci]
        if len(crew) <= 1:
            return crews, []
        seg_len = rng.randint(1, max(1, len(crew) // 2))
        start_pos = rng.randint(0, len(crew) - seg_len)
        removed = crew[start_pos:start_pos + seg_len]
        new_crew = crew[:start_pos] + crew[start_pos + seg_len:]
        new_crews = []
        for i, c in enumerate(crews):
            if i == ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)
        return new_crews, removed

    def destroy_related(crews, n_remove, rng):
        all_tasks_flat = [t for crew in crews for t in crew]
        if not all_tasks_flat:
            return crews, []
        seed_task = rng.choice(all_tasks_flat)
        removed_set = {seed_task}
        candidates = set()
        for j in succ[seed_task]:
            candidates.add(j)
        for i in pred[seed_task]:
            candidates.add(i)
        seed_start = tasks[seed_task][0]
        time_window = time_limit * 0.15
        for t in all_tasks_flat:
            if abs(tasks[t][0] - seed_start) < time_window:
                candidates.add(t)
        candidates -= removed_set
        candidates = sorted(candidates, key=lambda t: abs(tasks[t][0] - seed_start))
        n_remove = min(n_remove, len(all_tasks_flat))
        for t in candidates:
            if len(removed_set) >= n_remove:
                break
            removed_set.add(t)
        removed_tasks = list(removed_set)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, removed_tasks

    def destroy_expensive_arcs(crews, n_remove, rng):
        """Remove tasks adjacent to expensive arcs."""
        arc_costs_list = []
        for ci, crew in enumerate(crews):
            for pos in range(len(crew) - 1):
                c = arcs.get((crew[pos], crew[pos + 1]), 0)
                arc_costs_list.append((c, ci, pos))
        if not arc_costs_list:
            return crews, []
        arc_costs_list.sort(reverse=True)
        removed_set = set()
        for c, ci, pos in arc_costs_list[:max(1, n_remove // 2)]:
            removed_set.add(crews[ci][pos])
            removed_set.add(crews[ci][pos + 1])
            if len(removed_set) >= n_remove:
                break
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, list(removed_set)

    # ------------------------------------------------------------------ #
    # Local search: single-task relocation (best improvement)
    # ------------------------------------------------------------------ #
    def relocate_pass(crews, rng):
        """One pass of single-task relocation."""
        improved = False

        task_to_crew = {}
        task_to_pos = {}
        for ci, crew in enumerate(crews):
            for pos, t in enumerate(crew):
                task_to_crew[t] = ci
                task_to_pos[t] = pos

        all_task_ids = list(range(1, N + 1))
        rng.shuffle(all_task_ids)

        for task in all_task_ids:
            if remaining() < 0.5:
                break
            src_ci = task_to_crew[task]
            src_pos = task_to_pos[task]
            src_crew = crews[src_ci]

            # Check if removing task is valid (bridge check)
            if src_pos > 0 and src_pos < len(src_crew) - 1:
                prev_t = src_crew[src_pos - 1]
                next_t = src_crew[src_pos + 1]
                if (prev_t, next_t) not in arc_set:
                    continue
                if tasks[prev_t][1] > tasks[next_t][0]:
                    continue

            new_src = src_crew[:src_pos] + src_crew[src_pos + 1:]
            if new_src and tasks[new_src[-1]][1] - tasks[new_src[0]][0] > time_limit:
                continue

            # Cost change from removal
            removal_gain = 0.0
            if src_pos > 0:
                removal_gain += arcs.get((src_crew[src_pos - 1], task), 0.0)
            if src_pos < len(src_crew) - 1:
                removal_gain += arcs.get((task, src_crew[src_pos + 1]), 0.0)
            if src_pos > 0 and src_pos < len(src_crew) - 1:
                removal_gain -= arcs.get((src_crew[src_pos - 1], src_crew[src_pos + 1]), 0.0)

            ts_t, tf_t = tasks[task]
            best_ins_delta = float('inf')
            best_dst_ci = -1
            best_ins_pos = -1

            for dst_ci, dst_crew in enumerate(crews):
                if dst_ci == src_ci:
                    continue
                n = len(dst_crew)
                for pos in range(n + 1):
                    if pos > 0 and tasks[dst_crew[pos - 1]][1] > ts_t:
                        continue
                    if pos < n and tf_t > tasks[dst_crew[pos]][0]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((dst_crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < n:
                        c = arcs.get((task, dst_crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if 0 < pos < n:
                        bridge = arcs.get((dst_crew[pos - 1], dst_crew[pos]), 0.0)

                    head_start = tasks[dst_crew[0]][0] if pos > 0 else ts_t
                    tail_finish = tasks[dst_crew[-1]][1] if pos < n else tf_t
                    if tail_finish - head_start > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_ins_delta:
                        best_ins_delta = delta
                        best_dst_ci = dst_ci
                        best_ins_pos = pos

            if best_dst_ci < 0:
                continue

            total_delta = best_ins_delta - removal_gain
            if total_delta < -1e-9:
                dst_crew = crews[best_dst_ci]
                new_dst = dst_crew[:best_ins_pos] + [task] + dst_crew[best_ins_pos:]

                crews[src_ci] = new_src
                crews[best_dst_ci] = new_dst

                # Update mappings
                if new_src:
                    for p, t in enumerate(new_src):
                        task_to_crew[t] = src_ci
                        task_to_pos[t] = p
                task_to_crew[task] = best_dst_ci
                task_to_pos[task] = best_ins_pos
                for p, t in enumerate(new_dst):
                    task_to_crew[t] = best_dst_ci
                    task_to_pos[t] = p

                improved = True

        return crews, improved

    def swap_pass(crews, rng):
        """One pass of pairwise task swaps between crews."""
        improved = False
        crew_indices = list(range(len(crews)))
        rng.shuffle(crew_indices)

        for ci in crew_indices:
            if remaining() < 0.5:
                break
            for cj in crew_indices:
                if ci >= cj:
                    continue
                if remaining() < 0.5:
                    break

                crew_i = crews[ci]
                crew_j = crews[cj]

                for pi in range(len(crew_i)):
                    if remaining() < 0.5:
                        break
                    for pj in range(len(crew_j)):
                        ti = crew_i[pi]
                        tj = crew_j[pj]

                        # Build candidate swapped crews
                        new_ci = crew_i[:pi] + [tj] + crew_i[pi + 1:]
                        new_cj = crew_j[:pj] + [ti] + crew_j[pj + 1:]

                        if not crew_valid(new_ci) or not crew_valid(new_cj):
                            continue

                        old_cost = crew_cost_fn(crew_i) + crew_cost_fn(crew_j)
                        new_cost = crew_cost_fn(new_ci) + crew_cost_fn(new_cj)

                        if new_cost < old_cost - 1e-9:
                            crews[ci] = new_ci
                            crews[cj] = new_cj
                            improved = True

        return crews, improved

    def or_opt_pass(crews, seg_len, rng):
        """Or-opt: move a segment of seg_len tasks between crews."""
        improved = False
        crew_indices = list(range(len(crews)))
        rng.shuffle(crew_indices)

        for src_ci in crew_indices:
            if remaining() < 0.5:
                break
            src_crew = crews[src_ci]
            if len(src_crew) <= seg_len:
                continue

            for src_pos in range(len(src_crew) - seg_len + 1):
                segment = src_crew[src_pos:src_pos + seg_len]
                seg_start_t = tasks[segment[0]][0]
                seg_finish_t = tasks[segment[-1]][1]

                # Cost of removing segment
                removal_gain = 0.0
                if src_pos > 0:
                    removal_gain += arcs.get((src_crew[src_pos - 1], segment[0]), 0.0)
                if src_pos + seg_len < len(src_crew):
                    removal_gain += arcs.get((segment[-1], src_crew[src_pos + seg_len]), 0.0)

                # Bridge cost
                bridge_cost = 0.0
                if src_pos > 0 and src_pos + seg_len < len(src_crew):
                    prev_t = src_crew[src_pos - 1]
                    next_t = src_crew[src_pos + seg_len]
                    if (prev_t, next_t) not in arc_set:
                        continue
                    bridge_cost = arcs[(prev_t, next_t)]

                new_src = src_crew[:src_pos] + src_crew[src_pos + seg_len:]
                if new_src and tasks[new_src[-1]][1] - tasks[new_src[0]][0] > time_limit:
                    continue

                best_delta = -1e-9
                best_dst_ci = -1
                best_ins_pos = -1

                for dst_ci in crew_indices:
                    if dst_ci == src_ci:
                        continue
                    dst_crew = crews[dst_ci]

                    for ins_pos in range(len(dst_crew) + 1):
                        if ins_pos > 0 and tasks[dst_crew[ins_pos - 1]][1] > seg_start_t:
                            continue
                        if ins_pos < len(dst_crew) and seg_finish_t > tasks[dst_crew[ins_pos]][0]:
                            continue

                        ins_cost = 0.0
                        ok = True
                        if ins_pos > 0:
                            c = arcs.get((dst_crew[ins_pos - 1], segment[0]))
                            if c is None:
                                ok = False
                            else:
                                ins_cost += c
                        if ok and ins_pos < len(dst_crew):
                            c = arcs.get((segment[-1], dst_crew[ins_pos]))
                            if c is None:
                                ok = False
                            else:
                                ins_cost += c
                        if not ok:
                            continue

                        dst_bridge = 0.0
                        if 0 < ins_pos < len(dst_crew):
                            dst_bridge = arcs.get((dst_crew[ins_pos - 1], dst_crew[ins_pos]), 0.0)

                        new_dst = dst_crew[:ins_pos] + segment + dst_crew[ins_pos:]
                        if tasks[new_dst[-1]][1] - tasks[new_dst[0]][0] > time_limit:
                            continue

                        delta = (bridge_cost + ins_cost - dst_bridge) - removal_gain
                        if delta < best_delta:
                            best_delta = delta
                            best_dst_ci = dst_ci
                            best_ins_pos = ins_pos

                if best_dst_ci >= 0:
                    dst_crew = crews[best_dst_ci]
                    new_dst = dst_crew[:best_ins_pos] + segment + dst_crew[best_ins_pos:]
                    crews[src_ci] = new_src
                    crews[best_dst_ci] = new_dst
                    improved = True
                    # Restart this crew
                    break

        return crews, improved

    # ------------------------------------------------------------------ #
    # Main improvement loop
    # ------------------------------------------------------------------ #
    current_crews = [list(c) for c in initial_sol['crews']]
    current_cost = total_cost_fn(current_crews)
    best_crews = [list(c) for c in current_crews]
    best_cost = current_cost
    best_sol_out = {'crews': [list(c) for c in current_crews]}

    rng = random.Random(42)

    # SA temperature
    if current_cost > 0 and current_cost < float('inf'):
        T_init = max(0.05 * current_cost / math.log(2), 1.0)
    else:
        T_init = 100.0
    T_min = 1e-4
    T = T_init

    ls_time = remaining() - 0.5
    if ls_time <= 0:
        return initial_sol

    estimated_iters = max(100, int(ls_time * 30))
    cooling_rate = (T_min / T_init) ** (1.0 / max(1, estimated_iters))

    n_destroy_base = max(1, N // 8)

    # Adaptive operator selection (UCB)
    destroy_ops = ['random', 'worst_crew', 'segment', 'related', 'expensive']
    op_success = [0] * len(destroy_ops)
    op_tries = [1] * len(destroy_ops)

    def select_op_ucb():
        total_tries = sum(op_tries)
        scores = []
        for i in range(len(destroy_ops)):
            exploit = op_success[i] / op_tries[i]
            explore = math.sqrt(2 * math.log(total_tries) / op_tries[i])
            scores.append(exploit + 0.3 * explore)
        return scores.index(max(scores))

    no_improve_streak = 0
    iteration = 0
    last_ls_iter = 0
    last_or_opt_iter = 0

    while remaining() > 0.5:
        iteration += 1
        T = max(T * cooling_rate, T_min)

        # Adaptive destroy size
        n_destroy = n_destroy_base + min(no_improve_streak // 6, N // 5)
        n_destroy = max(1, min(n_destroy, N // 2))

        op_idx = select_op_ucb()
        op_tries[op_idx] += 1
        destroy_op = destroy_ops[op_idx]

        # Destroy
        if destroy_op == 'random':
            partial_crews, removed = destroy_random(current_crews, n_destroy, rng)
        elif destroy_op == 'worst_crew':
            n_cd = max(1, min(3, len(current_crews) // 3))
            partial_crews, removed = destroy_worst_crew(current_crews, n_cd, rng)
        elif destroy_op == 'segment':
            partial_crews, removed = destroy_segment(current_crews, rng)
        elif destroy_op == 'related':
            partial_crews, removed = destroy_related(current_crews, n_destroy, rng)
        else:
            partial_crews, removed = destroy_expensive_arcs(current_crews, n_destroy, rng)

        if not removed:
            continue

        # Repair: alternate between greedy and regret-2
        use_regret = (iteration % 3 == 0) and (len(removed) <= 30)
        if use_regret:
            new_crews = regret2_repair(removed, partial_crews, K)
        else:
            new_crews = greedy_repair(removed, partial_crews, K)

        if new_crews is None:
            continue

        # Check coverage
        all_covered = set(t for crew in new_crews for t in crew)
        if len(all_covered) != N:
            missing = list(set(range(1, N + 1)) - all_covered)
            new_crews = greedy_repair(missing, new_crews, K)
            if new_crews is None:
                continue
            if len(set(t for crew in new_crews for t in crew)) != N:
                continue

        if len(new_crews) > K:
            continue

        if not all(crew_valid(crew) for crew in new_crews):
            continue

        new_cost = total_cost_fn(new_crews)

        # SA acceptance
        delta = new_cost - current_cost
        accept = False
        if delta < 0:
            accept = True
        elif T > T_min * 10 and delta < float('inf'):
            accept = rng.random() < math.exp(-delta / T)

        if accept:
            current_crews = new_crews
            current_cost = new_cost

            if new_cost < best_cost - 1e-9:
                candidate = {'crews': [list(c) for c in new_crews]}
                try:
                    feasible, _ = tools['is_feasible'](candidate)
                    if feasible:
                        obj = tools['objective'](candidate)
                        if obj < best_cost:
                            best_cost = obj
                            best_crews = [list(c) for c in new_crews]
                            best_sol_out = candidate
                            op_success[op_idx] += 1
                            no_improve_streak = 0
                except Exception:
                    pass
            else:
                no_improve_streak += 1
        else:
            no_improve_streak += 1

        # Periodic or-opt (every 15 iterations)
        if iteration - last_or_opt_iter >= 15 and remaining() > 1.0:
            last_or_opt_iter = iteration
            seg_len = rng.choice([1, 2, 3])
            opt_crews, opt_improved = or_opt_pass([list(c) for c in current_crews], seg_len, rng)
            if opt_improved and len(opt_crews) <= K:
                if all(crew_valid(c) for c in opt_crews):
                    opt_cost = total_cost_fn(opt_crews)
                    if opt_cost < current_cost:
                        current_crews = opt_crews
                        current_cost = opt_cost
                        if opt_cost < best_cost - 1e-9:
                            candidate = {'crews': [list(c) for c in opt_crews]}
                            try:
                                feasible, _ = tools['is_feasible'](candidate)
                                if feasible:
                                    obj = tools['objective'](candidate)
                                    if obj < best_cost:
                                        best_cost = obj
                                        best_crews = [list(c) for c in opt_crews]
                                        best_sol_out = candidate
                                        no_improve_streak = 0
                            except Exception:
                                pass

        # Periodic relocate pass (every 25 iterations when stagnating)
        if iteration - last_ls_iter >= 25 and remaining() > 1.5 and no_improve_streak > 10:
            last_ls_iter = iteration
            ls_crews, ls_improved = relocate_pass([list(c) for c in current_crews], rng)
            if ls_improved:
                current_crews = ls_crews
                current_cost = total_cost_fn(current_crews)
                if current_cost < best_cost - 1e-9:
                    candidate = {'crews': [list(c) for c in current_crews if c]}
                    try:
                        feasible, _ = tools['is_feasible'](candidate)
                        if feasible:
                            obj = tools['objective'](candidate)
                            if obj < best_cost:
                                best_cost = obj
                                best_crews = [list(c) for c in current_crews if c]
                                best_sol_out = candidate
                                no_improve_streak = 0
                    except Exception:
                        pass

        # Periodic swap pass
        if iteration % 40 == 0 and remaining() > 2.0 and N <= 100:
            sw_crews, sw_improved = swap_pass([list(c) for c in current_crews], rng)
            if sw_improved:
                current_crews = sw_crews
                current_cost = total_cost_fn(current_crews)
                if current_cost < best_cost - 1e-9:
                    candidate = {'crews': [list(c) for c in current_crews if c]}
                    try:
                        feasible, _ = tools['is_feasible'](candidate)
                        if feasible:
                            obj = tools['objective'](candidate)
                            if obj < best_cost:
                                best_cost = obj
                                best_crews = [list(c) for c in current_crews if c]
                                best_sol_out = candidate
                                no_improve_streak = 0
                    except Exception:
                        pass

        # Restart from best when stagnating
        if no_improve_streak > 60 and remaining() > 2.0:
            current_crews = [list(c) for c in best_crews]
            current_cost = best_cost
            no_improve_streak = 0
            T = max(T, T_init * 0.1)

    # Final validation
    result = {'crews': [list(c) for c in best_crews if c]}
    try:
        feasible, _ = tools['is_feasible'](result)
        if feasible:
            return result
    except Exception:
        pass

    return best_sol_out

import time
import math
import random
import heapq
from collections import defaultdict


def solve(instance: dict, tools: dict, time_limit_s: float) -> dict:
    start_time = time.time()

    N = instance['N']
    K = instance['K']
    time_limit = instance['time_limit']
    tasks = instance['tasks']
    arcs = instance['arcs']

    def elapsed():
        return time.time() - start_time

    def remaining():
        return time_limit_s - elapsed()

    # ------------------------------------------------------------------ #
    # Precompute data structures
    # ------------------------------------------------------------------ #
    arc_set = set(arcs.keys())
    task_start = {t: tasks[t][0] for t in range(1, N + 1)}
    task_finish = {t: tasks[t][1] for t in range(1, N + 1)}

    succ_list = defaultdict(list)
    pred_list = defaultdict(list)
    for (i, j), cost in arcs.items():
        if task_finish[i] <= task_start[j]:
            succ_list[i].append(j)
            pred_list[j].append(i)
    for t in range(1, N + 1):
        succ_list[t].sort(key=lambda x: task_start[x])
        pred_list[t].sort(key=lambda x: task_finish[x])

    # ------------------------------------------------------------------ #
    # Core utility functions
    # ------------------------------------------------------------------ #
    def crew_cost_fast(crew):
        cost = 0.0
        for idx in range(len(crew) - 1):
            c = arcs.get((crew[idx], crew[idx + 1]))
            if c is None:
                return float('inf')
            cost += c
        return cost

    def check_crew_fast(crew):
        if not crew:
            return False
        if task_finish[crew[-1]] - task_start[crew[0]] > time_limit:
            return False
        for idx in range(len(crew) - 1):
            t1, t2 = crew[idx], crew[idx + 1]
            if task_finish[t1] > task_start[t2]:
                return False
            if (t1, t2) not in arc_set:
                return False
        return True

    def solution_cost_fast(crews):
        return sum(crew_cost_fast(c) for c in crews)

    # ------------------------------------------------------------------ #
    # Best solution tracking
    # ------------------------------------------------------------------ #
    best_sol = None
    best_cost = float('inf')

    def update_best(sol):
        nonlocal best_sol, best_cost
        if sol is None:
            return False
        try:
            feasible, _ = tools['is_feasible'](sol)
            if not feasible:
                return False
            cost = tools['objective'](sol)
            if cost < best_cost:
                best_cost = cost
                best_sol = {'crews': [list(c) for c in sol['crews']]}
                return True
        except Exception:
            pass
        return False

    # ------------------------------------------------------------------ #
    # Instance analysis for strategy dispatch
    # ------------------------------------------------------------------ #
    k_ratio = K / max(1, N)
    n_arcs = len(arcs)
    arc_density = n_arcs / max(1, N * (N - 1))
    avg_succ = sum(len(succ_list[t]) for t in range(1, N + 1)) / max(1, N)

    # Use ILP for small instances, MCF/LNS for larger
    use_ilp = (N <= 100)
    use_lns = (N > 80 or k_ratio < 0.35)

    # ------------------------------------------------------------------ #
    # Phase 1: Initial solution construction
    # ------------------------------------------------------------------ #

    # Strategy: try multiple solvers in order of expected quality
    if use_ilp and remaining() > 2.0:
        ilp_budget = min(remaining() * 0.45, 45.0)
        try:
            sol = tools['ilp_crew_scheduling'](time_limit_s=ilp_budget)
            update_best(sol)
        except Exception:
            pass

    if remaining() > 2.0:
        mcf_budget = min(remaining() * 0.30, 20.0)
        try:
            sol = tools['solve_min_cost_flow'](time_limit_s=mcf_budget)
            update_best(sol)
        except Exception:
            pass

    if best_sol is None and remaining() > 2.0:
        sd_budget = min(remaining() * 0.40, 25.0)
        try:
            sol = tools['solve_default'](time_limit_s=sd_budget)
            update_best(sol)
        except Exception:
            pass

    # Greedy chain pack
    if remaining() > 0.5:
        try:
            chains = tools['greedy_chain_pack']()
            if chains and len(chains) <= K:
                sol = tools['make_solution'](chains)
                update_best(sol)
        except Exception:
            pass

    # Custom greedy construction (deterministic)
    def greedy_construct(rng=None, alpha=0.0):
        task_order = sorted(range(1, N + 1), key=lambda t: task_start[t])
        crews_g = []
        crew_last = []
        crew_start_t = []
        crew_finish_t = []

        for task in task_order:
            ts = task_start[task]
            tf = task_finish[task]
            candidates = []

            for i in range(len(crews_g)):
                last = crew_last[i]
                if crew_finish_t[i] > ts:
                    continue
                if (last, task) not in arc_set:
                    continue
                if tf - crew_start_t[i] > time_limit:
                    continue
                c = arcs[(last, task)]
                candidates.append((c, i))

            if candidates:
                if rng is not None and alpha > 0 and len(candidates) > 1:
                    candidates.sort()
                    min_c = candidates[0][0]
                    max_c = candidates[-1][0]
                    threshold = min_c + alpha * (max_c - min_c)
                    rcl = [i for c, i in candidates if c <= threshold + 1e-9]
                    chosen = rng.choice(rcl)
                else:
                    chosen = min(candidates, key=lambda x: x[0])[1]
                crews_g[chosen].append(task)
                crew_last[chosen] = task
                crew_finish_t[chosen] = tf
            elif len(crews_g) < K:
                crews_g.append([task])
                crew_last.append(task)
                crew_start_t.append(ts)
                crew_finish_t.append(tf)
            else:
                forced = False
                for i in range(len(crews_g)):
                    last = crew_last[i]
                    if crew_finish_t[i] <= ts and (last, task) in arc_set:
                        if tf - crew_start_t[i] <= time_limit:
                            crews_g[i].append(task)
                            crew_last[i] = task
                            crew_finish_t[i] = tf
                            forced = True
                            break
                if not forced:
                    return None

        if not crews_g:
            return None
        sol = {'crews': crews_g}
        try:
            feasible, _ = tools['is_feasible'](sol)
            return sol if feasible else None
        except Exception:
            return None

    if remaining() > 0.3:
        sol = greedy_construct()
        update_best(sol)

    # Multiple randomized constructions
    rng_init = random.Random(42)
    for _ in range(5):
        if remaining() < 0.2:
            break
        alpha = rng_init.uniform(0.1, 0.5)
        sol = greedy_construct(rng=rng_init, alpha=alpha)
        update_best(sol)

    # Emergency fallback
    if best_sol is None:
        if K >= N:
            sol = {'crews': [[i] for i in range(1, N + 1)]}
            update_best(sol)
        if best_sol is None:
            task_order = sorted(range(1, N + 1), key=lambda t: task_start[t])
            crews_em = [[] for _ in range(min(K, N))]
            for idx, task in enumerate(task_order):
                crews_em[idx % len(crews_em)].append(task)
            sol = {'crews': [c for c in crews_em if c]}
            update_best(sol)

    if best_sol is None:
        return {'crews': [[i] for i in range(1, min(K + 1, N + 1))]}

    # ------------------------------------------------------------------ #
    # Phase 2: Local search + LNS optimization
    # ------------------------------------------------------------------ #

    def greedy_repair(unassigned, current_crews, max_crews):
        if not unassigned:
            return current_crews
        crews = [list(c) for c in current_crews]
        task_order = sorted(unassigned, key=lambda t: task_start[t])

        for task in task_order:
            ts_t = task_start[task]
            tf_t = task_finish[task]
            best_delta = float('inf')
            best_ci = -1
            best_pos = -1

            for ci, crew in enumerate(crews):
                n = len(crew)
                for pos in range(n + 1):
                    if pos > 0 and task_finish[crew[pos - 1]] > ts_t:
                        continue
                    if pos < n and tf_t > task_start[crew[pos]]:
                        continue

                    cost_add = 0.0
                    ok = True
                    if pos > 0:
                        c = arcs.get((crew[pos - 1], task))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if ok and pos < n:
                        c = arcs.get((task, crew[pos]))
                        if c is None:
                            ok = False
                        else:
                            cost_add += c
                    if not ok:
                        continue

                    bridge = 0.0
                    if 0 < pos < n:
                        bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                    head_start = task_start[crew[0]] if pos > 0 else ts_t
                    tail_finish = task_finish[crew[-1]] if pos < n else tf_t
                    if tail_finish - head_start > time_limit:
                        continue

                    delta = cost_add - bridge
                    if delta < best_delta:
                        best_delta = delta
                        best_ci = ci
                        best_pos = pos

            if best_ci >= 0:
                crews[best_ci] = crews[best_ci][:best_pos] + [task] + crews[best_ci][best_pos:]
            elif len(crews) < max_crews:
                crews.append([task])
            else:
                return None

        return crews

    def regret_repair(unassigned, current_crews, max_crews):
        if not unassigned:
            return current_crews
        if len(unassigned) > 30:
            return greedy_repair(unassigned, current_crews, max_crews)

        crews = [list(c) for c in current_crews]
        remaining_tasks = list(unassigned)

        while remaining_tasks:
            regrets = []
            for task in remaining_tasks:
                ts_t = task_start[task]
                tf_t = task_finish[task]
                insertions = []

                for ci, crew in enumerate(crews):
                    n = len(crew)
                    for pos in range(n + 1):
                        if pos > 0 and task_finish[crew[pos - 1]] > ts_t:
                            continue
                        if pos < n and tf_t > task_start[crew[pos]]:
                            continue

                        cost_add = 0.0
                        ok = True
                        if pos > 0:
                            c = arcs.get((crew[pos - 1], task))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if ok and pos < n:
                            c = arcs.get((task, crew[pos]))
                            if c is None:
                                ok = False
                            else:
                                cost_add += c
                        if not ok:
                            continue

                        bridge = 0.0
                        if 0 < pos < n:
                            bridge = arcs.get((crew[pos - 1], crew[pos]), 0.0)

                        head_start = task_start[crew[0]] if pos > 0 else ts_t
                        tail_finish = task_finish[crew[-1]] if pos < n else tf_t
                        if tail_finish - head_start > time_limit:
                            continue

                        delta = cost_add - bridge
                        insertions.append((delta, ci, pos))

                if len(crews) < max_crews:
                    insertions.append((0.0, -1, 0))

                if not insertions:
                    return None

                insertions.sort(key=lambda x: x[0])
                best_c = insertions[0][0]
                second_c = insertions[1][0] if len(insertions) > 1 else best_c + 1e9
                regret_val = second_c - best_c
                regrets.append((regret_val, task, insertions[0]))

            regrets.sort(key=lambda x: -x[0])
            _, task_to_insert, (delta, ci, pos) = regrets[0]

            if ci == -1:
                crews.append([task_to_insert])
            else:
                crews[ci] = crews[ci][:pos] + [task_to_insert] + crews[ci][pos:]
            remaining_tasks.remove(task_to_insert)

        return crews

    # ------------------------------------------------------------------ #
    # Local search moves
    # ------------------------------------------------------------------ #

    def intra_relocate_pass(crews, crew_costs):
        """Move tasks within a single crew to better positions."""
        improved = False
        for ci in range(len(crews)):
            crew = crews[ci]
            n = len(crew)
            if n < 3:
                continue
            old_cost = crew_costs[ci]
            best_gain = 1e-9
            best_new_crew = None
            best_new_cost = old_cost

            for ti in range(n):
                task = crew[ti]
                # Check if removal is valid (bridge arc exists)
                if ti > 0 and ti < n - 1:
                    prev_t = crew[ti - 1]
                    next_t = crew[ti + 1]
                    if task_finish[prev_t] > task_start[next_t]:
                        continue
                    if (prev_t, next_t) not in arc_set:
                        continue

                new_crew_base = crew[:ti] + crew[ti + 1:]

                for pos in range(len(new_crew_base) + 1):
                    if pos == ti:
                        continue
                    prev_j = new_crew_base[pos - 1] if pos > 0 else None
                    next_j = new_crew_base[pos] if pos < len(new_crew_base) else None

                    if prev_j is not None:
                        if task_finish[prev_j] > task_start[task]:
                            continue
                        if (prev_j, task) not in arc_set:
                            continue
                    if next_j is not None:
                        if task_finish[task] > task_start[next_j]:
                            continue
                        if (task, next_j) not in arc_set:
                            continue

                    new_crew = new_crew_base[:pos] + [task] + new_crew_base[pos:]
                    dt = task_finish[new_crew[-1]] - task_start[new_crew[0]]
                    if dt > time_limit:
                        continue

                    new_cost = crew_cost_fast(new_crew)
                    gain = old_cost - new_cost
                    if gain > best_gain:
                        best_gain = gain
                        best_new_crew = new_crew
                        best_new_cost = new_cost

            if best_new_crew is not None:
                crews[ci] = best_new_crew
                crew_costs[ci] = best_new_cost
                improved = True

        return improved, crews, crew_costs

    def inter_relocate_best(crews, crew_costs):
        """Move a single task from one crew to another, best improvement."""
        best_gain = 1e-9
        best_move = None

        for ci in range(len(crews)):
            crew_i = crews[ci]
            if len(crew_i) <= 1:
                continue
            old_cost_i = crew_costs[ci]

            for ti in range(len(crew_i)):
                task = crew_i[ti]
                t_s = task_start[task]
                t_f = task_finish[task]

                # Check removal validity
                if ti > 0 and ti < len(crew_i) - 1:
                    prev_t = crew_i[ti - 1]
                    next_t = crew_i[ti + 1]
                    if task_finish[prev_t] > task_start[next_t]:
                        continue
                    if (prev_t, next_t) not in arc_set:
                        continue

                new_crew_i = crew_i[:ti] + crew_i[ti + 1:]
                dt_i = task_finish[new_crew_i[-1]] - task_start[new_crew_i[0]]
                if dt_i > time_limit:
                    continue

                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                for cj in range(len(crews)):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_costs[cj]

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None:
                            if task_finish[prev_j] > t_s:
                                continue
                            if (prev_j, task) not in arc_set:
                                continue
                        if next_j is not None:
                            if t_f > task_start[next_j]:
                                continue
                            if (task, next_j) not in arc_set:
                                continue

                        head_start = task_start[crew_j[0]] if pos > 0 else t_s
                        tail_finish = task_finish[crew_j[-1]] if pos < len(crew_j) else t_f
                        if tail_finish - head_start > time_limit:
                            continue

                        insert_cost = 0.0
                        if prev_j is not None:
                            insert_cost += arcs[(prev_j, task)]
                        if next_j is not None:
                            insert_cost += arcs[(task, next_j)]
                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        gain = saving_i - (insert_cost - bridge_cost)
                        if gain > best_gain:
                            best_gain = gain
                            best_move = (ci, ti, cj, pos)

        if best_move is None:
            return False, crews, crew_costs

        ci, ti, cj, pos = best_move
        task = crews[ci][ti]
        new_crew_i = crews[ci][:ti] + crews[ci][ti + 1:]
        new_crew_j = crews[cj][:pos] + [task] + crews[cj][pos:]
        crews[ci] = new_crew_i
        crews[cj] = new_crew_j
        crew_costs[ci] = crew_cost_fast(new_crew_i)
        crew_costs[cj] = crew_cost_fast(new_crew_j)
        return True, crews, crew_costs

    def swap_best(crews, crew_costs):
        """Swap single tasks between two crews, best improvement."""
        best_gain = 1e-9
        best_move = None

        for ci in range(len(crews)):
            for cj in range(ci + 1, len(crews)):
                crew_i = crews[ci]
                crew_j = crews[cj]
                old_cost = crew_costs[ci] + crew_costs[cj]

                for pi in range(len(crew_i)):
                    task_i = crew_i[pi]
                    ti_s = task_start[task_i]
                    ti_f = task_finish[task_i]

                    for pj in range(len(crew_j)):
                        task_j = crew_j[pj]
                        tj_s = task_start[task_j]
                        tj_f = task_finish[task_j]

                        # Check task_j in crew_i at position pi
                        ok_i = True
                        if pi > 0:
                            prev = crew_i[pi - 1]
                            if task_finish[prev] > tj_s or (prev, task_j) not in arc_set:
                                ok_i = False
                        if ok_i and pi < len(crew_i) - 1:
                            nxt = crew_i[pi + 1]
                            if tj_f > task_start[nxt] or (task_j, nxt) not in arc_set:
                                ok_i = False
                        if ok_i:
                            first_i = crew_i[0] if pi > 0 else task_j
                            last_i = crew_i[-1] if pi < len(crew_i) - 1 else task_j
                            if task_finish[last_i] - task_start[first_i] > time_limit:
                                ok_i = False
                        if not ok_i:
                            continue

                        # Check task_i in crew_j at position pj
                        ok_j = True
                        if pj > 0:
                            prev = crew_j[pj - 1]
                            if task_finish[prev] > ti_s or (prev, task_i) not in arc_set:
                                ok_j = False
                        if ok_j and pj < len(crew_j) - 1:
                            nxt = crew_j[pj + 1]
                            if ti_f > task_start[nxt] or (task_i, nxt) not in arc_set:
                                ok_j = False
                        if ok_j:
                            first_j = crew_j[0] if pj > 0 else task_i
                            last_j = crew_j[-1] if pj < len(crew_j) - 1 else task_i
                            if task_finish[last_j] - task_start[first_j] > time_limit:
                                ok_j = False
                        if not ok_j:
                            continue

                        new_ci = list(crew_i)
                        new_cj = list(crew_j)
                        new_ci[pi] = task_j
                        new_cj[pj] = task_i
                        new_cost = crew_cost_fast(new_ci) + crew_cost_fast(new_cj)
                        gain = old_cost - new_cost
                        if gain > best_gain:
                            best_gain = gain
                            best_move = (ci, pi, cj, pj)

        if best_move is None:
            return False, crews, crew_costs

        ci, pi, cj, pj = best_move
        new_ci = list(crews[ci])
        new_cj = list(crews[cj])
        new_ci[pi] = crews[cj][pj]
        new_cj[pj] = crews[ci][pi]
        crews[ci] = new_ci
        crews[cj] = new_cj
        crew_costs[ci] = crew_cost_fast(new_ci)
        crew_costs[cj] = crew_cost_fast(new_cj)
        return True, crews, crew_costs

    def oropt_best(crews, crew_costs, seg_len):
        """Move a segment of seg_len tasks from one crew to another."""
        best_gain = 1e-9
        best_move = None

        for ci in range(len(crews)):
            crew_i = crews[ci]
            if len(crew_i) <= seg_len:
                continue
            old_cost_i = crew_costs[ci]

            for ti in range(len(crew_i) - seg_len + 1):
                segment = crew_i[ti:ti + seg_len]

                # Segment internal arcs must be valid
                seg_ok = all((segment[k], segment[k + 1]) in arc_set
                             for k in range(seg_len - 1))
                if not seg_ok:
                    continue

                # Check bridge after removal
                if ti > 0 and ti + seg_len < len(crew_i):
                    prev_t = crew_i[ti - 1]
                    next_t = crew_i[ti + seg_len]
                    if task_finish[prev_t] > task_start[next_t]:
                        continue
                    if (prev_t, next_t) not in arc_set:
                        continue

                new_crew_i = crew_i[:ti] + crew_i[ti + seg_len:]
                if new_crew_i:
                    dt_i = task_finish[new_crew_i[-1]] - task_start[new_crew_i[0]]
                    if dt_i > time_limit:
                        continue

                new_cost_i = crew_cost_fast(new_crew_i)
                saving_i = old_cost_i - new_cost_i

                seg_s = task_start[segment[0]]
                seg_f = task_finish[segment[-1]]
                seg_internal = crew_cost_fast(segment)

                for cj in range(len(crews)):
                    if cj == ci:
                        continue
                    crew_j = crews[cj]
                    old_cost_j = crew_costs[cj]

                    for pos in range(len(crew_j) + 1):
                        prev_j = crew_j[pos - 1] if pos > 0 else None
                        next_j = crew_j[pos] if pos < len(crew_j) else None

                        if prev_j is not None and task_finish[prev_j] > seg_s:
                            continue
                        if next_j is not None and seg_f > task_start[next_j]:
                            continue

                        extra_cost = seg_internal
                        ok = True
                        if prev_j is not None:
                            c = arcs.get((prev_j, segment[0]))
                            if c is None:
                                ok = False
                            else:
                                extra_cost += c
                        if ok and next_j is not None:
                            c = arcs.get((segment[-1], next_j))
                            if c is None:
                                ok = False
                            else:
                                extra_cost += c
                        if not ok:
                            continue

                        bridge_cost = 0.0
                        if prev_j is not None and next_j is not None:
                            bridge_cost = arcs.get((prev_j, next_j), 0.0)

                        head_start = task_start[crew_j[0]] if pos > 0 else seg_s
                        tail_finish = task_finish[crew_j[-1]] if pos < len(crew_j) else seg_f
                        if tail_finish - head_start > time_limit:
                            continue

                        gain = saving_i - (extra_cost - bridge_cost)
                        if gain > best_gain:
                            best_gain = gain
                            best_move = (ci, ti, cj, pos, seg_len)

        if best_move is None:
            return False, crews, crew_costs

        ci, ti, cj, pos, sl = best_move
        segment = crews[ci][ti:ti + sl]
        new_crew_i = crews[ci][:ti] + crews[ci][ti + sl:]
        new_crew_j = crews[cj][:pos] + segment + crews[cj][pos:]
        crews[ci] = new_crew_i
        crews[cj] = new_crew_j
        crew_costs[ci] = crew_cost_fast(new_crew_i)
        crew_costs[cj] = crew_cost_fast(new_crew_j)
        return True, crews, crew_costs

    def run_local_search(crews_in, time_budget):
        crews = [list(c) for c in crews_in]
        crew_costs = [crew_cost_fast(c) for c in crews]
        ls_start = time.time()

        def ls_rem():
            return time_budget - (time.time() - ls_start)

        improved_global = True
        while improved_global and ls_rem() > 0.05:
            improved_global = False

            if ls_rem() > 0.02:
                imp, crews, crew_costs = intra_relocate_pass(crews, crew_costs)
                if imp:
                    improved_global = True

            while ls_rem() > 0.05:
                imp, crews, crew_costs = inter_relocate_best(crews, crew_costs)
                if not imp:
                    break
                improved_global = True

            if ls_rem() < 0.05:
                break

            while ls_rem() > 0.05:
                imp, crews, crew_costs = swap_best(crews, crew_costs)
                if not imp:
                    break
                improved_global = True

            if ls_rem() < 0.05:
                break

            for sl in [2, 3]:
                if ls_rem() < 0.05:
                    break
                while ls_rem() > 0.05:
                    imp, crews, crew_costs = oropt_best(crews, crew_costs, sl)
                    if not imp:
                        break
                    improved_global = True

        return crews, sum(crew_costs)

    # ------------------------------------------------------------------ #
    # LNS destroy operators
    # ------------------------------------------------------------------ #

    def destroy_random_tasks(crews, n_remove, rng):
        all_tasks = [(ci, pos, t) for ci, crew in enumerate(crews)
                     for pos, t in enumerate(crew)]
        if not all_tasks:
            return crews, []
        n_remove = min(n_remove, len(all_tasks))
        removed_entries = rng.sample(all_tasks, n_remove)
        removed_set = set(t for _, _, t in removed_entries)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, list(removed_set)

    def destroy_worst_crew(crews, n_destroy, rng):
        if not crews:
            return crews, []
        crew_costs_sorted = sorted(range(len(crews)),
                                   key=lambda i: crew_cost_fast(crews[i]),
                                   reverse=True)
        n_destroy = min(n_destroy, len(crews))
        destroyed = set(crew_costs_sorted[:n_destroy])
        removed = []
        new_crews = []
        for ci, crew in enumerate(crews):
            if ci in destroyed:
                removed.extend(crew)
            else:
                new_crews.append(crew)
        return new_crews, removed

    def destroy_segment(crews, rng):
        if not crews:
            return crews, []
        crew_weights = [max(crew_cost_fast(crew), 0.01) for crew in crews]
        total_w = sum(crew_weights)
        r = rng.random() * total_w
        cumulative = 0.0
        ci = 0
        for i, w in enumerate(crew_weights):
            cumulative += w
            if r <= cumulative:
                ci = i
                break
        crew = crews[ci]
        if len(crew) <= 1:
            return crews, []
        seg_len = rng.randint(1, max(1, len(crew) // 2))
        start_pos = rng.randint(0, len(crew) - seg_len)
        removed = crew[start_pos:start_pos + seg_len]
        new_crew = crew[:start_pos] + crew[start_pos + seg_len:]
        new_crews = []
        for i, c in enumerate(crews):
            if i == ci:
                if new_crew:
                    new_crews.append(new_crew)
            else:
                new_crews.append(c)
        return new_crews, removed

    def destroy_related_tasks(crews, n_remove, rng):
        all_tasks_flat = [t for crew in crews for t in crew]
        if not all_tasks_flat:
            return crews, []
        seed_task = rng.choice(all_tasks_flat)
        removed_set = {seed_task}
        candidates = set()
        for j in succ_list[seed_task]:
            candidates.add(j)
        for i in pred_list[seed_task]:
            candidates.add(i)
        seed_s = task_start[seed_task]
        time_window = time_limit * 0.15
        for t in all_tasks_flat:
            if abs(task_start[t] - seed_s) < time_window:
                candidates.add(t)
        candidates -= removed_set
        candidates = sorted(candidates, key=lambda t: abs(task_start[t] - seed_s))
        n_remove = min(n_remove, len(all_tasks_flat))
        for t in candidates:
            if len(removed_set) >= n_remove:
                break
            removed_set.add(t)
        removed_tasks = list(removed_set)
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, removed_tasks

    def destroy_expensive_arcs(crews, n_remove, rng):
        """Remove tasks around most expensive arcs."""
        arc_costs_in_sol = []
        for ci, crew in enumerate(crews):
            for idx in range(len(crew) - 1):
                c = arcs.get((crew[idx], crew[idx + 1]), 0)
                arc_costs_in_sol.append((c, ci, idx, idx + 1))
        if not arc_costs_in_sol:
            return crews, []
        arc_costs_in_sol.sort(reverse=True)
        removed_set = set()
        for c, ci, idx1, idx2 in arc_costs_in_sol[:max(1, n_remove // 2)]:
            removed_set.add(crews[ci][idx1])
            removed_set.add(crews[ci][idx2])
            if len(removed_set) >= n_remove:
                break
        new_crews = [[t for t in crew if t not in removed_set] for crew in crews]
        new_crews = [c for c in new_crews if c]
        return new_crews, list(removed_set)

    # ------------------------------------------------------------------ #
    # Main optimization loop: adaptive LNS + SA with periodic LS
    # ------------------------------------------------------------------ #

    current_crews = [list(c) for c in best_sol['crews']]
    current_cost = solution_cost_fast(current_crews)
    lns_best_crews = [list(c) for c in current_crews]
    lns_best_cost = current_cost

    rng = random.Random(42)

    # Initial local search pass
    if remaining() > 1.5:
        ls_budget = min(remaining() * 0.35, 30.0)
        ls_crews, ls_cost = run_local_search(current_crews, ls_budget)
        ls_sol = {'crews': ls_crews}
        if update_best(ls_sol):
            current_crews = [list(c) for c in ls_crews]
            current_cost = ls_cost
            lns_best_crews = [list(c) for c in ls_crews]
            lns_best_cost = ls_cost
        else:
            try:
                feasible, _ = tools['is_feasible'](ls_sol)
                if feasible:
                    cost = tools['objective'](ls_sol)
                    if cost < lns_best_cost:
                        lns_best_cost = cost
                        lns_best_crews = [list(c) for c in ls_crews]
                    current_crews = ls_crews
                    current_cost = cost
            except Exception:
                pass

    if remaining() < 0.5:
        return best_sol

    # SA temperature setup
    if current_cost > 0 and current_cost < float('inf'):
        T_init = max(0.05 * current_cost / math.log(2), 1.0)
    else:
        T_init = 100.0
    T_min = 1e-4
    T = T_init

    lns_time = remaining() - 0.3
    if lns_time <= 0:
        return best_sol

    estimated_iters = max(100, int(lns_time * 40))
    cooling_rate = (T_min / T_init) ** (1.0 / max(1, estimated_iters))

    n_destroy_base = max(1, N // 10)

    destroy_ops = ['random', 'worst_crew', 'segment', 'related', 'expensive']
    op_success = [0] * len(destroy_ops)
    op_tries = [1] * len(destroy_ops)

    def select_destroy_op():
        total_tries = sum(op_tries)
        scores = []
        for i in range(len(destroy_ops)):
            exploit = op_success[i] / op_tries[i]
            explore = math.sqrt(2 * math.log(total_tries) / op_tries[i])
            scores.append(exploit + 0.3 * explore)
        return scores.index(max(scores))

    iteration = 0
    no_improve_streak = 0
    last_ls_iter = 0
    restart_count = 0

    while remaining() > 0.4:
        iteration += 1
        T = max(T * cooling_rate, T_min)

        # Adaptive destroy size
        n_destroy = n_destroy_base + min(no_improve_streak // 6, N // 5)
        n_destroy = max(1, min(n_destroy, N // 2))

        op_idx = select_destroy_op()
        op_tries[op_idx] += 1
        destroy_op = destroy_ops[op_idx]

        if destroy_op == 'random':
            partial_crews, removed = destroy_random_tasks(current_crews, n_destroy, rng)
        elif destroy_op == 'worst_crew':
            n_cd = max(1, min(3, len(current_crews) // 3))
            partial_crews, removed = destroy_worst_crew(current_crews, n_cd, rng)
        elif destroy_op == 'segment':
            partial_crews, removed = destroy_segment(current_crews, rng)
        elif destroy_op == 'related':
            partial_crews, removed = destroy_related_tasks(current_crews, n_destroy, rng)
        else:
            partial_crews, removed = destroy_expensive_arcs(current_crews, n_destroy, rng)

        if not removed:
            continue

        # Alternate between greedy and regret repair
        use_regret = (iteration % 4 == 0) and (len(removed) <= 25)
        if use_regret:
            new_crews = regret_repair(removed, partial_crews, K)
        else:
            new_crews = greedy_repair(removed, partial_crews, K)

        if new_crews is None:
            continue

        # Verify coverage
        all_covered = set(t for crew in new_crews for t in crew)
        if len(all_covered) != N:
            missing = set(range(1, N + 1)) - all_covered
            new_crews = greedy_repair(list(missing), new_crews, K)
            if new_crews is None:
                continue
            if len(set(t for crew in new_crews for t in crew)) != N:
                continue

        if len(new_crews) > K:
            continue

        if not all(check_crew_fast(crew) for crew in new_crews):
            continue

        new_cost = solution_cost_fast(new_crews)
        delta = new_cost - current_cost

        accept = False
        if delta < 0:
            accept = True
        elif T > T_min * 10 and delta < float('inf'):
            prob = math.exp(-delta / T)
            accept = rng.random() < prob

        if accept:
            current_crews = new_crews
            current_cost = new_cost

            if new_cost < lns_best_cost - 1e-9:
                candidate = {'crews': [list(c) for c in new_crews]}
                try:
                    feasible, _ = tools['is_feasible'](candidate)
                    if feasible:
                        obj = tools['objective'](candidate)
                        if obj < lns_best_cost:
                            lns_best_cost = obj
                            lns_best_crews = [list(c) for c in new_crews]
                            op_success[op_idx] += 1
                            no_improve_streak = 0
                            update_best(candidate)
                except Exception:
                    pass
            else:
                no_improve_streak += 1
        else:
            no_improve_streak += 1

        # Periodic local search refinement
        ls_interval = max(15, 50 - N // 10)
        if (iteration - last_ls_iter >= ls_interval and
                remaining() > 1.5 and no_improve_streak > 10):
            ls_budget = min(remaining() * 0.15, 8.0)
            ls_crews, ls_cost = run_local_search(
                [list(c) for c in current_crews], ls_budget)
            ls_sol = {'crews': ls_crews}
            try:
                feasible, _ = tools['is_feasible'](ls_sol)
                if feasible:
                    obj = tools['objective'](ls_sol)
                    if obj < lns_best_cost:
                        lns_best_cost = obj
                        lns_best_crews = [list(c) for c in ls_crews]
                        update_best(ls_sol)
                        no_improve_streak = 0
                    if obj < current_cost:
                        current_crews = ls_crews
                        current_cost = obj
            except Exception:
                pass
            last_ls_iter = iteration

        # Restart strategy: mix exploitation and diversification
        if no_improve_streak > 60 and remaining() > 1.5:
            restart_count += 1
            no_improve_streak = 0

            if restart_count % 4 == 0 and remaining() > 3.0:
                # Diversification: randomized greedy construction
                alpha = rng.uniform(0.1, 0.5)
                rand_sol = greedy_construct(rng=rng, alpha=alpha)
                if rand_sol is not None:
                    rand_crews = rand_sol['crews']
                    if (len(rand_crews) <= K and
                            all(check_crew_fast(c) for c in rand_crews) and
                            len(set(t for c in rand_crews for t in c)) == N):
                        rand_cost = solution_cost_fast(rand_crews)
                        if rand_cost < lns_best_cost * 1.6:
                            current_crews = rand_crews
                            current_cost = rand_cost
                            if rand_cost < lns_best_cost - 1e-9:
                                candidate = {'crews': [list(c) for c in rand_crews]}
                                update_best(candidate)
                                lns_best_cost = rand_cost
                                lns_best_crews = rand_crews
                        else:
                            current_crews = [list(c) for c in lns_best_crews]
                            current_cost = lns_best_cost
                    else:
                        current_crews = [list(c) for c in lns_best_crews]
                        current_cost = lns_best_cost
                else:
                    current_crews = [list(c) for c in lns_best_crews]
                    current_cost = lns_best_cost
                T = max(T, T_init * 0.25)
            else:
                # Exploitation: return to best known
                current_crews = [list(c) for c in lns_best_crews]
                current_cost = lns_best_cost
                T = max(T, T_init * 0.15)

    # Final local search polish
    if remaining() > 0.5:
        polish_budget = remaining() * 0.9
        polished, _ = run_local_search(
            [list(c) for c in lns_best_crews], polish_budget)
        update_best({'crews': polished})

    return best_sol if best_sol is not None else {
        'crews': [[i] for i in range(1, min(K + 1, N + 1))]
    }
